-- Poems batch 397
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-972','临江仙','郭应祥','宋','宋词','song-ci','临江仙','[]','忆我归舟初系岸，君家盛事先知。',70,'宋词/ci.song.12000.json','["忆我归舟初系岸，君家盛事先知。", "后房深处第三姬。", "熊罴符吉兆，鹫鷟产佳儿。", "衮衮庆源真未艾，谢兰还茁新枝。", "娇婴想见白和眉。", "他年贤子弟，今日小机宜。"]'),
('song-ci-973','临江仙','郭应祥','宋','宋词','song-ci','临江仙','[]','老子开年年五十，依前恁地痴顽。',70,'宋词/ci.song.12000.json','["老子开年年五十，依前恁地痴顽。", "昨非今是有无间。", "惟惭新赤绂，不称旧苍颜。", "休羡长年并极富，休贪宝带腰环。", "人生难得是清闲。", "急须抛县印，归去隐家山。"]'),
('song-ci-974','霜天晓角','郭应祥','宋','宋词','song-ci','霜天晓角','[]','琉璃十碗。',53,'宋词/ci.song.12000.json','["琉璃十碗。", "兽炭红炉暖。", "花下两枝银烛，和气洽、欢声满。", "从他吹急管。", "杯行须款款。", "尽做更移漏转，也犹胜、春宵短。"]'),
('song-ci-975','踏莎行','郭应祥','宋','宋词','song-ci','踏莎行','[]','鹗离风尘，燕辞门户。',68,'宋词/ci.song.12000.json','["鹗离风尘，燕辞门户。", "翩然举翮轻飞去。", "当初自恨探春迟，而今岂解留春住。", "花不重开，萍难再聚。", "垂杨只管牵离绪。", "直饶云雨梦阳台。", "梦回依旧无寻处。"]'),
('song-ci-976','踏莎行','郭应祥','宋','宋词','song-ci','踏莎行','[]','骤暖忽寒，送春迎夏。',68,'宋词/ci.song.12000.json','["骤暖忽寒，送春迎夏。", "金沙过了酴醿谢。", "漏声款款日偏长，奇峰历历云如画。", "幸有杯觞，堪同保社。", "棋如飞雹睛空下。", "六人酬唱已成编，他年遂水留佳话。"]'),
('song-ci-977','踏莎行','郭应祥','宋','宋词','song-ci','踏莎行','[]','露湿冠巾，风生襟袖。',68,'宋词/ci.song.12000.json','["露湿冠巾，风生襟袖。", "月华耿耿明好昼。", "主人情意十分浓，阮咸横膝清音奏。", "渐永更筹，新凉气候。", "穿针乞巧看看又。", "却怜相聚日无多，偷闲且可陪觞豆。"]'),
('song-ci-978','踏莎行','郭应祥','宋','宋词','song-ci','踏莎行','[]','明月清风，绿尊红袖。',68,'宋词/ci.song.12000.json','["明月清风，绿尊红袖。", "厌厌夜饮胜如昼。", "虽然文字有馀欢，也须闲把笙歌奏。", "十雨如期，三秋届候。", "去年丰稔今年又。", "东阡西陌稼如云，笑他齐量区兼豆。"]'),
('song-ci-979','踏莎行','郭应祥','宋','宋词','song-ci','踏莎行','[]','一撮精神，百般体态。',68,'宋词/ci.song.12000.json','["一撮精神，百般体态。", "兰心蕙性谁能赛。", "霎时不见早思量，许多日子如何捱。", "我已安排，你须宁耐。", "看看重了鸳鸯债。", "此生永愿不分飞，傍人一任胡瞋怪。"]'),
('song-ci-980','踏莎行','郭应祥','宋','宋词','song-ci','踏莎行','[]','自昔中元，多生上相。',68,'宋词/ci.song.12000.json','["自昔中元，多生上相。", "麒麟今又来天上。", "云衢虽未掇勋名，月评先已腾声望。", "宝鼎浓熏，金翘绝唱。", "真珠百斛倾家酿。", "斯辰聊用祝龟龄，他年端合扶鸠杖。"]'),
('song-ci-981','踏莎行','郭应祥','宋','宋词','song-ci','踏莎行','[]','春已经旬，历方换岁。',68,'宋词/ci.song.12000.json','["春已经旬，历方换岁。", "六花依旧来呈瑞。", "细思残腊与新年，一般清绝元非二。", "宿麦连云，遗蝗入地。", "坡仙有句谁能继。", "元宵此去日无多，会看霁色生和气。"]'),
('song-ci-982','南歌子','郭应祥','宋','宋词','song-ci','南歌子','[]','生世逢端午，齐头五十番。',62,'宋词/ci.song.12000.json','["生世逢端午，齐头五十番。", "一番须作一般看。", "又听竞船萧鼓、沸江干。", "不用丝缠臂，休将艾插门。", "及时蒲黍漫登盘。", "只恐岁华催促、鬓毛斑。"]'),
('song-ci-983','南歌子','郭应祥','宋','宋词','song-ci','南歌子','[]','心下悬悬地，侬家好好儿。',62,'宋词/ci.song.12000.json','["心下悬悬地，侬家好好儿。", "相怜相惜许多时。", "岂料一朝轻拆、便轻离。", "要见无由见，教归不肯归。", "数珠懒把镜慵窥。", "只有新添鬓雪、减腰围。"]'),
('song-ci-984','好事近','郭应祥','宋','宋词','song-ci','好事近','[]','春事日相催，红尽浅桃深杏。',53,'宋词/ci.song.12000.json','["春事日相催，红尽浅桃深杏。", "可惜窥园无暇，任绿苔封径。", "凭谁说与雨和风，休要太狂横。", "等待禁烟予告，要选幽寻胜。"]'),
('song-ci-985','卜算子','郭应祥','宋','宋词','song-ci','卜算子','[]','午夜一声雷，急雨如飞雹。',52,'宋词/ci.song.12000.json','["午夜一声雷，急雨如飞雹。", "枝上残红半点无，密叶都成幄。", "苦恨薄书尘，刚把闲身缚。", "却意湄湘春暮时，处处堪行乐。"]'),
('song-ci-986','卜算子','郭应祥','宋','宋词','song-ci','卜算子','[]','城上著裴亭，亭下临湘水。',52,'宋词/ci.song.12000.json','["城上著裴亭，亭下临湘水。", "泼黛揉蓝画不成，暝色仍含紫。", "忙里不知春，却问今馀几。", "相与偷将半日闲，共把尘襟洗。"]'),
('song-ci-987','更漏子','郭应祥','宋','宋词','song-ci','更漏子','[]','月蟠根，天雨粟。',58,'宋词/ci.song.12000.json','["月蟠根，天雨粟。", "宜贮阿娇金屋。", "心欲醉，眼偏明。", "无穷佳思生。", "焰银红，纷宝斝。", "倒著接䍦花下。", "人已散，梦初回。", "渴心犹望梅。"]'),
('song-ci-988','谒金门','郭应祥','宋','宋词','song-ci','谒金门','[]','香篆袅。',53,'宋词/ci.song.12000.json','["香篆袅。", "瓶里梅英犹小。", "鸳瓦霜华睛欲晓。", "今年生日好。", "鬓绿颜朱不老。", "女嫁儿婚将了。", "四世团栾同一笑。", "人间如此少。"]'),
('song-ci-989','鹧鸪天','郭应祥','宋','宋词','song-ci','鹧鸪天','[]','屈指新年五十三。',64,'宋词/ci.song.12000.json','["屈指新年五十三。", "未嫌垂领雪毵毵。", "设弧届旦人交贺，题座无功我自惭。", "荣莫羡，富休贪。", "寿龄也不慕彭聃。", "只思了却痴儿事，一榻香凝晓梦酣。"]'),
('song-ci-990','秦楼月・忆秦娥','郭应祥','宋','宋词','song-ci','秦楼月・忆秦娥','[]','三月一。',56,'宋词/ci.song.12000.json','["三月一。", "题舆恰届垂弧日。", "垂弧日。", "武安门外，欢声扬溢。", "双瞳炯炯头如漆。", "天公付与长生质。", "长生质。", "云霄稳坐，持荷簪笔。"]'),
('song-ci-991','卜算子','郭应祥','宋','宋词','song-ci','卜算子','[]','绿烛间红花，绝艳交相照。',52,'宋词/ci.song.12000.json','["绿烛间红花，绝艳交相照。", "不分花时雨又风，折取供吟笑。", "拟把插乌巾，却恨非年少。", "点笔舒笺领略渠，座客词俱妙。"]'),
('song-ci-992','临江仙','郭应祥','宋','宋词','song-ci','临江仙','[]','姑射仙人肌雪莹，笑他红紫纷纷。',70,'宋词/ci.song.12000.json','["姑射仙人肌雪莹，笑他红紫纷纷。", "从教藏白后庭深。", "虬枝才破蕾，鼻观已遥闻。", "花正繁时春又暮，年华荏苒催人。", "惜花心事与谁论。", "长哦清绝句，目断古南云。"]'),
('song-ci-993','浣溪沙','李壁','宋','宋词','song-ci','浣溪沙','[]','只记梅花破腊前。',48,'宋词/ci.song.12000.json','["只记梅花破腊前。", "恼人春色又薰然。", "山头井似陆公泉。", "上客长谣追楚些，娇娃短舞看胡旋。", "崇桃积李自年年。"]'),
('song-ci-994','朝中措','李壁','宋','宋词','song-ci','朝中措','[]','东风歌吹发重闉。',57,'宋词/ci.song.12000.json','["东风歌吹发重闉。", "飞旆入山新。", "小雨不妨酥润，江头一并霜晴。", "年年心似，输他钗燕，蟠带迎春。", "怎得尊前避酒，史君精鉴如神。"]'),
('song-ci-995','小重山','李壁','宋','宋词','song-ci','小重山','[]','燕雀风轻二月天。',68,'宋词/ci.song.12000.json','["燕雀风轻二月天。", "一枝何处是家园。", "有花不惜是谁怜。", "生嫌怕，不为老人妍。", "眉黛拥连娟。", "高情时载酒、雁湖边。", "略无雕饰自天然。", "新诗好，品第入朱弦。"]'),
('song-ci-996','满江红','李壁','宋','宋词','song-ci','满江红','[]','帘卷东风，□林外、鸟啼姑恶。',114,'宋词/ci.song.12000.json','["帘卷东风，□林外、鸟啼姑恶。", "政迤逦、花梢红绽，柳梢黄著。", "散策丘园容懒□，折冲樽俎须雄略。", "但有书盈屋酒盈缸，还堪乐。", "嗟每被，浮云缚。", "黄梁梦，新来觉。", "悄祗愁湖海，故交辽邈。", "一纸素书来问我，数峰苍玉何如昨。", "更几时、夜雨落檐花，同春酌。"]'),
('song-ci-997','南歌子','李壁','宋','宋词','song-ci','南歌子','[]','紫绶新符竹，叶赪老兄弟。',62,'宋词/ci.song.12000.json','["紫绶新符竹，叶赪老兄弟。", "西风吹棹过湖亭。", "杨柳夫渠相伴、也多情。", "况是瀛洲侣，来同酒盏倾。", "白沤浑不避双旌。", "一种风流人似、玉壶清。"]'),
('song-ci-998','好事近','李壁','宋','宋词','song-ci','好事近','[]','莫惜一樽留，共醉锦屏山色。',53,'宋词/ci.song.12000.json','["莫惜一樽留，共醉锦屏山色。", "多少飞花悠扬，送征轮南陌。", "曲湖归去未多时，还捧诏黄湿。", "生怕别来凄断，看满园行迹。"]'),
('song-ci-999','江神子・江城子','李壁','宋','宋词','song-ci','江神子・江城子','[]','露荷香泛小池台。',86,'宋词/ci.song.12000.json','["露荷香泛小池台。", "水云堆。", "好风催。", "宝扇胡床，无事且徘徊。", "帘外海榴裙一色，判共酹、两三杯。", "此怀能得几番开。", "玉山颓。", "不须推。", "回首慈恩，前梦老堪咍。", "好是上林多少树，应早晚、待公来。"]'),
('song-ci-0','阮郎归','李壁','宋','宋词','song-ci','阮郎归','[]','苏台一别费三年。',56,'宋词/ci.song.13000.json','["苏台一别费三年。", "锦书凭雁传。", "风姿重见阆江边。", "玉壶秋井泉。", "翻短舞，趁么弦。", "篆香同夕烟。", "多情莫惜为留连。", "落花中酒天。"]'),
('song-ci-1','鹧鸪天','李壁','宋','宋词','song-ci','鹧鸪天','[]','岸柳阴阴跃锦鳞。',64,'宋词/ci.song.13000.json','["岸柳阴阴跃锦鳞。", "并湖莲子恰尝新。", "谁教故岁应官去，会老堂中少个人。", "归未久，意弥新。", "吹香不断酒倾银。", "行藏判已天公付，且斗而今见在身。"]'),
('song-ci-2','西江月','李壁','宋','宋词','song-ci','西江月','[]','又送鹏程轩翥，几看驹隙推移。',58,'宋词/ci.song.13000.json','["又送鹏程轩翥，几看驹隙推移。", "多端时事只天知。", "不饮沈忧如醉。", "白首已甘蓬艾，苍生正倚丞疑。", "楚台风转一帆吹。", "朝列问君来未。"]'),
('song-ci-3','临江仙','韩淲','宋','宋词','song-ci','临江仙','["\u4e5d\u534e\u5c71"]','难老一杯春酒美，主人玉监清秋。',70,'宋词/ci.song.13000.json','["难老一杯春酒美，主人玉监清秋。", "九华山下共追游。", "朝来多爽气，都向笔端收。", "台阁功名归去好，便应衮衮公侯。", "未妨含笑看吴钩。", "当年佳梦日，和气瑞光浮。"]'),
('song-ci-4','满江红','韩淲','宋','宋词','song-ci','满江红','[]','五老峰前，九江上、曾生仙客。',115,'宋词/ci.song.13000.json','["五老峰前，九江上、曾生仙客。", "相邂逅、贵池亭下，定交金石。", "我辈风流宜啸咏，官曹尘冗从煎逼。", "且簿书、丛里举清觞，偷闲日。", "同一笑，当今夕。", "梅正好，香浮白。", "便相忘尔汝，醉巾沾湿。", "已向琼楼夸意态，似闻金殿传消息。", "想君今、归去际风云，应相忆。"]'),
('song-ci-5','柳梢青','韩淲','宋','宋词','song-ci','柳梢青','[]','云淡秋空。',61,'宋词/ci.song.13000.json','["云淡秋空。", "一江流水，烟雨濛濛。", "岸转溪回，野平山远，几点征鸿。", "行人独倚孤篷。", "算此景、如图画中。", "莫问功名，且寻诗酒，一棹西风。"]'),
('song-ci-6','醉蓬莱','韩淲','宋','宋词','song-ci','醉蓬莱','["\u897f\u6e56"]','问西湖好处，楼上薰风，有谁称寿。',120,'宋词/ci.song.13000.json','["问西湖好处，楼上薰风，有谁称寿。", "十里荷香，对槐阴清昼。", "细浪揉蓝，远山凝黛，更管弦初奏。", "醉舞嗟嗟，欢声沸沸，生申时候。", "膝下婆娑，老莱儿戏，帝所辉光，使衣呈绣。", "眷倚方隆，赐金章华绶。", "自此飞腾，凤阁鸾台，好满斟醇酎。", "道骨仙风，朱颜青鬓，年年依旧。"]'),
('song-ci-7','水调歌头','韩淲','宋','宋词','song-ci','水调歌头','[]','明月到花影，把酒对香红。',114,'宋词/ci.song.13000.json','["明月到花影，把酒对香红。", "此情飘洒，但觉清景满帘栊。", "人被好花相恼，花亦知人幽韵，佳处本同风。", "挥手谢尘网，举袂步蟾宫。", "秋已半，幽涧侧，乱山中。", "故人过我，终夕乘兴可千锺。", "赖有曲江才子，坐上平章花月，不管老英雄。", "心事将何寄，醉语又匆匆。"]'),
('song-ci-8','贺新郎','韩淲','宋','宋词','song-ci','贺新郎','[]','万事佯休去。',142,'宋词/ci.song.13000.json','["万事佯休去。", "漫栖迟、灵山起雾，玉溪流渚。", "击楫凄凉千古意，怅怏衣冠南渡。", "泪暗洒、神州沈处。", "多少胸中经济略，气□□、郁郁愁金鼓。", "空自笑，听鸡舞。", "天关九虎寻无路。", "叹都把、生民膏血，尚交胡虏。", "吴蜀江山无自好，形势何能尽语。", "但目尽、东南风土。", "赤壁楼船应似旧，问子瑜、公瑾今安否。", "割舍了，对君举。"]'),
('song-ci-9','贺新郎','韩淲','宋','宋词','song-ci','贺新郎','[]','病起情怀恶。',142,'宋词/ci.song.13000.json','["病起情怀恶。", "小帘栊、杨花坠絮，木阴成幄。", "试问春光今几许，都把年华忘却。", "更多少、从前盟约。", "拟待莺边寻好语，恍残红、零乱风回薄。", "思住事，信如昨。", "清明寒食须行乐。", "算人生、何时富贵，自徒萧索。", "试著春衫从酒伴，乱插繁英嫩萼。", "信莫被、功名担阁。", "随分溪山供笑傲，这一身、闲处谁能缚。", "琴剑外，尽杯酌。"]'),
('song-ci-10','清平乐','韩淲','宋','宋词','song-ci','清平乐','[]','鸣琴单父。',54,'宋词/ci.song.13000.json','["鸣琴单父。", "凫舄宜飞去。", "不比河阳花满树。", "此意直高千古。", "清秋诞日相逢。", "乃同涧上村侬。", "笑指壶山为寿，仁心静处加功。"]'),
('song-ci-11','水龙吟','韩淲','宋','宋词','song-ci','水龙吟','[]','从来江左夷吾，大名迥诸出公右。',126,'宋词/ci.song.13000.json','["从来江左夷吾，大名迥诸出公右。", "金堂玉室，瑶林琼树，龙麟蟠走。", "志在神皋，气雄云梦，十吞八九。", "问三槐盛事，当年初度，人应羡、青毡旧。", "说与文章太守。", "庆千秋、好为亲寿。", "冰桃雪藕，霞裾月佩，莺鸾歌奏。", "雨熟西畴，星躔南极，宝香凝昼。", "趁新凉，便约乘云绕日，饮天浆酒。"]'),
('song-ci-12','清平乐','韩淲','宋','宋词','song-ci','清平乐','[]','萧然在涧。',54,'宋词/ci.song.13000.json','["萧然在涧。", "景色秋来冠。", "几缕明霞红未断。", "矫首时时遐观。", "回思五马清游。", "分明前辈风流。", "留作山间佳话，更谁愁上眉头。"]'),
('song-ci-13','踏莎行','韩淲','宋','宋词','song-ci','踏莎行','[]','雨意生凉，云容催暮。',68,'宋词/ci.song.13000.json','["雨意生凉，云容催暮。", "画楼人倚阑干处。", "柳边新月已微明，银潢隐隐疏星渡。", "今古佳期，漫传牛女。", "一杯试与寻新句。", "幽怀冷眼是青山，旧欢往恨浑无据。"]'),
('song-ci-14','清平乐','韩淲','宋','宋词','song-ci','清平乐','[]','常思高致。',54,'宋词/ci.song.13000.json','["常思高致。", "又见凉风起。", "欢喜年时为寿意。", "快写山歌重寄。", "愿公好德康宁。", "青云收取功名。", "莫道而今官小，吾儒正要仁民。"]'),
('song-ci-15','柳梢青','韩淲','宋','宋词','song-ci','柳梢青','[]','雨洗元宵。',61,'宋词/ci.song.13000.json','["雨洗元宵。", "楼台烟锁，隐隐笙箫。", "且插梅花，自烧银烛，沈水香飘。", "软红尘里星桥。", "想霁色、皇都绛霄。", "屏掩潇湘，醉和衣倒，春梦迢迢。"]'),
('song-ci-16','菩萨蛮','韩淲','宋','宋词','song-ci','菩萨蛮','[]','雪云收尽晴风软。',52,'宋词/ci.song.13000.json','["雪云收尽晴风软。", "小山春浪晴波远。", "梅片已飞香。", "海棠红试妆。", "人言诗易与。", "酒盏谁分付。", "不是没心情。", "夕阳啼鸟声。"]'),
('song-ci-17','一翦梅','韩淲','宋','宋词','song-ci','一翦梅','[]','说著相思梦亦愁。',72,'宋词/ci.song.13000.json','["说著相思梦亦愁。", "芳草斜阳，春满秦楼。", "楼前新绿水西流。", "一曲阳关，分付眉头。", "多少风流事已休。", "纷薄香浓，怕见绸缪。", "淡云笼月小庭幽。", "明日山长，清恨悠悠。"]'),
('song-ci-18','海月谣','韩淲','宋','宋词','song-ci','海月谣','[]','晚秋烟渚。',79,'宋词/ci.song.13000.json','["晚秋烟渚。", "更舟倚、萧萧雨。", "水痕清汜，迤逦渐整，云帆西去。", "三叠阳关，留下别离情绪。", "溪南一坞。", "对风月、谁为主。", "酒徒诗社，自此冷落，胸怀尘土。", "目送鸿飞，莫听数柔橹。"]'),
('song-ci-19','好事近','韩淲','宋','宋词','song-ci','好事近','[]','春色入芳梢，点缀万枝红玉。',53,'宋词/ci.song.13000.json','["春色入芳梢，点缀万枝红玉。", "莫道怕愁贪睡，倚新妆如束。", "纷纷桃李太妖娆，相对夜阑烛。", "记取疏花横处，有暗香飘馥。"]'),
('song-ci-20','菩萨蛮','韩淲','宋','宋词','song-ci','菩萨蛮','[]','平生常为梅花醉。',52,'宋词/ci.song.13000.json','["平生常为梅花醉。", "数枝滴滴香沾袂。", "雪后月华明*胆瓶无限清。", "夜深灯影瘦。", "饮尽杯中酒。", "明日景尤新。", "人间都是春。"]'),
('song-ci-21','西江月','韩淲','宋','宋词','song-ci','西江月','[]','春色著人多少，溪头桃杏舒红。',58,'宋词/ci.song.13000.json','["春色著人多少，溪头桃杏舒红。", "杖藜相与过桥东。", "往事旧欢如梦。", "花底醉眠芳草，柳边嘶入骄骢。", "如今憔悴坐诗穷。", "莫问醯鸡舞瓮。"]'),
('song-ci-22','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','一曲青山映小池。',48,'宋词/ci.song.13000.json','["一曲青山映小池。", "林疏人静月明时。", "相逢杯酒也相宜。", "醉眼不知春事少，欢情犹得漏声迟。", "神仙何处梦魂飞。"]'),
('song-ci-23','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','宝鸭香消酒未醒。',48,'宋词/ci.song.13000.json','["宝鸭香消酒未醒。", "锦衾春暖梦初惊。", "鬓云撩乱玉钗横。", "半怯夜寒褰绣幌，尚馀娇困剔银灯。", "粉痕微褪脸霞生。"]'),
('song-ci-24','西江月','韩淲','宋','宋词','song-ci','西江月','[]','风暖晨光寂寂，月明夜气沈沈。',58,'宋词/ci.song.13000.json','["风暖晨光寂寂，月明夜气沈沈。", "山间林下步轻阴。", "花柳飞绵布锦。", "酒病向谁能遣，春愁惟我难禁。", "尊前一曲断肠声。", "梦破晓窗敧枕。"]'),
('song-ci-25','朝中措','韩淲','宋','宋词','song-ci','朝中措','[]','池塘春草燕飞飞。',56,'宋词/ci.song.13000.json','["池塘春草燕飞飞。", "人醉牡丹时。", "多少姚黄魏紫，搦成腻粉燕支。", "谪仙醉把平章看，晴影度帘迟。", "花外一声鶗鴂，柳边几个黄鹂。"]'),
('song-ci-26','水调歌头','韩淲','宋','宋词','song-ci','水调歌头','[]','今古钓台下，行客系扁舟。',114,'宋词/ci.song.13000.json','["今古钓台下，行客系扁舟。", "扁舟何似，云山千叠亦东游。", "我欲停桡一醉，与写平生幽愤，横管更清讴。", "小上客星阁，短鬓独搔头。", "风乍起，烟未敛，雨初收。", "一年花事，数声鶗鴂欲春休。", "吊古怀贤情味，只有浮名如故，谁复识羊裘。", "赖得玄英隐，相望此溪流。"]'),
('song-ci-27','西江月','韩淲','宋','宋词','song-ci','西江月','[]','梅蕊小春天气，橘林良月风光。',58,'宋词/ci.song.13000.json','["梅蕊小春天气，橘林良月风光。", "五云边近九霞觞。", "美景初无尽藏。", "老矣相逢湖海，年来游遍潇湘。", "诗情满眼兴何长。", "赢得烟霄直上。"]'),
('song-ci-28','卜算子','韩淲','宋','宋词','song-ci','卜算子','[]','花底醉东风，好景宜同寿。',52,'宋词/ci.song.13000.json','["花底醉东风，好景宜同寿。", "海角天涯今几春，邂逅新丰酒。", "内集记高阳，南渡闲回首。", "但愿长年饱饭休，一笑风尘表。"]'),
('song-ci-29','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','小雨收晴作社寒。',48,'宋词/ci.song.13000.json','["小雨收晴作社寒。", "月桥花院篆香残。", "杏腮桃脸黛眉弯。", "歌拂燕梁牵客恨，醉临鸾镜怕人看。", "良宵春梦绕屏山。"]'),
('song-ci-30','菩萨蛮','韩淲','宋','宋词','song-ci','菩萨蛮','[]','海棠欲谢绵飞柳。',52,'宋词/ci.song.13000.json','["海棠欲谢绵飞柳。", "柳丝自拂行人首。", "上巳是清明。", "新烟带粥饧。", "轻阴帘幕冷。", "闲却秋千影。", "曲水兴无涯。", "丽人花半遮。"]'),
('song-ci-31','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','湖海相逢更日边。',48,'宋词/ci.song.13000.json','["湖海相逢更日边。", "槐风莲雨寿杯前。", "琴书图画水沈烟。", "共指金銮当儤直，不应彭泽尚回旋。", "今年初度想超然。"]'),
('song-ci-32','恋绣衾','韩淲','宋','宋词','song-ci','恋绣衾','[]','欢浓两点笑靥儿。',68,'宋词/ci.song.13000.json','["欢浓两点笑靥儿。", "雪初消、梅欲放时。", "不信道、伤春瘦，怕人猜、犹待皱眉。", "香浓翠被屏山曲，把珊枕、侧过又移。", "试与伴、江头去，但醉翁、亭上要诗。"]'),
('song-ci-33','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','一曲霓裳舞未终。',48,'宋词/ci.song.13000.json','["一曲霓裳舞未终。", "玉钗垂额鬓云松。", "梦回金殿月华东。", "燕子莺儿情脉脉，柳枝桃叶恨匆匆。", "罗襟空惹御香浓。"]'),
('song-ci-34','步蟾宫','韩淲','宋','宋词','song-ci','步蟾宫','[]','三年重到严滩路。',73,'宋词/ci.song.13000.json','["三年重到严滩路。", "叹须鬓、衣冠尘土。", "倚孤篷、闲自濯清风，见一片、飞鸿归去。", "人间何用论今古。", "漫赢得、个般情绪。", "雨吹来云、乱处水东流，但只有、青山如故。"]'),
('song-ci-35','水调歌头','韩淲','宋','宋词','song-ci','水调歌头','[]','一枕暑风外，事事且随缘。',114,'宋词/ci.song.13000.json','["一枕暑风外，事事且随缘。", "随缘何处琴剑，闲泊此层巅。", "日绕九天楼殿，烟抹四山林薄，尘土市声前。", "老眼醉还醒，犹得到诗边。", "桥南院，双桂隐，有名言。", "江湖人物，好在收拾付书帘。", "回首吾庐无恙，寄卧僧窗何事，鸿鹄本高骞。", "水调赋明月，谁道更超然。"]'),
('song-ci-36','鹧鸪天','韩淲','宋','宋词','song-ci','鹧鸪天','[]','雨湿西风水面烟。',64,'宋词/ci.song.13000.json','["雨湿西风水面烟。", "一巾华发上溪船。", "帆迎山色来还去，橹破滩痕散复圆。", "寻浊酒，试吟篇。", "避人鸥鹭更翩翩。", "五更犹作钱塘梦，睡觉方知过眼前。"]'),
('song-ci-37','水调歌头','韩淲','宋','宋词','song-ci','水调歌头','[]','嘉节已吹帽，谁复见南山。',114,'宋词/ci.song.13000.json','["嘉节已吹帽，谁复见南山。", "南山佳处，台上云绕一溪环。", "犹记使君同醉，化鹤千年何在，今古自应悭。", "胜事漫陈迹，风物只高寒。", "都莫问，归酒畔，集毫端。", "等闲吟笑而已，赖有孔融尊。", "伟矣广平心致，赢得相遭淡泊，感旧唱酬闲。", "且看小斋菊，抵掌共凭阑。"]'),
('song-ci-38','减字木兰花','韩淲','宋','宋词','song-ci','减字木兰花','[]','年光虚度。',52,'宋词/ci.song.13000.json','["年光虚度。", "能得几多消散处。", "莫恨归迟。", "得见新词不自持。", "山中酒里。", "笑语喧哗知有弟。", "此意谁如。", "世事纷纷一任渠。"]'),
('song-ci-39','生查子','韩淲','宋','宋词','song-ci','生查子','[]','霜叶柳塘风，烟蕊梅溪渡。',48,'宋词/ci.song.13000.json','["霜叶柳塘风，烟蕊梅溪渡。", "茅店问村醪，未许空归去。", "倚杖小徘徊，写我吟边句。", "醉眼复何之，落日孤鸿处。"]'),
('song-ci-40','西江月','韩淲','宋','宋词','song-ci','西江月','[]','闻道晚春时候，暖风是处花飘。',58,'宋词/ci.song.13000.json','["闻道晚春时候，暖风是处花飘。", "游人争渡水南桥。", "多少池塘春草。", "跃马谁联玉勒，钓鱼应泛兰桡。", "韶光何限不逍遥。", "输与溪鸥野鸟。"]'),
('song-ci-41','朝中措','韩淲','宋','宋词','song-ci','朝中措','[]','春浓人静倦游嬉。',56,'宋词/ci.song.13000.json','["春浓人静倦游嬉。", "烟雨战棠梨。", "翠径乱红无数，频啼枝上黄鹂。", "小园流水溅溅处，绿遍谢家池。", "怨月恨花滋味，泪痕犹染罗衣。"]'),
('song-ci-42','小重山','韩淲','宋','宋词','song-ci','小重山','[]','云影收晴雨外明。',70,'宋词/ci.song.13000.json','["云影收晴雨外明。", "碧溪春滟滟，落花平。", "莺声催我过桥行。", "人何在，诗酒淡心情。", "闲里兴还生。", "锦鳞题尺素，有谁能。", "草边芳径柳边城。", "归来也，清梦绕山屏。"]'),
('song-ci-43','临江仙','韩淲','宋','宋词','song-ci','临江仙','[]','脆管繁弦无觅处，小楼空掩遥山。',70,'宋词/ci.song.13000.json','["脆管繁弦无觅处，小楼空掩遥山。", "柳丝直下曲阑干。", "海棠红欲褪，玉钏怯春衫。", "殢酒不成芳信断，社寒新燕呢喃。", "雕盘慵整宝香残。", "绮疏明薄暮，帘外雨潺潺。"]'),
('song-ci-44','朝中措','韩淲','宋','宋词','song-ci','朝中措','[]','五湖烟水百花洲。',56,'宋词/ci.song.13000.json','["五湖烟水百花洲。", "别乘最风流。", "人道紫枢家世，清时衮衮公侯。", "名园绿水春无价，蜀锦舞缠头。", "眉寿年年今日，宝杯香霭飞浮。"]'),
('song-ci-45','月宫春','韩淲','宋','宋词','song-ci','月宫春','[]','柳娇花妒燕莺喧。',57,'宋词/ci.song.13000.json','["柳娇花妒燕莺喧。", "断肠空眼穿。", "一春风雨夜厌厌。", "不闻钟鼓传。", "香冷曲屏罗帐掩，园林谁与上秋千。", "忆得年时凤枕，日高犹醉眠。"]'),
('song-ci-46','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','芍药酴醿满院春。',48,'宋词/ci.song.13000.json','["芍药酴醿满院春。", "门前杨柳媚晴曛。", "重帘双燕语沈沈。", "花映绿娇初日嫩，叶栖红小晚烟昏。", "轻雷不觉送微阴。"]'),
('song-ci-47','鹧鸪天','韩淲','宋','宋词','song-ci','鹧鸪天','[]','烟禁荒荒雨湿云。',64,'宋词/ci.song.13000.json','["烟禁荒荒雨湿云。", "近郊争出满城人。", "儿童藉草几成市，杯酒沾花不觉村。", "身又老，眼增明。", "回头一任是红尘。", "山中谁信无寒食，涧上何如且采苹。"]'),
('song-ci-48','一丛花','韩淲','宋','宋词','song-ci','一丛花','[]','翻空雪浪送飞花。',94,'宋词/ci.song.13000.json','["翻空雪浪送飞花。", "春晓媚霜华。", "风回点点迷人处，峭寒轻、诗思殊佳。", "双燕未来，断鸿何在，微雨又天涯。", "绮窗明暗是谁家。", "雕槛馥兰芽。", "画檐帘幕黄昏后，试倾杯、笑语喧哗。", "聚散人生，吾侪老矣，醉墨任横斜。"]'),
('song-ci-49','眼儿媚','韩淲','宋','宋词','song-ci','眼儿媚','[]','东风拂槛露犹寒。',58,'宋词/ci.song.13000.json','["东风拂槛露犹寒。", "花重湿阑干。", "淡云殢日，晨光微透，帘幕香残。", "阴晴不定瑶阶润，新恨觉心阑。", "凭高望断，绿杨南陌，无限关山。"]'),
('song-ci-50','青玉案','韩淲','宋','宋词','song-ci','青玉案','["\u897f\u6e56"]','苏公堤上西湖路。',80,'宋词/ci.song.13000.json','["苏公堤上西湖路。", "柳外跃、青骢去。", "多少韶华惊暗度。", "南山游遍，北山归后，总是题诗处。", "如今老矣伤春暮。", "泽畔行吟漫寻句。", "落拓情怀空自许。", "小园芳草，短篱修竹，点点飞花雨。"]'),
('song-ci-51','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','只恐山灵俗驾回。',48,'宋词/ci.song.13000.json','["只恐山灵俗驾回。", "海鸥飞下莫惊猜。", "机心消尽重徘徊。", "宿雨乍晴千涧落，晓云微露两山排。", "新苗时翼好风来。"]'),
('song-ci-52','朝中措','韩淲','宋','宋词','song-ci','朝中措','[]','扁舟撑月转江湖。',56,'宋词/ci.song.13000.json','["扁舟撑月转江湖。", "烟水湛金铺。", "篷底晓凉歌罢，肌肤冰雪初扶。", "诗人自是风尘表，佳处句能摹。", "属玉一双飞去，荷花香动菰蒲。"]'),
('song-ci-53','明月棹孤舟・夜行船','韩淲','宋','宋词','song-ci','明月棹孤舟・夜行船','["\u897f\u6e56"]','忽得相逢惊似旧。',68,'宋词/ci.song.13000.json','["忽得相逢惊似旧。", "问山中、酒徒诗友。", "闲倚睛楼，长安市上，华发为君搔首。", "绿竹疏梅今在否。", "对西湖、夕阳烟岫。", "鸿雁声中，人间今古，还是醉醒时候。"]'),
('song-ci-54','江城子','韩淲','宋','宋词','song-ci','江城子','[]','天孙应为织云裳。',86,'宋词/ci.song.13000.json','["天孙应为织云裳。", "试宫妆。", "问刘郎。", "湖上波寒，依旧远山苍。", "自是老来心事懒，空落拓，少年场。", "挥豪闲与细端相。", "记严扬。", "陋苏张。", "兴到一杯，微醉亦成章。", "回首片帆西去也，何日更，共清狂。"]'),
('song-ci-55','冉冉云','韩淲','宋','宋词','song-ci','冉冉云','[]','倚遍阑干弄花雨。',72,'宋词/ci.song.13000.json','["倚遍阑干弄花雨。", "卷珠帘、草迷芳树。", "山崦里、几许云烟来去。", "画不就、人家院宇。", "社寒梁燕呢喃舞。", "小桃红、海棠初吐。", "谁信道、午醉醒时情绪。", "闲整春衫自语。"]'),
('song-ci-56','谒金门','韩淲','宋','宋词','song-ci','谒金门','[]','花影半。',53,'宋词/ci.song.13000.json','["花影半。", "晴色乍开云卷。", "择胜寻春愁日短。", "雨馀山路晚。", "涧底桃深红满。", "人意不禁闲远。", "胡蝶绕枝啼鸟怨。", "东风吹酒面。"]'),
('song-ci-57','满庭芳','韩淲','宋','宋词','song-ci','满庭芳','[]','点点淮山，迢迢江水，分明别是风光。',118,'宋词/ci.song.13000.json','["点点淮山，迢迢江水，分明别是风光。", "地灵人杰，星斗烂文章。", "初度充闾佳气，当年瑞、应弄珪璋。", "薰弦奏，凉宵宝月，玉井藕花香。", "清真，如逸少，兰亭修竹，曲水流觞。", "想醉乡日永，地久天长。", "小驻屏星怀玉，飞凫舄、元在鹓行。", "功名事，云龙风虎，行矣佩金章。"]'),
('song-ci-58','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','一曲西风醉木犀。',48,'宋词/ci.song.13000.json','["一曲西风醉木犀。", "天香吹梦入瑶池。", "钗横犹记未开枝。", "花重嫩舒红笑脸，叶稀轻拂翠颦眉。", "酒醒残月雁声迟。"]'),
('song-ci-59','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','山气吹云宝月凉。',48,'宋词/ci.song.13000.json','["山气吹云宝月凉。", "园英承露菊花黄。", "吾生只合醉为乡。", "怅望佳人因共赋，分明佳节是重阳。", "酒边犹发少年狂。"]'),
('song-ci-60','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','莫问星星鬓染霜。',48,'宋词/ci.song.13000.json','["莫问星星鬓染霜。", "一杯同看月昏黄。", "放歌渔父濯沧浪。", "却忆手栽双柳句，真成云汉抉天章。", "苏仙何在立苍茫。"]'),
('song-ci-61','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','霜后黄花尚自开。',48,'宋词/ci.song.13000.json','["霜后黄花尚自开。", "老年情绪为何哉。", "株株浑是手亲栽。", "秋际有言挥玉尘，冬来无梦绕金钗。", "相思一夜发窗梅。"]'),
('song-ci-62','江城子','韩淲','宋','宋词','song-ci','江城子','[]','雪消霜入小溪舟。',86,'宋词/ci.song.13000.json','["雪消霜入小溪舟。", "试浮游。", "上山头。", "薄薄寒烟，依旧未全收。", "问道梅花开也未，吟不尽，一春愁。", "襟怀如此老还休。", "懒凝眸。", "转深幽。", "诗罢一眉，新月又如钩。", "腊后春前村意远，回棹稳，水西流。"]'),
('song-ci-63','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','月角珠庭映伏犀。',48,'宋词/ci.song.13000.json','["月角珠庭映伏犀。", "扶摇当上凤凰池。", "广寒曾折最高枝。", "壮志还同诸葛膝，清名还似紫芝眉。", "梅花春寿酒行迟。"]'),
('song-ci-64','鹧鸪天','韩淲','宋','宋词','song-ci','鹧鸪天','[]','老去情怀酒味中。',64,'宋词/ci.song.13000.json','["老去情怀酒味中。", "水边林下古人风。", "岁云暮矣江空晚，谁识儋州秃鬓翁。", "人易远，语难工。", "春时犹记一尊同。", "苦心未免皆如此，只合挥弦目送鸿。"]'),
('song-ci-65','风入松','韩淲','宋','宋词','song-ci','风入松','[]','小楼春映远山横。',88,'宋词/ci.song.13000.json','["小楼春映远山横。", "绿遍高城。", "望中一片斜阳静，更萋萋、芳草还生。", "疏雨冷烟寒食，落花飞絮清明。", "数声弦管忍重听。", "犹带微酲。", "问春何事春将老，春不语、春恨难平。", "莫把风流时节，都归闲淡心情。"]'),
('song-ci-66','菩萨蛮','韩淲','宋','宋词','song-ci','菩萨蛮','[]','小园红入春无际。',52,'宋词/ci.song.13000.json','["小园红入春无际。", "新声休写花间意。", "一笑唤真真。", "香腮酒未醒。", "惜芳追胜事。", "畅饮馀诗思。", "无处说衷情。", "暗尘罗帐生。"]'),
('song-ci-67','谒金门','韩淲','宋','宋词','song-ci','谒金门','[]','花肃肃。',53,'宋词/ci.song.13000.json','["花肃肃。", "杨柳三眠未足。", "一棹溪山新涨绿。", "旧欢无梦续。", "莫问杜鹃啼蜀。", "只有江南水竹。", "北客凄凉无伴独。", "春山生草木。"]'),
('song-ci-68','谒金门','韩淲','宋','宋词','song-ci','谒金门','[]','幽意熟。',53,'宋词/ci.song.13000.json','["幽意熟。", "吟啸春风自足。", "爽气初生晴未燠。", "相逢休问卜。", "画出高山盘谷。", "岩上飞云相逐。", "他日江东思渭北。", "断舷谁为续。"]'),
('song-ci-69','卜算子','韩淲','宋','宋词','song-ci','卜算子','[]','一雨已秋深，月色寒而静。',52,'宋词/ci.song.13000.json','["一雨已秋深，月色寒而静。", "夜半披衣草树间，玉露团清影。", "长笛倚楼声，听彻还重省。", "手启柴门倦复关，云卧衣裳冷。"]'),
('song-ci-70','醉蓬莱','韩淲','宋','宋词','song-ci','醉蓬莱','[]','庆文章太守，燕寝凝香，诞弥佳节。',120,'宋词/ci.song.13000.json','["庆文章太守，燕寝凝香，诞弥佳节。", "庾岭归来，又经年梅发。", "棋酒心情，笙歌滋味，便合朝天阙。", "玉作山前，冰为水际，几多风月。", "绿鬓朱颜，浩然相对，自是中原，旧家人物。", "鹓鹭班回，尚记陪清切。", "好把胸蟠万卷，谈笑了、济时勋业。", "锦幄初温，宝杯深劝，舞回香雪。"]'),
('song-ci-71','朝中措','韩淲','宋','宋词','song-ci','朝中措','[]','为兹春酒寿诗翁。',56,'宋词/ci.song.13000.json','["为兹春酒寿诗翁。", "我辈一尊同。", "香动梅梢圆月，年年先得东风。", "冰溪清浅流环玉，莲幕漫从容。", "但愿人生长久，挥弦目送飞鸿。"]'),
('song-ci-72','太常引','韩淲','宋','宋词','song-ci','太常引','[]','小春时候腊前梅。',62,'宋词/ci.song.13000.json','["小春时候腊前梅。", "还知道、为谁开。", "应绕百千回。", "夜色转、参横斗魁。", "十分孤静，替伊愁绝，片月共徘徊。", "一阵暗香来。", "便觉得、诗情有涯。"]'),
('song-ci-73','朝中措','韩淲','宋','宋词','song-ci','朝中措','[]','谁翻新曲玉溪滨。',56,'宋词/ci.song.13000.json','["谁翻新曲玉溪滨。", "何日得为邻。", "醉里行歌相答，步随泉石松云。", "如今又是梅时候，只有眼中人。", "魂断幽香孤影，花前闲整衣巾。"]'),
('song-ci-74','恋绣衾','韩淲','宋','宋词','song-ci','恋绣衾','[]','溪风吹雨晚打窗。',68,'宋词/ci.song.13000.json','["溪风吹雨晚打窗。", "把心情、阑入醉乡。", "记取在、山深处，我如今、双鬓已苍。", "夜阑寒影灯花淡，梦难成、清漏更长。", "宝瑟断、鸾胶续，泪珠弹、犹带粉香。"]'),
('song-ci-75','一翦梅','韩淲','宋','宋词','song-ci','一翦梅','["\u897f\u6e56"]','一朵梅花百和香。',72,'宋词/ci.song.13000.json','["一朵梅花百和香。", "浅色春风，别样宫妆。", "西湖衣钵更难忘。", "雪意江天，浑断人肠。", "清夜横斜竹影窗。", "赢得相思，魂梦悠扬。", "玉溪山外水云乡。", "茅舍疏篱，不换金章。"]'),
('song-ci-76','蝶恋花','韩淲','宋','宋词','song-ci','蝶恋花','[]','道上疏梅花一树。',70,'宋词/ci.song.13000.json','["道上疏梅花一树。", "人去人来，不管流年度。", "闲过南豅同散步。", "东风为我吹香去。", "试问青春今几许。", "明日新正，溪影横山暮。", "遮莫攀翻君且住。", "心儿却在题诗处。"]'),
('song-ci-77','蝶恋花','韩淲','宋','宋词','song-ci','蝶恋花','[]','尽道今年春较早。',70,'宋词/ci.song.13000.json','["尽道今年春较早。", "梅与人情，觉得梅偏好。", "一树南豅香未老。", "春风已自生芳草。", "来自城中犹带晓。", "行到君家，细雨吹池沼。", "怅望沙坑须会到。", "玉溪此意年时少。"]'),
('song-ci-78','生查子','韩淲','宋','宋词','song-ci','生查子','[]','山意入春晴，都是梅和柳。',48,'宋词/ci.song.13000.json','["山意入春晴，都是梅和柳。", "白白与青青，日映风前酒。", "归去也如何，路上休回首。", "各自做新年，柳袅梅枝瘦。"]'),
('song-ci-79','探春令','韩淲','宋','宋词','song-ci','探春令','[]','暗尘明月小桃枝，旧家时情味。',64,'宋词/ci.song.13000.json','["暗尘明月小桃枝，旧家时情味。", "问而今、风转蛾儿底。", "有谁把、春衫试。", "景龙灯火升平世。", "动长安歌吹。", "这山城、不道人能记。", "甚村酒、偏教醉。"]'),
('song-ci-80','临江仙','韩淲','宋','宋词','song-ci','临江仙','[]','罗帐画屏新梦悄，绿窗慵起香残。',70,'宋词/ci.song.13000.json','["罗帐画屏新梦悄，绿窗慵起香残。", "重帘生怕倚阑干。", "春风吹玉水，春雪满灵山。", "梁燕未来归雁动，海棠才带红酣。", "酒愁花恨霎时间。", "烟云催薄暮，丝雨湿轻寒。"]'),
('song-ci-81','眼儿媚','韩淲','宋','宋词','song-ci','眼儿媚','[]','风回香雪到梨花。',58,'宋词/ci.song.13000.json','["风回香雪到梨花。", "山影是谁家。", "小窗未晚，重檐初霁，玉倚蒹葭。", "社寒不管人如此，依旧在天涯。", "碧云暮合，芳心撩乱，醉眼横斜。"]'),
('song-ci-82','临江仙','韩淲','宋','宋词','song-ci','临江仙','[]','竹树阴阴流涧水，黄鹂飞去飞还。',70,'宋词/ci.song.13000.json','["竹树阴阴流涧水，黄鹂飞去飞还。", "蓬门篱落小桥湾。", "更无尘迹到，我自爱其闲。", "雨又随风催薄暮，轻雷时动云斑。", "归来凉意一窗间。", "病馀真倦矣，睡熟簟纹宽。"]'),
('song-ci-83','蝶恋花','韩淲','宋','宋词','song-ci','蝶恋花','[]','斜日清霜山薄暮。',70,'宋词/ci.song.13000.json','["斜日清霜山薄暮。", "行到桥东，林竹疑无路。", "小院横窗香噀雾。", "胆屏曲几花如雨。", "细酌心情因少驻。", "九万刚风，寒影吹琼素。", "不是月宫那有许。", "霓裳舞彻凌波步。"]'),
('song-ci-84','柳梢青','韩淲','宋','宋词','song-ci','柳梢青','[]','玉水明沙。',61,'宋词/ci.song.13000.json','["玉水明沙。", "峰回路转，城倚桥斜。", "老我登临，同谁酩酊，一望还赊。", "飞鸿杳霭天涯。", "但拚取、心情酒家。", "紫菊枝枝，红茱颗颗，休问年华。"]'),
('song-ci-85','满庭芳','韩淲','宋','宋词','song-ci','满庭芳','[]','玉水灵山，霜天清晓，非烟非雾琴堂。',118,'宋词/ci.song.13000.json','["玉水灵山，霜天清晓，非烟非雾琴堂。", "载临初度，圭璧记煌煌。", "百里民安抚字，欢呼处、禾黍登场。", "今年好，为兹春酒，莫惜醉淋浪。", "神仙，□领袖，山河勋业，星斗文章。", "便黄扉青琐，会遇明良。", "愿赐尚方之剑，攀槛折、於古辉光。", "飞凫去，甘棠遗爱，留与话桐乡。"]'),
('song-ci-86','菩萨蛮','韩淲','宋','宋词','song-ci','菩萨蛮','[]','风前觅得梅花句。',52,'宋词/ci.song.13000.json','["风前觅得梅花句。", "香来自是相分付。", "片月动黄昏。", "一枝横酒尊。", "人间何处有。", "又到春时候。", "莫负此诗家。", "将心吟好花。"]'),
('song-ci-87','贺新郎','韩淲','宋','宋词','song-ci','贺新郎','[]','梅蕊依稀矣。',142,'宋词/ci.song.13000.json','["梅蕊依稀矣。", "岁华深、け然但把，杖藜闲倚。", "山绕荒林红叶下，落日孤城烟水。", "意兴寄、云何则是。", "底事疏枝横绝峭，未吹香、便与花相似。", "不忍折，为之喜。", "寒鸦万点霜风起。", "正人家、园收芋栗，小槽初美。", "欲醉阿谁同一饮，拟赋才成又止。", "老态度、浑侵发齿。", "摸索孤根春在否。", "任红红、白白皆桃李。", "空烂漫，岂能尔。"]'),
('song-ci-88','百字令・念奴娇','韩淲','宋','宋词','song-ci','百字令・念奴娇','["\u897f\u6e56"]','诏飞天上，看金狨系马，西湖风月。',120,'宋词/ci.song.13000.json','["诏飞天上，看金狨系马，西湖风月。", "朝罢香烟携满袖，身在琼楼玉阙。", "锦绣肝肠，珠玑欬唾，绿鬓非华发。", "与谁经济，河山应笑吴越。", "且把春酒寻梅，年年眉寿，坐对南枝发。", "兵卫朱门生画戟，醉舞尘生罗袜。", "山面高堂，溪浮新舰，留取邦人说。", "等闲馀事，一时如此奇绝。"]'),
('song-ci-89','菩萨蛮','韩淲','宋','宋词','song-ci','菩萨蛮','[]','陇头无驿奚为朵。',52,'宋词/ci.song.13000.json','["陇头无驿奚为朵。", "岩前有折宜来堕。", "风急雪云溪。", "诗清满意携。", "竹炉良夜饮。", "饮竟煎僧茗。", "梅以句深长。", "得花情未忘。"]'),
('song-ci-90','小重山','韩淲','宋','宋词','song-ci','小重山','[]','点染烟浓柳色新。',70,'宋词/ci.song.13000.json','["点染烟浓柳色新。", "小桃红映水，日初匀。", "露收芳径草铺茵。", "凝情久，风淡起轻尘。", "梁燕已争春。", "折花闲伴酒，试濡唇。", "流莺何处语声频。", "阑干曲，蜂蝶更随人。"]'),
('song-ci-91','感皇恩','韩淲','宋','宋词','song-ci','感皇恩','[]','急管度青枝，醉眠芳草。',81,'宋词/ci.song.13000.json','["急管度青枝，醉眠芳草。", "云断巫阳梦能到。", "乍醒馀困，晴影暗移纱帽。", "旧时闲意思，都忘了。", "今岁春迟，去年春早。", "点点繁红又多少。", "惜春归去，酒病翻成花恼。", "数声鸣鸟唤，人惊老。"]'),
('song-ci-92','感皇恩','韩淲','宋','宋词','song-ci','感皇恩','[]','诗社酒徒闲，村村花柳。',81,'宋词/ci.song.13000.json','["诗社酒徒闲，村村花柳。", "月榭风亭更霞牖。", "临春结绮，又是那回时候。", "不禁中夜雨，相孱愁。", "弄蕊攀条，为寻芳酒。", "一斗谁能问千首。", "江南云梦，空说气吞八九。", "持杯人共我，能吟否。"]'),
('song-ci-93','瑞鹧鸪','韩淲','宋','宋词','song-ci','瑞鹧鸪','[]','南兰陵郡鹧鸪词。',64,'宋词/ci.song.13000.json','["南兰陵郡鹧鸪词。", "底用登临更赋诗。", "贵不能淫非一日，老当益壮未多时。", "人间天上风云会，眼底眉前岁月知。", "只有海门横北固，宦情随牒想推移。"]'),
('song-ci-94','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','屋上青山列晚云。',48,'宋词/ci.song.13000.json','["屋上青山列晚云。", "水边红袂映斜曛。", "柳阴荷气簟湘纹。", "酒以歌长谁乐事，诗成杯滟我离群。", "香消凉意有南薰。"]'),
('song-ci-95','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','作意如何和好歌。',48,'宋词/ci.song.13000.json','["作意如何和好歌。", "细翻重看得长哦。", "晓梧吹雨露明荷。", "老我从他琴下爨，故人元自笛亭柯。", "北山烟岫郁嵯峨。"]'),
('song-ci-96','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','鸦矫荒寒燕复低。',48,'宋词/ci.song.13000.json','["鸦矫荒寒燕复低。", "门前长草与人齐。", "长桥南畔小桥西。", "安得有诗同尔句，可教无酒泛其杯。", "相思常苦易离携。"]'),
('song-ci-97','鹧鸪天','韩淲','宋','宋词','song-ci','鹧鸪天','[]','只唱离歌一叠休。',64,'宋词/ci.song.13000.json','["只唱离歌一叠休。", "玉溪浮动木兰舟。", "如何又对云烟晚，不道难禁草树秋。", "空脉脉，忍悠悠。", "绸缪终是转绸缪。", "相思相见知何处，记取新欢说旧游。"]'),
('song-ci-98','满江红','韩淲','宋','宋词','song-ci','满江红','["\u897f\u6e56"]','归锦堂成，云汉上、天垂新画。',112,'宋词/ci.song.13000.json','["归锦堂成，云汉上、天垂新画。", "有朱颜绿鬓，禁林仙客。", "玉局暂从香火社，金龟未报文章力。", "看彤庭、赐第别承恩，居君侧。", "斑衣戏，蟠桃摘。", "翠袖倚，歌檀拍。", "正祥开初度，颂声千百。", "又是腊前梅态度，几多春近花消息。", "想明年、今日醉西湖，光辉赫。"]'),
('song-ci-99','好事近','韩淲','宋','宋词','song-ci','好事近','[]','一涧水南山，腊尽春生梅雪。',53,'宋词/ci.song.13000.json','["一涧水南山，腊尽春生梅雪。", "行过小桥深处，带疏钟横月。", "征衫闲著指东吴，休怕与人别。", "吟到翠圆枝上，是归来时节。"]'),
('song-ci-100','菩萨蛮','韩淲','宋','宋词','song-ci','菩萨蛮','[]','南枝已见春消息。',52,'宋词/ci.song.13000.json','["南枝已见春消息。", "今年为寿方知得。", "俾尔炽而昌。", "流霞浮暗香。", "蓬壶清浅水。", "笑指云阶喜。", "高论不规模。", "平戎赋两都。"]'),
('song-ci-101','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','风软湖光远荡磨。',48,'宋词/ci.song.13000.json','["风软湖光远荡磨。", "春衫初试薄香罗。", "踏青无计奈君何。", "莫笑老来多岁月，肯教闲去少诗歌。", "长安陌上有铜驼。"]'),
('song-ci-102','谒金门','韩淲','宋','宋词','song-ci','谒金门','[]','春尚早。',53,'宋词/ci.song.13000.json','["春尚早。", "春入湖山渐好。", "人去人来虽未老。", "酒徒犹恨少。", "梅落桃开烟岛。", "日日更吹香草。", "一片芳心拚醉倒。", "冷云藏落照。"]'),
('song-ci-103','祝英台近','韩淲','宋','宋词','song-ci','祝英台近','[]','馆娃宫，采香径，范蠡五湖侧。',95,'宋词/ci.song.13000.json','["馆娃宫，采香径，范蠡五湖侧。", "子夜吴歌，声缓不须拍。", "崇桃积李花闲，芳洲绿遍，更冉冉、柳丝无力。", "试思忆。", "老去一片身心，孤负好春色。", "古往今来，时序恼行客。", "去年今日山中，如何知得。", "却又在、他乡寒食。"]'),
('song-ci-104','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','梅叶阴阴占晚春。',48,'宋词/ci.song.13000.json','["梅叶阴阴占晚春。", "博山香尽玉嶙峋。", "茶瓯酒碗试濡唇。", "闲里常愁无伴侣，老来不是有情人。", "牡丹天气惜芳辰。"]'),
('song-ci-105','洞仙歌','韩淲','宋','宋词','song-ci','洞仙歌','[]','溪山好处，赢得题新曲。',101,'宋词/ci.song.13000.json','["溪山好处，赢得题新曲。", "待足人生甚时足。", "问临流情味，倚遍斜晖，应似画、小景生绡一幅。", "渔舟声欸乃，岩上云飞，杳杳归鸦去鸿逐。", "任当年伊吕，谈笑兴王，争敌恁、闲眠野宿。", "待雪天、月夜我还来，醉潇洒清幽，那些儿屋。"]'),
('song-ci-106','点绛唇','韩淲','宋','宋词','song-ci','点绛唇','[]','山凹春生，探梅只道今年早。',50,'宋词/ci.song.13000.json','["山凹春生，探梅只道今年早。", "暗香迎晓。", "人与花能好。", "岁岁持杯，天地同难老。", "须吟啸。", "放开怀抱。", "更约寻瑶草。"]'),
('song-ci-107','减字木兰花','韩淲','宋','宋词','song-ci','减字木兰花','[]','菊花开了。',52,'宋词/ci.song.13000.json','["菊花开了。", "待得梅梢来索笑。", "雪色江波。", "看尽千林未觉多。", "一丘缓步。", "只恐朝来有新句。", "岁岁年年。", "白发催人到酒边。"]'),
('song-ci-108','采桑子','韩淲','宋','宋词','song-ci','采桑子','[]','萧萧两鬓吹华发，老眼全昏。',52,'宋词/ci.song.13000.json','["萧萧两鬓吹华发，老眼全昏。", "徒倚衡门。", "岁晚寒消涧水痕。", "含情更觉沧洲远，欲语谁论。", "窈窕孤村。", "细雨梅花只断魂。"]'),
('song-ci-109','采桑子','韩淲','宋','宋词','song-ci','采桑子','[]','华灯自是年年好，月淡烟空。',52,'宋词/ci.song.13000.json','["华灯自是年年好，月淡烟空。", "依旧东风。", "箫鼓吹香醉脸融。", "谢他诗侣还相觅，雨迹云踪。", "不分情浓。", "柳浅梅深鬓影松。"]'),
('song-ci-110','好事近','韩淲','宋','宋词','song-ci','好事近','[]','北客过江来，赢得家家都老。',53,'宋词/ci.song.13000.json','["北客过江来，赢得家家都老。", "屈指中兴人物，到如今谁好。", "散庵常是爱山林，健笔胜挥扫。", "我则临风三叹。", "信儿曹惊倒。"]'),
('song-ci-111','减字木兰花','韩淲','宋','宋词','song-ci','减字木兰花','[]','一杯易足。',52,'宋词/ci.song.13000.json','["一杯易足。", "自断此生犹杜曲。", "词客哀时，不敢愁来赋别离。", "孤城麦秀。", "常愧葛洪丹未就。", "诗罢长吟。", "衰晚迟回违寸心。"]'),
('song-ci-112','鹧鸪天','韩淲','宋','宋词','song-ci','鹧鸪天','[]','便把山林寄此身。',64,'宋词/ci.song.13000.json','["便把山林寄此身。", "也须诗酒属吾人。", "仙家旧是金堂士，吏隐新收玉局名。", "惟自乐，不忧贫。", "渊明谈笑更清真。", "年年眉寿登高后，醉帽常留菊满簪。"]'),
('song-ci-113','好事近','韩淲','宋','宋词','song-ci','好事近','[]','腊雪映江梅，冰玉更分风月。',53,'宋词/ci.song.13000.json','["腊雪映江梅，冰玉更分风月。", "衮衮紫枢家世，庆诞弥时节。", "烘堂赢得戏莱衣，春酒宝杯凸。", "籍籍郑庄人物，要汉廷勋业。"]'),
('song-ci-114','太常引','韩淲','宋','宋词','song-ci','太常引','[]','随风和雨带烟开。',62,'宋词/ci.song.13000.json','["随风和雨带烟开。", "更清冷、照崔巍。", "片片亦佳哉。", "细看得、花如翦裁。", "茅檐出没，水浮桥外，人自两峰来。", "吟到涧泉梅。", "问何似、山阴道回。"]'),
('song-ci-115','西江月','韩淲','宋','宋词','song-ci','西江月','[]','脉脉蜂黄蝶粉，盈盈水秀山明。',58,'宋词/ci.song.13000.json','["脉脉蜂黄蝶粉，盈盈水秀山明。", "卖花声里听吹饧。", "佳丽芳华韵胜。", "下上休看舞燕，惺忪一任啼莺。", "枕痕屏曲梦关情。", "酒醒春宵漏尽。"]'),
('song-ci-116','谒金门','韩淲','宋','宋词','song-ci','谒金门','[]','行又住。',53,'宋词/ci.song.13000.json','["行又住。", "水远山遥村路。", "把酒问春春几许。", "老年花似雾。", "坐上风流张绪。", "留我我还难去。", "却忆章台飞柳絮。", "只愁萦暮雨。"]'),
('song-ci-117','绕池游慢','韩淲','宋','宋词','song-ci','绕池游慢','["\u897f\u6e56"]','菏花好处，是红酣落照，翠蔼馀凉。',128,'宋词/ci.song.13000.json','["菏花好处，是红酣落照，翠蔼馀凉。", "绕郭从前无此乐，空浮动、山影林篁。", "几度薰风晚，留望眼、立尽濠梁。", "谁知好事，初移画舫，特地相将。", "惊起双飞属玉，萦小楫冲岸，犹带生香。", "莫问西湖西畔□，□九里、松下侯王。", "且举觞寄兴，看闲人、来伴吟章。", "寸折柏枝，蓬分莲实，徒系柔肠。"]'),
('song-ci-118','水调歌头','李廷忠','宋','宋词','song-ci','水调歌头','[]','抚景几今古，遗恨此江山。',114,'宋词/ci.song.13000.json','["抚景几今古，遗恨此江山。", "百年形胜，但见幽草杂枯菅。", "多少名流登览，赖有神扶坏栋，诗墨尚斑斑。", "风月要磨洗，顾我已衰颜。", "擎天手，携玉斧，到江干。", "一新奇观，领客觞咏有馀闲。", "烟草半川开霁，城郭两州相望，都在画屏间。", "便拟骑黄鹄，直上扣云关。"]'),
('song-ci-119','满江红','李廷忠','宋','宋词','song-ci','满江红','[]','玉帐西来，道前是、绣衣使者。',115,'宋词/ci.song.13000.json','["玉帐西来，道前是、绣衣使者。", "游览处、秋风鼓吹，自天而下。", "湘水得霜清可鉴，巫峰过雨森如画。", "有神仙、佳致在胸襟，真潇洒。", "荆州宝，元无价。", "夔门政，长多暇。", "听谈兵樽俎，百川倾泻。", "此日寿觞容我劝，他年枢柄还公把。", "趁桂花、时节去朝天，香随马。"]'),
('song-ci-120','鹧鸪天','李廷忠','宋','宋词','song-ci','鹧鸪天','["\u957f\u6c5f"]','槛外长江浪拍空。',64,'宋词/ci.song.13000.json','["槛外长江浪拍空。", "萧萧红蓼白苹风。", "三秋告稔三农庆，九日追欢九客同。", "烟渚北，月岩东。", "莫嫌光景太匆匆。", "登龙戏马英雄事，都在南楼一啸中。"]'),
('song-ci-121','踏莎行','李廷忠','宋','宋词','song-ci','踏莎行','[]','星野涵辉，云峰环翠。',68,'宋词/ci.song.13000.json','["星野涵辉，云峰环翠。", "南园迎腊开梅蕊。", "瑶台仙子笑相逢，金钗行里拼沈醉。", "照乘骊珠，出闲天骥。", "相随寿母多年纪。", "春风侍宴宝花楼，五枝七叶都荣贵。"]'),
('song-ci-122','贺新凉・贺新郎','李廷忠','宋','宋词','song-ci','贺新凉・贺新郎','[]','濯锦江头路。',140,'宋词/ci.song.13000.json','["濯锦江头路。", "望祥云、密拥旌幢，初开天府。", "冰露壶中秋玉莹，不著人间烦暑。", "现物表、神仙风度。", "回首太清宫阙杳，是鸣珂簪笔遨游处。", "舟万斛，却西诉。", "筹边堂上兵无数。", "笑当年、蜀山谅将，夜分旗鼓。", "听取今朝宣阃令，洗尽蛮烟塞雾。", "便催唤、衮衣归去。", "运应河清逢岳诞，办中兴事业须申甫。", "看岁岁，寿觞举。"]'),
('song-ci-123','霜天晓角','李廷忠','宋','宋词','song-ci','霜天晓角','[]','洞天仙伯。',53,'宋词/ci.song.13000.json','["洞天仙伯。", "总是梅标格。", "来索东风一笑，香浮动、潜溪月。", "寿尊谁共酌。", "少年花县客。", "试问日边春信，梁园上、正飞雪。"]'),
('song-ci-124','感皇恩','李廷忠','宋','宋词','song-ci','感皇恩','[]','昨夜一星明，太微西畔。',81,'宋词/ci.song.13000.json','["昨夜一星明，太微西畔。", "应得良朝诞名将。", "豹韬龙节，谈笑坐清江汉。", "年年梅雪里、开华宴。", "铁券高勋，金锺洪算。", "要同宗社流芳远。", "玺书褒异，自得君王深眷。", "看看登剑履、明光殿。"]'),
('song-ci-125','临江仙','李廷忠','宋','宋词','song-ci','临江仙','[]','人物风流真罕见，何须尘外求仙。',70,'宋词/ci.song.13000.json','["人物风流真罕见，何须尘外求仙。", "绿龟千岁稳巢莲。", "醉倾金凿落，笑拥玉и娟。", "须信日边消息好，寒花也作春妍。", "笙歌乐地酒中天。", "功名无限事，都在寿觞前。"]'),
('song-ci-126','临江仙','李廷忠','宋','宋词','song-ci','临江仙','[]','秋到三山呈瑞气，斑斑绣虎文章。',70,'宋词/ci.song.13000.json','["秋到三山呈瑞气，斑斑绣虎文章。", "早分桂殿一枝香。", "婉谋参幕府，华署等朝行。", "驾月姮娥来献寿，胜如昨夜辉光。", "十分满劝紫霞觞。", "年年花萼宴，相约侍君王。"]'),
('song-ci-127','庆清朝','李廷忠','宋','宋词','song-ci','庆清朝','[]','天启重光，地锺上瑞，有人起自东山。',117,'宋词/ci.song.13000.json','["天启重光，地锺上瑞，有人起自东山。", "当年谢傅，几曾鹤发貂冠。", "不似文章隽老，重来鸣步斗枢间。", "洪钧转，五原草绿，太白兵闲。", "运庆今朝初度，正日添纹线，月挂冰盘。", "恩重御壶宣劝，喜溢天颜。", "听取沙堤好语，金科红篆押千官。", "春长在，调元鼎里，不假还丹。"]'),
('song-ci-128','卜算子','李廷忠','宋','宋词','song-ci','卜算子','[]','草际雪痕消，梅上春心动。',52,'宋词/ci.song.13000.json','["草际雪痕消，梅上春心动。", "碧幕红裙簇画筵，横玉声三弄。", "雅兴杂鱼龙，妙舞回鸾凤。", "莫道司空眼惯□，还入清宵梦。"]'),
('song-ci-129','百字令・念奴娇','胡惠斋','宋','宋词','song-ci','百字令・念奴娇','[]','小斋幽僻，久无人到此，满地狼藉。',121,'宋词/ci.song.13000.json','["小斋幽僻，久无人到此，满地狼藉。", "几案尘生多少憾，把玉指亲传踪迹。", "画出南枝，正开侧面，花蕊俱端的。", "可怜风韵，故人难寄消息。", "非共雪月交光，这般造化，岂费东君力。", "只欠清香来扑鼻，亦有天然标格。", "不上寒窗，不随流水，应不钿宫额。", "不愁三弄，祗愁罗袖轻拂。"]'),
('song-ci-130','满江红','胡惠斋','宋','宋词','song-ci','满江红','[]','暝霭黄昏，灯檠上、荧荧初炙。',115,'宋词/ci.song.13000.json','["暝霭黄昏，灯檠上、荧荧初炙。", "银焰袅、孤光分夜，寸心凝碧。", "留照娇颜欢笑偶，上元庆赏嬉游夕。", "笑聚萤、积雪与偷光，寒儒忆。", "蝶眷恋，成何得。", "花传喜，知何日。", "听邻家昨夜，扣阍谁觅。", "焰短始知新月上，摇红孤馆因风急。", "恨那人、别后不成眠，时时剔。"]'),
('song-ci-131','卜算子','谢直','宋','宋词','song-ci','卜算子','[]','双桨浪花平，夹岸青山锁。',52,'宋词/ci.song.13000.json','["双桨浪花平，夹岸青山锁。", "你自归家我自归，说着如何过。", "我断不思量，你莫思量我。", "将你从前与我心，付与他人可。"]'),
('song-ci-132','金人捧露盘','高似孙','宋','宋词','song-ci','金人捧露盘','[]','下明光，违宣曲，上扬州。',101,'宋词/ci.song.13000.json','["下明光，违宣曲，上扬州。", "玉帐暖、十万貔貅。", "梅花照雪，月随歌吹到江头。", "牙樯锦缆，听雁声、夜宿瓜州。", "南山客，东山妓，蒲萄酒，鹔鹴裘。", "占何逊、杜牧风流。", "琼花红叶，做珠帘、十里遨头。", "竹西歌吹，理新曲、人在春楼。"]'),
('song-ci-133','眼儿媚','高似孙','宋','宋词','song-ci','眼儿媚','[]','翠帘低护郁金堂。',58,'宋词/ci.song.13000.json','["翠帘低护郁金堂。", "犹自未忺妆。", "梨花新月，杏花新雨，怎奈昏黄。", "春今不管人相忆，欲去又相将。", "只销相约，与春同去，须到君行。"]'),
('song-ci-134','莺啼序','高似孙','宋','宋词','song-ci','莺啼序','[]','青旗报春来了，玉鳞鳞风旎。',294,'宋词/ci.song.13000.json','["青旗报春来了，玉鳞鳞风旎。", "陈瑶席、新奏琳琅，窈窕来荐嘉社。", "桂酒洗琼芳，丽景晖晖，日夜催红紫。", "湛青阳新沐，人声澹荡花里。", "光泛崇兰，坼遍桃李，把深心料理。", "共携手、蘅室兰房，奈何新恨如此。", "对佳时、芳情脉脉，眉黛蹙、羞搴琼珥。", "折微馨、聊寄相思，莫愁如水。", "青苹再转，淑思菲菲，春又过半矣。", "细雨湿香尘，未晓又止。", "莫教一鴂无聊，群芳亹亹。", "伤情漠漠，泪痕轻洗。", "曲琼桂帐流苏暖，望美人、又是论千里。", "佳期杳渺，香风不肯为媒，可堪玩此芳芷。", "春今渐歇，不忍零花，犹恋馀绮。", "度美曲、造新声，乐莫乐此新知。", "思美人兮，有花同倚。", "年华做了，功成如委。", "天时相代何日已。", "怅春功、非与他时比。", "殷勤举酒酬春，春若能留，□还亦喜。"]'),
('song-ci-135','失调名','高似孙','宋','宋词','song-ci','失调名','[]','红翻茧栗梢头遍。',8,'宋词/ci.song.13000.json','["红翻茧栗梢头遍。"]'),
('song-ci-136','蓦山溪','易祓','宋','宋词','song-ci','蓦山溪','[]','海棠枝上，留得娇莺语。',102,'宋词/ci.song.13000.json','["海棠枝上，留得娇莺语。", "双燕几时来，并飞入、东风院宇。", "梦回芳草，绿遍旧池塘，梨花雪，桃花雨。", "毕竟春谁主。", "东郊拾翠，襟袖沾飞絮。", "宝马趁雕轮，乱红中、香尘满路。", "十千斗酒，相与买春闲，吴姬唱，秦娥舞。", "拼醉青楼暮。"]'),
('song-ci-137','喜迁莺','易祓','宋','宋词','song-ci','喜迁莺','[]','帝城春昼。',126,'宋词/ci.song.13000.json','["帝城春昼。", "见杏脸桃腮，胭脂微透。", "一霎儿晴，一霎儿雨，正是催花时候。", "淡烟细柳如画，雅称踏青携手。", "怎知道、那人人，独倚阑干消瘦。", "别后。", "音信断，应是泪珠，滴遍香罗袖。", "记得年时，胆瓶儿畔，曾把牡丹同嗅。", "故乡水遥山远，怎得新欢如旧。", "强消遣，把闲愁推入，花前杯酒。"]'),
('song-ci-138','水调歌头','易祓','宋','宋词','song-ci','水调歌头','[]','自古清胜地，江带与山篸。',113,'宋词/ci.song.13000.json','["自古清胜地，江带与山篸。", "夸娥擘此石鐪，不独岭之南。", "初见仙岩第一，再见砻岩第二，今见淡岩三。", "邱壑皆有分，品第不须谈。", "望前驱，陪后乘，破晴岚。", "出城一舍而近，峭壁与天参。", "不使尘埃涴脚，忽觉烟云对面，鹤驭可同骖。", "杖屦从归去，此乐湘潭。"]'),
('song-ci-139','一翦梅','易祓妻','宋','宋词','song-ci','一翦梅','[]','染泪修书寄彦章。',72,'宋词/ci.song.13000.json','["染泪修书寄彦章。", "贪做前廊。", "忘却回廊。", "功名成就不还乡。", "铁做心肠。", "石做心肠。", "红日三竿懒画妆。", "虚度韶光。", "瘦损容光。", "不知何日得成双。", "羞对鸳鸯。", "懒对鸳鸯。"]'),
('song-ci-140','水调歌头','章斯才','宋','宋词','song-ci','水调歌头','[]','帝念重湖远，使者选清强。',113,'宋词/ci.song.13000.json','["帝念重湖远，使者选清强。", "关西夫子人杰，搅辔出鸳行。", "熊楚一天坐镇，虎节三台更历，号令肃秋霜。", "褰帷间风俗，原隰总生光。", "瞻南极，朝北斗，酌霞觞。", "潢池息浪奏凯，筹饷属萧张。", "一点眉间多，一札日边有诏，香案侍东皇。", "岁岁蓬壶宴，好景对枨黄。"]'),
('song-ci-141','水调歌头','章斯才','宋','宋词','song-ci','水调歌头','[]','秋老楚天阔，光粲极南星。',114,'宋词/ci.song.13000.json','["秋老楚天阔，光粲极南星。", "郁葱瑞霭浮动，湘水舞湘灵。", "方启流虹华旦，恰值绂麟弥月，嘉会庆千龄。", "维岳绛神处，玉印注长生。", "衣衮绣，袍练鹊，纽双萦。", "民气和乐，雁到回地作欢声。", "楚观连天境界，四景撩人风物，身世自蓬瀛。", "剩酌金貂醁，飞诏到临蒸。"]'),
('song-ci-142','水龙吟','危稹','宋','宋词','song-ci','水龙吟','[]','洛阳九老图中，当时司马年犹小。',126,'宋词/ci.song.13000.json','["洛阳九老图中，当时司马年犹小。", "争如今夕，举杯相劝，十人齐寿。", "已幸同庚，何分雌甲，本无多少。", "但有头可白，无愁可解，只如此、都赢了。", "庆礼十年还又，更十年、依前难老。", "尽教百岁，做人高祖，见孙白首。", "却要从今，探梅脚健，看山眼好。", "赖天公，顿得东园长在，陪歌陪酒。"]'),
('song-ci-143','渔家傲','危稹','宋','宋词','song-ci','渔家傲','[]','老去诸馀情味浅。',72,'宋词/ci.song.13000.json','["老去诸馀情味浅。", "诗词不上闲钗钏。", "宝幌有人红两靥。", "帘间见。", "紫云元在梨花院。", "十四条弦音调远。", "柳丝不隔芙蓉面。", "秋入西窗风露晚。", "归去懒。", "酒酣一任乌巾岸。"]'),
('song-ci-144','沁园春','危稹','宋','宋词','song-ci','沁园春','[]','籍甚声名，门阑相种，文章世科。',139,'宋词/ci.song.13000.json','["籍甚声名，门阑相种，文章世科。", "算当年瑞世，正当夏五，仙家毓德，全是春和。", "底事屏星，著之海峤，奈此腾骧骥足何。", "君知否，看飞来丹诏，径上鸾坡。", "殷勤携酒相过。", "要滟滟浮君金叵罗。", "叹同心相契，古来难觅，二年同处，意总无它。", "如此平分，更教添个，也自清风明月多。", "拼沈醉，任光浮绿鬓，笑满红涡。"]'),
('song-ci-145','满江红','王居安','宋','宋词','song-ci','满江红','[]','八十归来，方岩下、几竿修竹。',115,'宋词/ci.song.13000.json','["八十归来，方岩下、几竿修竹。", "柴门外，沙铺软路，水流清玉。", "栽接新来桃与李，安排旧日松和菊。", "过小桥、作个看山楼，千峰绿。", "收笔砚，藏棋局。", "酒莫饮，经须读。", "但平平放下，顿超凡俗。", "独睡已无年少梦，闲吟不唱他家曲。", "算人生、万事苦无多，相将足。"]'),
('song-ci-146','沁园春','王居安','宋','宋词','song-ci','沁园春','[]','湖海襟期，烟霞气宇，天下星郎。',139,'宋词/ci.song.13000.json','["湖海襟期，烟霞气宇，天下星郎。", "有灵方时后，年年却老，神锋耳底，夜夜腾光。", "万卷蟠胸，千锺蘸甲，衮衮词源三峡滂。", "功成处，见须弥日月，河岳星霜。", "兴来引笔千行。", "看举世何人是智囊。", "任纵横万变，难瞒道眼，优游自乐，不识愁肠。", "闹市丛中，密林静处，鼻观常闻三界香。", "天书到，听笙箫竞奏，幢盖班行。"]'),
('song-ci-147','朝中措','王克勤','宋','宋词','song-ci','朝中措','[]','银河无际渺澄空。',57,'宋词/ci.song.13000.json','["银河无际渺澄空。", "一点寿光中。", "此夕谪仙初度，清歌吉甫清风。", "文章间世，曾亲玉座，屡赐金锺。", "丹禁若须鳌便，赤城唤取渔翁。"]'),
('song-ci-148','浣溪沙','锺将之','宋','宋词','song-ci','浣溪沙','[]','鬓亸云梳月带痕。',48,'宋词/ci.song.13000.json','["鬓亸云梳月带痕。", "软红香里步莲轻。", "妖娆六幅过腰裙。", "不怕满堂佳客醉，只愁灭烛翠眉颦。", "更期疏影月黄昏。"]'),
('song-ci-149','浣溪沙','锺将之','宋','宋词','song-ci','浣溪沙','[]','苹老秋深水落痕。',48,'宋词/ci.song.13000.json','["苹老秋深水落痕。", "桂花微弄雨花轻。", "癯仙也解醉红裙。", "太白麴君愁满饮，小鸿眉黛爱低颦。", "尊前一洗眼花昏。"]'),
('song-ci-150','水调歌头','锺将之','宋','宋词','song-ci','水调歌头','[]','更似南津港，再遇吕公船。',12,'宋词/ci.song.13000.json','["更似南津港，再遇吕公船。"]'),
('song-ci-151','浣溪沙','吴礼之','宋','宋词','song-ci','浣溪沙','[]','南国风流是故乡。',48,'宋词/ci.song.13000.json','["南国风流是故乡。", "红盐落子不因霜。", "于中小底最珍藏。", "荐酒荐茶些子涩，透心透顶十分香。", "可人回味越思量。"]'),
('song-ci-152','喜迁莺','吴礼之','宋','宋词','song-ci','喜迁莺','[]','银蟾光彩。',126,'宋词/ci.song.13000.json','["银蟾光彩。", "喜稔岁闰正，元宵还再。", "乐事难并，佳时罕遇，依旧试灯何碍。", "花市又移星汉，莲炬重芳人海。", "尽勾引，遍嬉游宝马，香车喧隘。", "晴快。", "天意教、人月更圆，偿足风流债。", "媚柳烟浓，夭桃红小，景物迥然堪爱。", "巷陌笑声不断，襟袖馀香仍在。", "待归也，便相期明日，踏青挑菜。"]'),
('song-ci-153','丑奴儿・采桑子','吴礼之','宋','宋词','song-ci','丑奴儿・采桑子','[]','金风颤叶，那更饯别江楼。',110,'宋词/ci.song.13000.json','["金风颤叶，那更饯别江楼。", "听凄切、阳关声断，楚馆云收。", "去也难留。", "万重烟水一扁舟。", "锦屏罗幌，多应换得，蓼岸苹洲。", "凝想恁时欢笑，伤今萍梗悠悠。", "谩回首、妖娆何处，眷恋无由。", "先自悲秋。", "眼前景物只供愁。", "寂寥情绪，也恨分浅，也悔风流。"]'),
('song-ci-154','杏花天','吴礼之','宋','宋词','song-ci','杏花天','[]','闷来凭得阑干暖。',65,'宋词/ci.song.13000.json','["闷来凭得阑干暖。", "自手引、朱帘高卷。", "桃花半露胭脂面。", "芳草如茵乍展。", "烟光散、湖光潋滟。", "映绿柳、黄鹂巧啭。", "遥山好似宫眉浅。", "人比遥山更远。"]'),
('song-ci-155','雨中花・夜行船','吴礼之','宋','宋词','song-ci','雨中花・夜行船','[]','眷浓恩重，长离永别，凭谁为返香魂。',118,'宋词/ci.song.13000.json','["眷浓恩重，长离永别，凭谁为返香魂。", "忆湘裙霞袖，杏脸樱唇。", "眉扫春山淡淡，眼裁秋水盈盈。", "便如何忘得，温柔情态，恬静天真。", "凭栏念及，夕阳西下，暮烟四起江村。", "渐入夜、疏星映柳，新月笼云。", "酝造一生清瘦，能消几个黄昏。", "断肠时候，帘垂深院，人掩重门。"]'),
('song-ci-156','瑞鹤仙','吴礼之','宋','宋词','song-ci','瑞鹤仙','[]','风传秋信至。',127,'宋词/ci.song.13000.json','["风传秋信至。", "颤叶叶庭梧，飘零阶砌。", "年华迅流水。", "况荣枯翻手，存亡弹指。", "谁编故纸。", "论古往、英雄斗智。", "在当时、唤做功名，到此尽成闲气。", "何谓。", "生为行客，死乃归人，世同驿邸。", "十步九计。", "空捞攘，谩儿戏。", "忍都将、有限光阴萦绊，趁逐无穷天地。", "我直须、跳出樊笼，做个俏底。"]'),
('song-ci-157','蓦山溪','吴礼之','宋','宋词','song-ci','蓦山溪','[]','刘郎老矣，倦入繁华地。',102,'宋词/ci.song.13000.json','["刘郎老矣，倦入繁华地。", "触目愈伤情，念陈迹、人非物是。", "共谁携手，落日步江村，临远水，对遥山，闲看烟云起。", "买牛卖剑，便作儿孙计。", "朋旧自荣华，也怜我、无名无利。", "箪瓢锺鼎，等是百年身，空妄作，枉迂回，贪爱从今止。"]'),
('song-ci-158','风入松','吴礼之','宋','宋词','song-ci','风入松','[]','苹汀蓼岸荻花洲。',88,'宋词/ci.song.13000.json','["苹汀蓼岸荻花洲。", "占断清秋。", "五湖景物供心眼，几曾有、一点闲愁。", "梦里翩翩胡蝶，觉来叶叶渔舟。", "谢郎随分总优游。", "信任沈浮。", "恬然云水无贪吝，笑腰缠、骑鹤扬州。", "只恐丹青妙笔，写传难尽风流。"]'),
('song-ci-159','渔家傲','吴礼之','宋','宋词','song-ci','渔家傲','[]','红日三竿莺百啭。',72,'宋词/ci.song.13000.json','["红日三竿莺百啭。", "梦回鸳枕离魂乱。", "料得玉人肠已断。", "眉峰敛。", "晓妆镜里春愁满。", "绿琐窗深难见面。", "云笺谩写教谁传。", "闻道笙歌归小院。", "梁尘颤。", "多因唱我新词劝。"]'),
('song-ci-160','蝶恋花','吴礼之','宋','宋词','song-ci','蝶恋花','[]','睡思厌厌莺唤起。',70,'宋词/ci.song.13000.json','["睡思厌厌莺唤起。", "帘卷东风，犹未忺梳洗。", "眼细眉长云拥髻。", "笑垂罗袖熏沈水。", "媚态盈盈闲举止。", "只有江梅，清韵能相比。", "诗酒琴棋歌舞地。", "又还同醉春风里。"]'),
('song-ci-161','蝶恋花','吴礼之','宋','宋词','song-ci','蝶恋花','[]','急水浮萍风里絮。',70,'宋词/ci.song.13000.json','["急水浮萍风里絮。", "恰似人情，恩爱无凭据。", "去便不来来便去。", "到头毕竟成轻负。", "帘卷春山朝又暮。", "莺燕空忙，不念花无主。", "心事万千谁与诉。", "断云零雨知何处。"]'),
('song-ci-162','蝶恋花','吴礼之','宋','宋词','song-ci','蝶恋花','[]','满地落红初过雨。',70,'宋词/ci.song.13000.json','["满地落红初过雨。", "绿树成阴，紫燕风前舞。", "烟草低迷萦小路。", "昼长人静扃朱户。", "沈水香销新剪苎。", "敧枕朦胧，花底闻莺语。", "春梦又还随柳絮。", "等闲飞过东墙去。"]'),
('song-ci-163','桃源忆故人','吴礼之','宋','宋词','song-ci','桃源忆故人','[]','画桥流水飞花舞。',56,'宋词/ci.song.13000.json','["画桥流水飞花舞。", "柳外斜风细雨。", "红瘦绿肥春暮。", "肠断桃源路。", "欢随仙子乘鸾去。", "镂月裁云何处。", "唯有病和愁绪。", "肯伴刘郎住。"]'),
('song-ci-164','谒金门','吴礼之','宋','宋词','song-ci','谒金门','[]','风乍扇。',53,'宋词/ci.song.13000.json','["风乍扇。", "帘外落红千片。", "飞尽落花春不管。", "斗忙莺与燕。", "往事上心撩乱。", "睡起日高犹倦。", "料得伊家情眷眷。", "近来长梦见。"]'),
('song-ci-165','霜天晓角','吴礼之','宋','宋词','song-ci','霜天晓角','[]','连环易缺。',54,'宋词/ci.song.13000.json','["连环易缺。", "难解同心结。", "痴呆佳人才子，情缘重、怕离别。", "意切。", "人路绝。", "共沈烟水阔。", "荡漾香魂何处，长桥月。", "断桥月。"]'),
('song-ci-166','霜天晓角','吴礼之','宋','宋词','song-ci','霜天晓角','[]','西风又急。',54,'宋词/ci.song.13000.json','["西风又急。", "细雨黄花湿。", "楼枕一篙烟水，兰舟漾、画桥侧。", "念昔。", "空泪滴。", "故人何处觅。", "魂断菱歌凄怨，疏帘卷、暮山碧。"]'),
('song-ci-167','生查子','吴礼之','宋','宋词','song-ci','生查子','[]','吴山与越山，相对摩今古。',48,'宋词/ci.song.13000.json','["吴山与越山，相对摩今古。", "袅缆浙江亭，回首西兴渡。", "区区名利人，无分香闺住。", "匆遽促征鞍，又入临平路。"]'),
('song-ci-168','失调名','吴礼之','宋','宋词','song-ci','失调名','[]','我不成、心酸眼软。',9,'宋词/ci.song.13000.json','["我不成、心酸眼软。"]'),
('song-ci-169','好事近','吴礼之','宋','宋词','song-ci','好事近','[]','金菊间芙蓉，秋意未为萧索。',53,'宋词/ci.song.13000.json','["金菊间芙蓉，秋意未为萧索。", "临水见山庭院。", "伴玉人杯酌。", "携炉终日袅沈烟，氤氲篆文□。", "可惜被风吹散，把袖儿笼著。"]'),
('song-ci-170','柳梢青','吴礼之','宋','宋词','song-ci','柳梢青','[]','板约红牙。',61,'宋词/ci.song.13000.json','["板约红牙。", "歌翻白雪，杯泛流霞。", "苏小情多，潘郎年少，欢计生涯。", "轩窗临水人家。", "更门掩、青春杏花。", "百万呼卢，十千沽酒，不负韶华。"]'),
('song-ci-171','满江红','陈善','宋','宋词','song-ci','满江红','[]','三月风前花薄命，五更枕上春无力。',16,'宋词/ci.song.13000.json','["三月风前花薄命，五更枕上春无力。"]'),
('song-ci-172','满江红','丁黼','宋','宋词','song-ci','满江红','[]','梅腊宾春，瑞烟满、华堂馥郁。',115,'宋词/ci.song.13000.json','["梅腊宾春，瑞烟满、华堂馥郁。", "还又祝、屏垂彩帨，觞称醽醁。", "南浦西山开寿域，朱帘画栋调新曲。", "庆彩衣、龙节侍慈萱，春长绿。", "双鹤发，齐眉福。", "一麟瑞，如冰玉。", "看国封重见，五霞凝轴。", "王母瑶池鸾凤驭，麻姑金鼎神仙箓。", "数从今、椿算到何时，蟠桃熟。"]'),
('song-ci-173','贺新凉・贺新郎','俞国宝','宋','宋词','song-ci','贺新凉・贺新郎','[]','梦里骖鸾鹤。',140,'宋词/ci.song.13000.json','["梦里骖鸾鹤。", "觉三山不远，依前海风吹落。", "浮到五湖烟月上，刚被梅香醉着。", "粲玉树、轻明疏薄。", "十万琼琚天女队，捧冰壶、玉液琉璃杓。", "来伴我，荐清酌。", "恍然梦断浑非昨。", "问溪边竹外，新来为谁开却。", "无限冰魂招不得，拟把离骚唤觉。", "待抖擞、红尘双脚。", "万里瑶台终一到，想玉奴、不负东昏约。", "留此恨，寄残角。"]'),
('song-ci-174','风入松','俞国宝','宋','宋词','song-ci','风入松','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u897f\u6e56"]','一春长费买花钱。',90,'宋词/ci.song.13000.json','["一春长费买花钱。", "日日醉花边。", "玉骢惯识西湖路，骄嘶过、沽酒垆前。", "红杏香中箫鼓，绿杨影里秋千。", "暖风十里丽人天。", "花压髻云偏。", "画船载取春归去，馀情寄、湖水湖烟。", "明日重扶残醉，来寻陌上花钿。"]'),
('song-ci-175','瑞鹤仙','俞国宝','宋','宋词','song-ci','瑞鹤仙','[]','春衫和泪著。',127,'宋词/ci.song.13000.json','["春衫和泪著。", "又燕入江南，雁归衡岳。", "东风晓来恶。", "绕西园无绪，泪随花落。", "愁钟恨角。", "梦无凭、难成易觉。", "到春来易感，韩香顿减，沈腰如削。", "离索。", "挑灯占信，听鹊求音，不禁春弱。", "云轻雨薄。", "阳台远，信难托。", "念盟钗一股，鸾光两破，已负秦楼素约。", "但莫教、嫩绿成阴，把人误却。"]'),
('song-ci-176','清平乐','俞国宝','宋','宋词','song-ci','清平乐','[]','数声乌鹊。',54,'宋词/ci.song.13000.json','["数声乌鹊。", "院宇寒萧索。", "杨柳梢头秋过却。", "无叶可供风落。", "可人犹有芙蕖。", "向人泠澹妆梳。", "云外征鸿过尽，夕阳依旧平芜。"]'),
('song-ci-177','卜算子','俞国宝','宋','宋词','song-ci','卜算子','[]','翦烛写香笺，拨火温寒醑。',52,'宋词/ci.song.13000.json','["翦烛写香笺，拨火温寒醑。", "门外东风将我愁，欲作三更雨。", "夜夜玉楼心，日日长亭路。", "豆蔻花开信不来，尘满金钗股。"]'),
('song-ci-178','风入松','俞国宝','宋','宋词','song-ci','风入松','[]','东风巷陌暮寒骄。',90,'宋词/ci.song.13000.json','["东风巷陌暮寒骄。", "灯火闹河桥。", "胜游忆遍钱塘夜，青鸾远、信断难招。", "蕙草情随雪尽，梨花梦与云销。", "客怀先自病无聊。", "绿酒负金蕉。", "下帏独拥香篝睡，春城外、玉漏声遥。", "可惜满街明月，更无人为吹箫。"]'),
('song-ci-179','水调歌头','徐冲渊','宋','宋词','song-ci','水调歌头','[]','穷达付天命，生死见交情。',114,'宋词/ci.song.13000.json','["穷达付天命，生死见交情。", "人今老矣，□□狗苟与蝇营。", "赢得一头霜雪。", "闲却五湖风月。", "鸥鸟负前盟。", "颜厚已如甲，太息误平生。", "想箕山，怀颍水，挹馀清。", "只今归去，沧浪深处濯吾缨。", "笑抚山中泉石。", "细说人间荆棘。", "有道苦难行。", "好补青萝屋，且占白云耕。"]'),
('song-ci-180','谒金门','李好义','宋','宋词','song-ci','谒金门','[]','花过雨。',53,'宋词/ci.song.13000.json','["花过雨。", "又是一番红素。", "燕子归来衔绣幕。", "旧巢无觅处。", "谁在玉楼歌舞。", "谁在玉关辛苦。", "若使胡尘吹得去。", "东风侯万户。"]'),
('song-ci-181','望江南・忆江南','李好义','宋','宋词','song-ci','望江南・忆江南','[]','思往事，白尽少年头。',64,'宋词/ci.song.13000.json','["思往事，白尽少年头。", "曾帅三军平蜀难，沿边四郡一齐收。", "逆党反封侯。", "元宵夜，灯火闹啾啾。", "厅上一员闲总管，门前几个纸灯球。", "箫鼓胜皇州。"]'),
('song-ci-182','水调歌头','程准','宋','宋词','song-ci','水调歌头','[]','船系钓台下，身寄碧云端。',114,'宋词/ci.song.13000.json','["船系钓台下，身寄碧云端。", "胸中千古风月，笔下助波澜。", "唤起羊裘仙魄，来伴蝉冠清影，星阁倚阑干。", "上想中兴事，名节重於山。", "濯沧浪，开玉鉴，照朱颜。", "平生多少英气，直欲斩楼兰。", "尽道诗书元帅，好作经纶上衮，勋业秉华丹。", "霄汉展鸾翼，雷雨震龙蟠。"]'),
('song-ci-183','秋日田父辞','高翥','宋','宋词','song-ci','秋日田父辞','[]','啄黍黄鸡没骨肥。',32,'宋词/ci.song.13000.json','["啄黍黄鸡没骨肥。", "绕篱绿橘缀枝垂。", "新酿酒，旋裁衣。", "正是昏男嫁女时。"]'),
('song-ci-184','秋日田父辞','高翥','宋','宋词','song-ci','秋日田父辞','[]','少妇挼蓝旋染裙。',32,'宋词/ci.song.13000.json','["少妇挼蓝旋染裙。", "大儿敲葛自浆巾。", "新摘摘，笑欣欣。", "相唤相呼看赛神。"]'),
('song-ci-185','念奴娇','高惟月','宋','宋词','song-ci','念奴娇','[]','岩扃不锁，算空洞深窈，是谁初凿。',120,'宋词/ci.song.13000.json','["岩扃不锁，算空洞深窈，是谁初凿。", "帝遣六丁持月斧，乱把云根镵斫。", "骇目奇观，恍如崩浪，汹涌从天落。", "谪仙何处，翠珉佳句如昨。", "惆怅白首重游，多情还似，与青山有约。", "且对清尊酬胜赏，休想舞衣歌乐。", "景物依然，头颅如许，何事嗟漂泊。", "翩翩归兴，故山无限林壑。"]'),
('song-ci-186','水调歌头','彭叔夏','宋','宋词','song-ci','水调歌头','[]','铜章纡墨绶，茜服佩银鱼。',114,'宋词/ci.song.13000.json','["铜章纡墨绶，茜服佩银鱼。", "慈闱一笑，全胜莱子彩衣裾。", "好事柿红萱草，长伴朱颜绿发，荣贵更谁如。", "轴锦装鸾诰，帘绣窣藤舆。", "龙为炙，麟作脯，倒琼壶。", "寿筵今年，邀请金母伴麻姑。", "缥渺飞琼舞罢，宛转双成歌彻，何物奉亲娱。", "探支长命缕，预借角蟾蜍。"]'),
('song-ci-187','失调名','应','宋','宋词','song-ci','失调名','[]','横斜淡月黄昏，漏泄早春消息。',14,'宋词/ci.song.13000.json','["横斜淡月黄昏，漏泄早春消息。"]'),
('song-ci-188','失调名','吴康','宋','宋词','song-ci','失调名','[]','试问海棠健否，海棠虽似，减清香。',16,'宋词/ci.song.13000.json','["试问海棠健否，海棠虽似，减清香。"]'),
('song-ci-189','失调名','吴康','宋','宋词','song-ci','失调名','[]','凌空蜂翼递香来，惊破蜜房幽梦。',15,'宋词/ci.song.13000.json','["凌空蜂翼递香来，惊破蜜房幽梦。"]'),
('song-ci-190','贺新郎','汪','宋','宋词','song-ci','贺新郎','[]','田舍炉头语。',142,'宋词/ci.song.13000.json','["田舍炉头语。", "便如何学得，三变美成家数。", "村酒三杯狂兴发，拔剑偶然起舞。", "只麽也、迎寒送暑。", "待草万言书上阙，似忧端、倚柱东邻女。", "卿相事，未易许。", "渔歌且和芙蓉渚。", "又何须、淫辞媟语，诃风诋雨。", "劝人生、且随缘分，分外一毫莫取。", "那富贵、由天付与。", "身蹈危机犹不觉，如布衣、自在都无阻。", "空博得，雪千缕。"]'),
('song-ci-191','蝶恋花','汪','宋','宋词','song-ci','蝶恋花','[]','午夜凉生风不住。',70,'宋词/ci.song.13000.json','["午夜凉生风不住。", "河汉无声，时见疏星度。", "佳客伴君知未去。", "对床只欠潇潇雨。", "素月四更山外吐。", "金鸭慵添，消尽沈烟缕。", "料想玉楼人念处。", "归舟日望荷花浦。"]'),
('song-ci-192','念奴娇','汪','宋','宋词','song-ci','念奴娇','["\u897f\u6e56"]','谁家野菜饭炊香，正是江南寒食。',119,'宋词/ci.song.13000.json','["谁家野菜饭炊香，正是江南寒食。", "试问春光今几许，犹有三分之一。", "枝上花稀，柳间莺老，是处春狼藉。", "新来燕子，尚传晋苑消息。", "应记往日西湖，万家罗绮，见满城争出。", "急管繁弦嘈杂处，宝马香车如织。", "猛省狂游，恍如昨梦，何日重寻觅。", "杜鹃声里，桂轮挂上空碧。"]'),
('song-ci-193','水调歌头','汪','宋','宋词','song-ci','水调歌头','[]','落日水亭静，藕叶胜花香。',114,'宋词/ci.song.13000.json','["落日水亭静，藕叶胜花香。", "时贤飞盖，松间喝道挟胡床。", "暑气林深不受，山色晚来逾好，顿觉酒尊凉。", "妙语发天籁，幽眇亦张皇。", "射者中，弈者胜，兴悠长。", "佳人雪藕，更调冰水赛寒浆。", "惊饵游鱼深逝，带箭山禽高举，此话要商量。", "溪上采菱女，三五傍垂杨。"]'),
('song-ci-194','如梦令','汪','宋','宋词','song-ci','如梦令','[]','几点弄晴微雨。',40,'宋词/ci.song.13000.json','["几点弄晴微雨。", "翳日薄云来去。", "断送一番春，满径杨花飞絮。", "无语。", "无语。", "还是旧时院宇。"]'),
('song-ci-195','贺新郎','汪','宋','宋词','song-ci','贺新郎','[]','帖子传新语。',142,'宋词/ci.song.13000.json','["帖子传新语。", "问自来、翰林学士，几多人数。", "或道江心空铸镜，或道艾人如舞。", "或更道、冰盘消暑。", "或道芸香能去蠹，有宫中、斗草盈盈女。", "都不管，道何许。", "离骚古意盈洲渚。", "也莫道、龙舟吊屈，浪花吹雨。", "只有辟兵符子好，少有词人拈取。", "谁肯向、帖中道与。", "绝口用兵两个字，是老臣、忠爱知艰阻。", "写此句，绛纱缕。"]'),
('song-ci-196','贺新郎','汪','宋','宋词','song-ci','贺新郎','[]','夜对灯花语。',142,'宋词/ci.song.13000.json','["夜对灯花语。", "且随宜、果盘草草，两三杯数。", "翠玉环中园五亩，自唱山歌自舞。", "况今夜、尊前无暑。", "何用食前须方丈，更后车、何用婵娟女。", "这闲福，自心许。", "蓼花芦叶纷江渚。", "有沙边、寒蛩吟透，梧桐秋雨。", "羡甚满堂金玉富，未可学人渔取。", "怕天也、未曾相与。", "豹遁蛟藏泉可濯，有鬼神、呵护盘之阻。", "鲜可食，脍银缕。"]'),
('song-ci-197','鹧鸪词・瑞鹧鸪','汪','宋','宋词','song-ci','鹧鸪词・瑞鹧鸪','[]','伤时怀抱不胜愁。',64,'宋词/ci.song.13000.json','["伤时怀抱不胜愁。", "野水粼粼绿遍洲。", "满地落花春病酒，一帘明月夜登楼。", "明眸皓齿人难得，寒食清明事又休。", "只是鹧鸪三两曲，等闲白了几人头。"]'),
('song-ci-198','念奴娇','汪','宋','宋词','song-ci','念奴娇','[]','相逢草草，共吟诗、同醉杯中之物。',120,'宋词/ci.song.13000.json','["相逢草草，共吟诗、同醉杯中之物。", "评论三王讥五霸，谈辩喧哗邻壁。", "敲缺唾壶，击残如意，妙语飞华雪。", "无能为也，如何对此三杰。", "看取东野诗成，南昌书就，奈征车催发。", "后夜山深何处宿，红豆寒灯明灭。", "一老堪怜，两生未起，应念星星发。", "风传佳话，花村无犬惊月。"]'),
('song-ci-199','西江月','汪','宋','宋词','song-ci','西江月','[]','千缕柳丝犹嫩，一星榆火初明。',58,'宋词/ci.song.13000.json','["千缕柳丝犹嫩，一星榆火初明。", "载将新意寿幽人。", "红袖持杯劝尽。", "老鹤自偏野性，沙鸥难比轻身。", "殷勤多谢祝长春。", "一笑东风夜静。"]'),
('song-ci-200','沁园春','汪','宋','宋词','song-ci','沁园春','[]','民吾同胞，剖破藩篱，元是大家。',138,'宋词/ci.song.13000.json','["民吾同胞，剖破藩篱，元是大家。", "故见之诰诏，视如子弟，谆勤恳切，悃愊无华。", "孝悌力田，职当劝相，起早非干为看花。", "亲酌酒，老农唯诺，句句仁芽。", "晓来犹觉寒些。", "看雨湿风吹旗□斜。", "笑吾生八十，尽谙农事，公筵既彻，更共烹茶。", "高唱豳风，敬酬令尹，王道桑麻乐有涯。", "春务急，见溪头杨柳，已可藏鸦。"]'),
('song-ci-201','如梦令','汪','宋','宋词','song-ci','如梦令','[]','一只船儿没赛。',40,'宋词/ci.song.13000.json','["一只船儿没赛。", "七十六年装载。", "把柁更须牢，风饱蒲帆轻快。", "无碍。", "无碍。", "匹似子猷访戴。"]'),
('song-ci-202','江城子','汪','宋','宋词','song-ci','江城子','[]','可是东风、当日欠商量。',27,'宋词/ci.song.13000.json','["可是东风、当日欠商量。", "百紫千红春富贵，无半点，似渠香。"]'),
('song-ci-203','南乡子','虞刚简','宋','宋词','song-ci','南乡子','[]','儿有掌中杯。',66,'宋词/ci.song.13000.json','["儿有掌中杯。", "但把归期苦苦催。", "奕世衣冠仍上第，公台。", "元自诗书里面来。", "秋色为渠开。", "先我梁山马首回。", "猿鹤莫轻窥蕙帐，惊猜。", "抬步归休亦乐哉。"]'),
('song-ci-204','向湖边','张拭','宋','宋词','song-ci','向湖边','[]','万里烟堤，百花风榭，游女翩翩羽盖。',126,'宋词/ci.song.13000.json','["万里烟堤，百花风榭，游女翩翩羽盖。", "彩挂秋千，向花梢娇对。", "矧门外、森立乔松，日花争丽，犹若当年文会。", "廊庙夔龙，暂卜邻交外。", "共讲真率，玉糁金齑脍。", "同萧散寄傲，樽罍倾北海。", "佳处难忘，约追欢须再。", "况风月不用一钱买。", "但回首，七虎堂中心欲碎。", "千里相思，幸前盟犹在。"]'),
('song-ci-205','霜天晓角','赵希明','宋','宋词','song-ci','霜天晓角','[]','空山木落。',53,'宋词/ci.song.13000.json','["空山木落。", "月淡阑干角。", "相与羊裘披上，方知道、宦情薄。", "老来须自觉。", "酒尊行处乐。", "疑到碧湾无路，滩声小、橹声薄。"]'),
('song-ci-206','醉蓬莱','程珌','宋','宋词','song-ci','醉蓬莱','[]','望皇都清晓，瑞日祥烟，洞开阊阖。',120,'宋词/ci.song.13000.json','["望皇都清晓，瑞日祥烟，洞开阊阖。", "一朵红云，映重瞳日月。", "万岁山高，九霞杯暖，正想宸游洽。", "绝塞庭琛，重闱天笑，年年仙阙。", "韶凤徘徊，蒲鱼演漾，镐酒恩浓，龙蟠建业。", "玉琢麟符，分付人中杰。", "奠国安民，持将祝寿，乐作君臣悦。", "看取头厅，押班称贺，明年天节。"]'),
('song-ci-207','西江月','程珌','宋','宋词','song-ci','西江月','[]','岁贡来从玉垒，天恩拜赐金奁。',58,'宋词/ci.song.13000.json','["岁贡来从玉垒，天恩拜赐金奁。", "春风一朵紫云鲜。", "明月轻浮盏面。", "想见清都绛阙，雍容多少神仙。", "归来满袖玉炉烟。", "愿侍年年天宴。"]'),
('song-ci-208','鹧鸪天','程珌','宋','宋词','song-ci','鹧鸪天','[]','饮罢天厨碧玉觞。',64,'宋词/ci.song.13000.json','["饮罢天厨碧玉觞。", "仙韶九奏少停章。", "何人采得扶桑椹，捣就蓝桥碧绀霜。", "凡骨变，骤清凉。", "何须仙露与琼浆。", "君恩珍重浑如许，祝取天皇似玉皇。"]'),
('song-ci-209','水调歌头','程珌','宋','宋词','song-ci','水调歌头','[]','玉女扫天净，雍观掠江宽。',114,'宋词/ci.song.13000.json','["玉女扫天净，雍观掠江宽。", "问君何事底急，夜半挟舟还。", "三岛眠龙惊觉，万顷明琼碾破，凉月照东南。", "碧气正吞吐，满挹漱膺肝。", "烟蓬上，乘云象，嗷天关。", "人间已梦，我独危坐玩漫汗。", "螭殿黄昏未锁，鹤氅翩跹蜚下，共吸酒壶乾。", "兴罢吹笙去，风露五更寒。"]'),
('song-ci-210','水调歌头','程珌','宋','宋词','song-ci','水调歌头','[]','电阙驱神骏，铁棰起痴蛟。',114,'宋词/ci.song.13000.json','["电阙驱神骏，铁棰起痴蛟。", "木鸣山裂盛夏，白昼野魖号。", "急上瑶庭深处，为问龙君何怒，抉破古天河。", "日华开绚采，雨意属诗豪。", "与君来，蜚玉佩，斩觚瓢。", "纤流沈羽，借我万斛沸银涛。", "醉拍满缸香雪，写竭一池浓墨，逸气正飘颻。", "何事谪仙子，归去续松醪。"]'),
('song-ci-211','水调歌头','程珌','宋','宋词','song-ci','水调歌头','[]','日毂金钲赤，雪窦水晶寒。',114,'宋词/ci.song.13000.json','["日毂金钲赤，雪窦水晶寒。", "支机石下翻浪，喷薄出层关。", "半夜雌龙惊走，明日灵蛇张甲，蜚上石盘桓。", "多谢山君护，未放醉翁闲。", "安得醉，风泚泚，露珊珊。", "翠云老子，邀我瑶佩驾红鸾。", "一勺流觞何有，万石横缸如注，虹气饮溪乾。", "忽梦坐银井，长啸俯清湍。"]'),
('song-ci-212','水调歌头','程珌','宋','宋词','song-ci','水调歌头','["\u957f\u6c5f"]','天地本无际，南北竟谁分。',114,'宋词/ci.song.13000.json','["天地本无际，南北竟谁分。", "楼前多景，中原一恨杳难论。", "却似长江万里，忽有孤山两点，点破水晶盆。", "为借鞭霆力，驱去附昆仑。", "望淮阴，兵冶处，俨然存。", "看来天意，止欠士雅与刘琨。", "三拊当时顽石，唤醒隆中一老，细与酌芳尊。", "孟夏正须雨，一洗北尘昏。"]'),
('song-ci-213','水调歌头','程珌','宋','宋词','song-ci','水调歌头','[]','渤澥东南界，西北倚昆仑。',114,'宋词/ci.song.13000.json','["渤澥东南界，西北倚昆仑。", "当时推步，但知宇内有乾坤。", "午夜风轮微转，驾我浮空泛景，一息过天垠。", "俯视人间世，渺渺聚沤尘。", "挽天吴，摩海若，吐还吞。", "宁用计年，八十阳九又三阴。", "要自白榆星外，直至黑流沙底，山与泽俱平。", "不论初末度，一色界如银。"]'),
('song-ci-214','六州歌头','程珌','宋','宋词','song-ci','六州歌头','[]','向来抵掌，未必总谈空。',182,'宋词/ci.song.13000.json','["向来抵掌，未必总谈空。", "难遍举，质三事，试从公。", "记当年，赋得一丘一壑，天鸢阔，渊鱼静，莫击磬，但酌酒，尽从容。", "一水西来他日，会从公、曳杖其中。", "问前回归去，已笑白发成蓬。", "不识如今，几西风。", "蒙庄多事，论虱豕，推羊蚁，未辞终。", "又骤说，鱼得计，孰能通。", "□□□。", "叹如云罔罟，龙伯啖，眇难穷。", "凡三惑，谁使我，释然融。", "岂是匏瓜者，把行藏、悉俯鸿濛。", "且从头检校，想见迎公。", "湖上千松。"]'),
('song-ci-215','满江红','程珌','宋','宋词','song-ci','满江红','["\u6d1e\u5ead\u6e56", "\u9ec4\u9e64\u697c"]','黄鹤楼前，江百尺、波横光溢。',115,'宋词/ci.song.13000.json','["黄鹤楼前，江百尺、波横光溢。", "问老子、当年高兴，何人知得。", "最爱洞庭天际水，分明表里玻璃色。", "恐今宵、未必似前番，天应惜。", "都莫问，鸿锺勒。", "也休羡，壶天谪。", "忆故人霜下，乱滩横笛。", "便好骑鲸游汗漫，古来蟾影何曾没。", "更明年、重约再来时，乘槎客。"]'),
('song-ci-216','满江红','程珌','宋','宋词','song-ci','满江红','[]','颇恨登临，浪自作、骚人愁语。',115,'宋词/ci.song.13000.json','["颇恨登临，浪自作、骚人愁语。", "石城上、何须苦说，死袁生褚。", "当日卧龙商略处，秦淮王气真何许。", "与君来、萧瑟北风寒，黄云暮。", "枕锺阜，湖玄武。", "生此虎，真蹲踞。", "看四山环合，休临江渚。", "可笑唐人无意度，却言此虎凌波去。", "君且住、明月为人来，潮生浦。"]'),
('song-ci-217','沁园春','程珌','宋','宋词','song-ci','沁园春','[]','玉局仙人，轻帆万里，送入三吴。',140,'宋词/ci.song.13000.json','["玉局仙人，轻帆万里，送入三吴。", "怪一舟如叶，元无浊物，依然姑射，满载冰壶。", "昔日文君，千言成诵，不识如今记得无。", "新来也，喜都将分付，一颗骊珠。", "向来田赋蠲输。", "散多少、春风巴与渝。", "算公家粗了，莼鲈而已，何妨西子，白发江湖。", "印铸黄金，时来须佩，毕竟人生万卷书。", "离情处，正秦淮岁晚，雪意模糊。"]'),
('song-ci-218','步虚词・西江月','程珌','宋','宋词','song-ci','步虚词・西江月','[]','休怪频年司钥，仙官长守仙宫。',58,'宋词/ci.song.13000.json','["休怪频年司钥，仙官长守仙宫。", "东风未肯到凡红。", "先舞云韶彩凤。", "都是一团和气，故教上苑春浓。", "群仙拍手过江东。", "高唱紫芝新颂。"]'),
('song-ci-219','沁园春','程珌','宋','宋词','song-ci','沁园春','[]','公有仙姿，苍松野鹤，落落昂昂。',140,'宋词/ci.song.13000.json','["公有仙姿，苍松野鹤，落落昂昂。", "论法主长生，仍须极贵，云台绛阙，都许尚羊。", "更忆当年，而今时候，一念功名下帝旁。", "天分付，使人间草木，尽有春香。", "人知相法奇庞。", "又那识、阴功事更长。", "算毗陵荒政，江东风采，忠文典则，澟澟生光。", "再岁秦淮，觚棱入梦，帷幄从来在庙堂。", "公归去，好平心献替，人望时康。"]'),
('song-ci-220','沁园春','程珌','宋','宋词','song-ci','沁园春','[]','那用招秋，休言推暑，风自薰兮。',140,'宋词/ci.song.13000.json','["那用招秋，休言推暑，风自薰兮。", "问谁解当初，识公来处，月明碧落，旆卷青霓。", "千丈长松，起人生意，冻芋寒瓜空满畦。", "还堪怪，怪诸公衮衮，我尚凭泥。", "须教一举崔嵬。", "算人世、功名各有梯。", "更何须炼鼎，玄霜绛雪，只烦煮茗，水饼冰齑。", "紫府多仙，招来满座，公自长生角亢齐。", "何曾也，有玉麟行地，老凤梧栖。"]'),
('song-ci-221','沁园春','程珌','宋','宋词','song-ci','沁园春','[]','君有新词，何妨为我，时遣奚奴。',140,'宋词/ci.song.13000.json','["君有新词，何妨为我，时遣奚奴。", "看此山大小，风流晋宋，眼中馀子，苦自侏儒。", "九曲清溪，千枝杨柳，还记新条更有无。", "春将好，欲从君商略，君意何如。", "佳人玉佩琼琚。", "更胸中、浇灌有诗书。", "把古人行处，从头检点，今人说底，却不须渠。", "更上石头，重登锺阜，画作金陵考古图。", "频相见，怕薰风早晚，便隔天隅。"]'),
('song-ci-222','沁园春','程珌','宋','宋词','song-ci','沁园春','[]','消得雕栏，也不枉教，车马如狂。',140,'宋词/ci.song.13000.json','["消得雕栏，也不枉教，车马如狂。", "怪元和一事，韩公子者，归来斫去，玉毁崑冈。", "为解花嘲，朝来试看，采佩殷霞浥露香。", "君休怪，算只缘太艳，俗障难降。", "诗人未易平章。", "向百卉、雕零独后装。", "看洪炉大器，从来成晚，只须这著，也做花王。", "况是月坡，花围一尺，压尽纷纷琐细芳。", "还堪笑，笑龙锺老凤，方入都堂。"]'),
('song-ci-223','沁园春','程珌','宋','宋词','song-ci','沁园春','[]','试课阳坡，春后添栽，多少杉松。',140,'宋词/ci.song.13000.json','["试课阳坡，春后添栽，多少杉松。", "正桃坞昼浓，云溪风软，从容延叩，太史丞公。", "底事越人，见垣一壁，比过秦关遽失瞳。", "江神吏，灵能脱罟，不发卫平蒙。", "休言唐举无功。", "更休笑、丘轲自厄穷。", "算汨罗醒处，元来醉里，真敖假孟，毕竟谁封。", "太史亡言，床头酿熟，人在晴岚杳霭中。", "新堤路，喜樛枝鳞角，夭矫苍龙。"]'),
('song-ci-224','锦堂春・锦堂春慢','程珌','宋','宋词','song-ci','锦堂春・锦堂春慢','[]','最是元来，苦无风雨。',74,'宋词/ci.song.13000.json','["最是元来，苦无风雨。", "只恁匆匆归去。", "看游丝、都不恨，恨秦淮新涨，向人东注。", "醉里仙人，惜春曾赋。", "却不解、留春且住。", "问何人、留得住。", "怕小山更有，碧芜春句。"]'),
('song-ci-225','壶中天・念奴娇','程珌','宋','宋词','song-ci','壶中天・念奴娇','[]','日躔东井，正轮囷桂影，十分光洁。',121,'宋词/ci.song.13000.json','["日躔东井，正轮囷桂影，十分光洁。", "火令方中符国运，天与非常英杰。", "荦荦平生，眼空宇宙，绿发千寻雪。", "笑谈一镇，单于底事心慑。", "晚岁佛地功深，人间富贵，五湖烟水阔。", "谁遣心期事左，须酬满、麒麟勋业。", "又也何妨，长生仙箓，已在黄金阙。", "中原恢拓，要公归任调燮。"]'),
('song-ci-226','烛影摇红','程珌','宋','宋词','song-ci','烛影摇红','[]','青旆摇风，朱帘漏月黄昏早。',116,'宋词/ci.song.13000.json','["青旆摇风，朱帘漏月黄昏早。", "蓬山万叠忽蜚来，上有千灯照。", "和气祥烟缭绕。", "映琼楼、五云缥缈。", "青裙缟袂，乱吹繁弦，九衢欢笑。", "元是琴堂，十分管领春光到。", "手移星宿下人寰，招客来仙岛。", "信道邦人见少。", "彷佛似、皇都春好。", "明年只恐，鳌山扈从，随班清晓。"]'),
('song-ci-227','谒金门','程珌','宋','宋词','song-ci','谒金门','[]','烟漠漠。',53,'宋词/ci.song.13000.json','["烟漠漠。", "醉里看春都错。", "过了清明迟一著。", "牡丹重约摸。", "晓日渐明檐角。", "天与芳辰难却。", "驻得韶华元有药。", "桃源谁共约。"]'),
('song-ci-228','水龙吟','程珌','宋','宋词','song-ci','水龙吟','["\u6ed5\u738b\u9601"]','道家弱水蓬莱，鲸波万里谁知得。',126,'宋词/ci.song.13000.json','["道家弱水蓬莱，鲸波万里谁知得。", "人间自有，南昌居士，仙风道骨。", "诗似白星，貌如聃老，风尘挺出。", "向谪仙家里，滕王阁畔，飘玉佩、下丹阙。", "黄发四朝元老，又谁知、重生绿发。", "手提一笔，活人多少，三千功积。", "已冠文昌，人人瞻望，玉枢躔逼。", "对新凉、酒颊微红，宛是一星南极。"]'),
('song-ci-229','喜迁莺','程珌','宋','宋词','song-ci','喜迁莺','[]','少年意气，脑燕兵胡，虏王区脱。',125,'宋词/ci.song.13000.json','["少年意气，脑燕兵胡，虏王区脱。", "眼底朦胧，腹中空洞，不著曹刘元白。", "闻道殊科八中，也要彩卢连掷。", "收拾尽，到如今但有，寸心如铁。", "天付，真奇特。", "口静神充，双眼胡僧碧。", "楚国离骚，唐朝词学，未信芳尘□歇。", "结取佳人香佩，截断儿曹绮舌。", "归去也，且斓斑戏彩，好春长日。"]'),
('song-ci-230','喜迁莺','程珌','宋','宋词','song-ci','喜迁莺','[]','评君谁似，似长松千丈，离奇多节。',126,'宋词/ci.song.13000.json','["评君谁似，似长松千丈，离奇多节。", "骨瘦棱棱，文高荦荦，今日□来仙阙。", "走卒识公容貌，酋虏问公官阀。", "更史馆，一编书多少，频添勋业。", "伟绝。", "今岁别。", "新绿名孙，又见枝生叶。", "底事七旬，双瞳如水，毕竟桂花方发。", "赐第彤墀秋早，又一瑶枢光洁。", "故人也，念相逢谁似，凤池同列。"]'),
('song-ci-231','喜迁莺','程珌','宋','宋词','song-ci','喜迁莺','[]','一天风露，喜初行弹压，人间残暑。',126,'宋词/ci.song.13000.json','["一天风露，喜初行弹压，人间残暑。", "金母此时，云軿先绛，又见枢星光吐。", "人道鸿濛逢日，可是东方明处。", "更天上、走王人络绎，仪鸾琼醑。", "听语。", "更希举。", "试把皇朝、盛事都来数。", "当日鳌头，皇扉侍母，绿发方瞳□□。", "更有飞凫王季，往往文星再聚。", "浑休问，但回班千岁，貂蝉成谱。"]'),
('song-ci-232','喜迁莺','程珌','宋','宋词','song-ci','喜迁莺','[]','去年玉燕，记曾期今岁，瑶光入度。',126,'宋词/ci.song.13000.json','["去年玉燕，记曾期今岁，瑶光入度。", "今日都人，从头屈指，尽是黑头公辅。", "争道一朝语合，谁信千龄际遇。", "更积雨。", "晓来晴，洗出琉璃秋宇。", "笑语。", "知何许。", "旆卷青霓，来自钧天所。", "道骨仙风，安排顿著，须是人间紫府。", "要识云台高绝，更有凤池深处。", "从今数。", "看千秋万岁，永承明主。"]'),
('song-ci-233','柳梢青','程珌','宋','宋词','song-ci','柳梢青','[]','官已尚书，人犹寒素，仙有名言。',61,'宋词/ci.song.13000.json','["官已尚书，人犹寒素，仙有名言。", "谓是若人，法当至贵，仍主修年。", "唐人四字鲜妍。", "堪照映、画堂彩烟。", "更对新凉，一声芝曲，万斛金船。"]'),
('song-ci-234','柳梢青','程珌','宋','宋词','song-ci','柳梢青','[]','嫩绿成堆。',61,'宋词/ci.song.13000.json','["嫩绿成堆。", "朝来红紫，都在莓苔。", "方见春来，又闻春去，暗里谁催。", "人生易老何哉。", "春去矣、秋风又来。", "何似云溪，长春日月，无去无归。"]'),
('song-ci-235','酹江月・念奴娇','程珌','宋','宋词','song-ci','酹江月・念奴娇','[]','平生有意，把六经膏泽，人人沾受。',120,'宋词/ci.song.13000.json','["平生有意，把六经膏泽，人人沾受。", "白被子明康节辈，浪说乘除先后。", "遇合一时，英雄千古，谁是高强手。", "蹉跎岁晚，临风浩然搔首。", "今但入梦青山，云溪深处，烟月生怀袖。", "宿有十年萧散愿，此段功缘须就。", "因忆坡公，仇池有约，莫误归时候。", "今朝对酒，歌此与君为寿。"]'),
('song-ci-236','贺新郎','程珌','宋','宋词','song-ci','贺新郎','[]','袖手云溪畔。',146,'宋词/ci.song.13000.json','["袖手云溪畔。", "看人间、纷纷饥乌腐鼠，触蛮交战。", "便得金鱼垂玉带，多少雌黄点勘。", "算此语、必非河汉。", "直自弹冠班八座，更青春、数到期颐算。", "一段玉，无纤玷。", "公难学处尤堪羡。", "全似□、泠泠秋水，体清形健。", "衮处从来高一著，那肯随人脚转。", "要须是、常见乾坤清晏。", "天意未教公猛去，要都俞、了却从公便。", "歌寿斝，朱帘卷。"]'),
('song-ci-237','宝鼎现','程珌','宋','宋词','song-ci','宝鼎现','[]','绿杨欲舞，红杏微笑，春工渐侈。',192,'宋词/ci.song.13000.json','["绿杨欲舞，红杏微笑，春工渐侈。", "试偻指、自从嘉定，数到宝庆□□里。", "无一岁、不书年大有，问元功谁燮理。", "□□□、於变雍熙，如此自当千岁。", "况是端笏蓬莱陛。", "但看雍容、玉立山峙。", "炼五色、补天无迹，扶日天衢光四被。", "安清祐、填群心声色，恬然如谈笑耳。", "更八荒、民生奠枕，此著又当千岁。", "又况善述先猷，严武备、不开边鄙。", "阴功遍南北，千岁未多畴祉。", "且说总是三千岁。", "此际方岐嶷。", "听今日、处处笙歌，何止南楼十二。"]'),
('song-ci-238','念奴娇','程珌','宋','宋词','song-ci','念奴娇','["\u897f\u6e56"]','归来一笑，尚看看趁得，人间寒食。',121,'宋词/ci.song.13000.json','["归来一笑，尚看看趁得，人间寒食。", "阿寿牵衣仍问我，双鬓新来添白。", "忍见庭前，去年芳草，依旧青青色。", "西湖雨后，绿波两岸平拍。", "天教断送流年，三之一矣，又是成疏隔。", "燕子春寒浑未到，谁说江南消息。", "玉树熏香，冰桃翻浪，好个山间景物。", "这回归去，松风深处横笛。"]'),
('song-ci-239','念奴娇','程珌','宋','宋词','song-ci','念奴娇','[]','嫣然一笑，向烛花光下，经年才见。',120,'宋词/ci.song.13000.json','["嫣然一笑，向烛花光下，经年才见。", "欲语还羞如有恨，方得东君一盼。", "天意无情，更教微雨，香泪流丹脸。", "今朝霁色，笙歌初沸庭院。", "因是思入东屏，当年手植，遍桃源低岸。", "失脚东来春七度，辜负芳丛无限。", "问讯园丁，宁如归去，细与从头看。", "东风独立，白云遮断双眼。"]'),
('song-ci-240','倾杯・倾杯乐','程珌','宋','宋词','song-ci','倾杯・倾杯乐','[]','銮殿秋深，玉堂宵永，千门人静。',132,'宋词/ci.song.13000.json','["銮殿秋深，玉堂宵永，千门人静。", "问天上、西风几度，金盘光满，露浓银井。", "碧云飞下双鸾影。", "迤逦笙歌近笑语，群仙隐隐。", "更前问讯。", "堕在红尘今省。", "渐曙色、晓风清迥。", "更积霭沈阴、都卷尽。", "向窗前、引镜看来，尚喜精神炯炯。", "便折简、浮丘共酌，奈天也、未教酩酊。", "来岁却笑群仙，月寒空冷。"]'),
('song-ci-241','醉蓬莱','程珌','宋','宋词','song-ci','醉蓬莱','[]','算千葩百卉，谁伴东风，早春时候。',119,'宋词/ci.song.13000.json','["算千葩百卉，谁伴东风，早春时候。", "唯有江梅，在人间长久。", "雪后霜前，冲涉多少，尚精神如旧。", "岁岁年年，酴酥饮了，便为公寿。", "更向尊前席上，细看人与梅花，棱棱争瘦。", "桃李漫山，都落芳尘后。", "和气满身，参调玉弦，表天然孤秀。", "来岁今朝，星闱雾阁，一卮春酒。"]'),
('song-ci-242','醉蓬莱','程珌','宋','宋词','song-ci','醉蓬莱','[]','记蟾宫桂子，撒向人间，如今时候。',119,'宋词/ci.song.13000.json','["记蟾宫桂子，撒向人间，如今时候。", "□□□□，□□□□□。", "白下长干，乱滩横笛，想昔游依旧。", "大海一沤，千年一息，谁称彭寿。", "开遍门前丹蕊，渐西风入东篱，酿成仙酒。", "□□□□，□□□□□。", "卓笔鸡笼，悬天宝盖，占断宣徽秀。", "来岁清苕，公家事了，斑衣蓝绶。"]'),
('song-ci-243','西江月','程珌','宋','宋词','song-ci','西江月','[]','天上初秋桂子，庭前八月丹花。',58,'宋词/ci.song.13000.json','["天上初秋桂子，庭前八月丹花。", "一年一度见仙槎。", "秋色分明如画。", "愿把阴功一脉，灯灯相续无涯。", "降祥作善岂其差。", "永作渔樵嘉话。"]'),
('song-ci-244','西江月','程珌','宋','宋词','song-ci','西江月','[]','底事中秋无月，元来留待今宵。',58,'宋词/ci.song.13000.json','["底事中秋无月，元来留待今宵。", "群仙拍手度仙桥。", "惊起眠龙夭矫。", "天上灵槎一度，人间八月江潮。", "西兴渡口几魂消。", "又见潮生月上。"]'),
('song-ci-245','满庭芳','程珌','宋','宋词','song-ci','满庭芳','[]','未岁嘉平，初旬日四，雪中归自崇唐。',118,'宋词/ci.song.13000.json','["未岁嘉平，初旬日四，雪中归自崇唐。", "山林湖海，一气接苍茫。", "踏尽玉龙千丈，更一望、龙尾天长。", "须臾上，高峰四顾，迤逦过前冈。", "群山，如玉削，松林百万，尽傅琼霜。", "浑疑是天际，一鹤翱翔。", "人道玉皇三六，欲一叩、风力方刚。", "明朝好，金乌衔烛，八表散祥光。"]'),
('song-ci-246','满庭芳','程珌','宋','宋词','song-ci','满庭芳','[]','去腊飞花，今春未已，迤逦将度元宵。',118,'宋词/ci.song.13000.json','["去腊飞花，今春未已，迤逦将度元宵。", "俄然甲子，青帝下新条。", "净扫一天沈霭，红轮满、大地山河。", "从今好，便当听取，万国起歌谣。", "有人，当此际，锄云深坞，剪月中阿。", "已占断春风，自种仙桃。", "更扶疏桂影直，从岩底、上拂云梢。", "仍为我，长摩苍石，无负此清波。"]'),
('song-ci-247','满庭芳','程珌','宋','宋词','song-ci','满庭芳','[]','人道苍姬，燠多寒少，故教千岁绵绵。',118,'宋词/ci.song.13000.json','["人道苍姬，燠多寒少，故教千岁绵绵。", "算来春夏，一气本无偏。", "底事今年玉历，秋未朔、风露泠然。", "君知否，山深地僻，自是早霜天。", "如今，当此去，十分亲切，面问婵娟。", "何须看仙槎，海上重还。", "好在金英玉屑，□为我、满泛金船。", "仍传语，横江秀石，□永锁三川。"]'),
('song-ci-248','减字木兰花','程珌','宋','宋词','song-ci','减字木兰花','[]','不应双睫。',52,'宋词/ci.song.13000.json','["不应双睫。", "看尽人间花与雪。", "曾是当时。", "一朵红云拥日飞。", "如今正好。", "万绿千红深处坐。", "也使春工。", "唤作天池五月风。"]'),
('song-ci-249','意难忘','朱用之','宋','宋词','song-ci','意难忘','[]','宫额涂黄。',114,'宋词/ci.song.13000.json','["宫额涂黄。", "怕笺凝怨墨，酒渍离觞。", "红楼春寄梦，青琐夕生香。", "花气暖，柳阴凉。", "棹曲水沧浪。", "爱弄娇、临流梳洗，顾影低相。", "桃花结子成双。", "纵题红去后，枉误刘郎。", "琴心挑别恨，莺羽学新妆。", "千万恨，恼愁肠。", "便憔悴何妨。", "待共伊、平消别后，几度风光。"]'),
('song-ci-250','失调名','厉元范','宋','宋词','song-ci','失调名','[]','叶叶柳眉齐抹翠，梢梢花脸争匀白。',16,'宋词/ci.song.13000.json','["叶叶柳眉齐抹翠，梢梢花脸争匀白。"]'),
('song-ci-251','昭君怨','郑域','宋','宋词','song-ci','昭君怨','[]','道是花来春未。',48,'宋词/ci.song.13000.json','["道是花来春未。", "道是雪来香异。", "竹外一枝斜。", "野人家。", "冷落竹篱茅舍。", "富贵玉堂琼榭。", "两地不同栽。", "一般开。"]'),
('song-ci-252','念奴娇','郑域','宋','宋词','song-ci','念奴娇','[]','水晶宫殿，放三千龙女，凌波浮浴。',120,'宋词/ci.song.13000.json','["水晶宫殿，放三千龙女，凌波浮浴。", "花里雕房分洞户，隐隐钉头齐簇。", "处子娇羞，碧裙无袖，密护圆瑳玉。", "堤头微露，半身犹掩金绿。", "知是紫府筵开，□随纤指，出玲珑窗屋。", "倩剥霓裳轻手搔，掐损些些香玉。", "端的中心，密藏芳意，苦苦何时足。", "巴城憔悴，采歌犹闻新曲。"]'),
('song-ci-253','蓦山溪','郑域','宋','宋词','song-ci','蓦山溪','[]','嫣然一笑，风味人间没。',102,'宋词/ci.song.13000.json','["嫣然一笑，风味人间没。", "来自广寒宫，直偷得、天香入骨。", "软金缕屑，点缀碧琼枝，花藏叶，叶笼花，刚被风吹拂。", "道人衾帐，不用沈烟熨。", "插满枕屏山，觉身在、蓝桥仙窟。", "一觞一咏，消得九秋愁，篱边菊，畹中兰，甘避芳尘不。"]'),
('song-ci-254','霜天晓角','郑域','宋','宋词','song-ci','霜天晓角','[]','绿云剪叶。',54,'宋词/ci.song.13000.json','["绿云剪叶。", "低护黄金屑。", "占断花中声誉，香与韵、两清洁。", "胜绝。", "君听说。", "是他来处别。", "试看金衣犹带，金庭露、玉阶月。"]'),
('song-ci-255','念奴娇','郑域','宋','宋词','song-ci','念奴娇','[]','素肌莹净，隔鲛绡贴衬，猩红妆束。',120,'宋词/ci.song.13000.json','["素肌莹净，隔鲛绡贴衬，猩红妆束。", "火伞飞空熔不透，一块玲珑冰玉。", "破暑当筵，褪衣剥带，微露真珠肉。", "中心些子，向人何大焦缩。", "应恨旧日杨妃，尘埃走遍，向南闽西蜀。", "困入筠笼消黯搅，香色精神愁蹙。", "赖有君谟，为传家谱，不弃青黄绿。", "到头甜口，是人都要圜熟。"]'),
('song-ci-256','念奴娇','郑域','宋','宋词','song-ci','念奴娇','[]','蕊宫仙子，爱痴儿、不禁三偷家果。',120,'宋词/ci.song.13000.json','["蕊宫仙子，爱痴儿、不禁三偷家果。", "弃核成根传汉苑，依旧风烟难□。", "老养丹砂，长留红脸，点透胭脂颗。", "金盘盛处，恍然天上新堕。", "莫厌对此飞觞，千年一熟，异人间梨枣。", "刘阮尘缘犹未断，却向花间飞过。", "争似莲枝，摘来满把，莺嘴平分破。", "餐霞嚼露，镇长歌醉蓬岛。"]'),
('song-ci-257','念奴娇','郑域','宋','宋词','song-ci','念奴娇','[]','东陵美景，有轻烟和月，斜风吹雨。',120,'宋词/ci.song.13000.json','["东陵美景，有轻烟和月，斜风吹雨。", "一体龙须随地转，不学松萝儿女。", "结就员青，收来掌握，犹带金盘露。", "拍浮金井，水花零乱飞舞。", "谁信六月飘霜，破开落刃，散银丝金缕。", "冷碧凄香萦齿颊，洗我尘襟烦暑。", "杜老吟诗，已公留客，此兴无今古。", "安期非诞，世间有枣如许。"]'),
('song-ci-258','画堂春','郑域','宋','宋词','song-ci','画堂春','[]','东风吹雨破花悭。',55,'宋词/ci.song.13000.json','["东风吹雨破花悭。", "客毡晓梦生寒。", "有人斜倚小屏山。", "蹙损眉弯。", "合是一钗双燕，却成两镜孤鸾。", "暮云修竹泪留残。", "翠袖凝斑。"]'),
('song-ci-259','桃源忆故人','郑域','宋','宋词','song-ci','桃源忆故人','[]','东风料峭寒吹面。',56,'宋词/ci.song.13000.json','["东风料峭寒吹面。", "低下绣帘休卷。", "憔悴怕他春见。", "一任莺花怨。", "新愁不受诗排遣。", "尘满玉毫金砚。", "若问此愁深浅。", "天阔浮云远。"]'),
('song-ci-260','念奴娇','郑域','宋','宋词','song-ci','念奴娇','[]','嗟来咄去，被天公、把做小儿调戏。',121,'宋词/ci.song.13000.json','["嗟来咄去，被天公、把做小儿调戏。", "蹀雪龙庭归未久，还促炎州行李。", "不半年间，北胡南越，一万三千里。", "征衫著破，著衫人、可知矣。", "休问海角天涯，黄蕉丹荔，自足供甘旨。", "泛绿依红无个事，时舞斑衣而已。", "救蚁藤桥，养鱼盆沼，是亦经纶耳。", "伊周安在，且须学老莱子。"]'),
('song-ci-261','浣溪沙','郑域','宋','宋词','song-ci','浣溪沙','[]','酒薄愁浓醉不成。',48,'宋词/ci.song.13000.json','["酒薄愁浓醉不成。", "夜长敧枕数残更。", "嫩寒时节过烧灯。", "已自孤鸾羞对镜，未能双凤怕闻笙。", "莫教吹作别离声。"]'),
('song-ci-262','霜天晓角','王澡','宋','宋词','song-ci','霜天晓角','[]','疏明瘦直。',54,'宋词/ci.song.13000.json','["疏明瘦直。", "不受东皇识。", "留与伴春终肯，千红底、怎著得。", "夜色。", "何处笛。", "晓寒无奈力。", "若在寿阳宫院，一点点、有人惜。"]'),
('song-ci-263','祝英台近','王澡','宋','宋词','song-ci','祝英台近','[]','玉东西，歌宛转。',95,'宋词/ci.song.13000.json','["玉东西，歌宛转。", "未做苦离调。", "著上征衫，字字是愁抱。", "月寒鬓影刁萧，舵楼开缆，记柳暗、乳鸦啼晓。", "短亭草。", "还是绿与春归，罗屏梦空好。", "燕语难凭，憔悴未渠了。", "可能妒柳羞花，起来浑懒，便瘦也、教春知道。"]'),
('song-ci-264','点绛唇','赵希','宋','宋词','song-ci','点绛唇','[]','又是年时，冷烟寒食梨花院。',50,'宋词/ci.song.13000.json','["又是年时，冷烟寒食梨花院。", "柳金拖线。", "一曲珠歌转。", "翠碧雕梁，风软帘通燕。", "何须劝。", "酒豪诗健。", "逸韵今重见。"]'),
('song-ci-265','满江红','戴复古','宋','宋词','song-ci','满江红','[]','赤壁矶头，一番过、一番怀古。',115,'宋词/ci.song.13000.json','["赤壁矶头，一番过、一番怀古。", "想当时、周郎年少，气吞区宇。", "万骑临江貔虎噪，千艘列炬鱼龙怒。", "卷长波、一鼓困曹瞒，今如许。", "江上渡，江边路。", "形胜地，兴亡处。", "览遗踪，胜读史书言语。", "几度东风吹世换，千年往事随潮去。", "问道傍、杨柳为谁春，摇金缕。"]'),
('song-ci-266','水调歌头','戴复古','宋','宋词','song-ci','水调歌头','[]','雕鹗上云汉，虎豹守天关。',114,'宋词/ci.song.13000.json','["雕鹗上云汉，虎豹守天关。", "一官游戏，笑向古郢试朱轓。", "天下封疆几郡，尽得公为太守，奉诏仰天宽。", "万物一吐气，千里贺平安。", "雪楼高，三百尺，玉栏干。", "政成无事，时复把酒对江山。", "问讯莫愁安在，见说风流宋玉，犹有屋三间。", "请和阳春曲，留与世人看。"]'),
('song-ci-267','沁园春','戴复古','宋','宋词','song-ci','沁园春','[]','一曲狂歌，有百馀言，说尽一生。',138,'宋词/ci.song.13000.json','["一曲狂歌，有百馀言，说尽一生。", "费十年灯火，读书读史，四方奔走，求利求名。", "蹭蹬归来，闭门独坐，赢得穷吟诗句清。", "夫诗者，皆吾侬平日，愁叹之声。", "空馀豪气峥嵘。", "安得良田二顷耕。", "向临邛涤器，可怜司马，成都卖卜，谁识君平。", "分则宜然，吾何敢怨，蝼蚁逍遥戴粒行。", "开怀抱，有青梅荐酒，绿树啼莺。"]'),
('song-ci-268','贺新郎','戴复古','宋','宋词','song-ci','贺新郎','[]','说与黄花道。',141,'宋词/ci.song.13000.json','["说与黄花道。", "九秋深、三光五岳，气锺英表。", "金马玉堂真学士，蕴藉诗书奥妙。", "一一是、经纶才调。", "斟酌古今来活国，算忠言、谠论知多少。", "又入奏，金门晓。", "朝回问寝披萱草。", "对高堂长说，一片君恩难报。", "更待痴儿千载遇，膝下十分荣耀。", "趁绿鬓、朱颜不老。", "整顿乾坤济时了，奉板舆、拜国夫人号。", "可谓忠，可谓孝。"]'),
('song-ci-269','贺新郎','戴复古','宋','宋词','song-ci','贺新郎','["\u897f\u6e56"]','忆把金罍酒。',142,'宋词/ci.song.13000.json','["忆把金罍酒。", "叹别来、光阴荏苒，江湖宿留。", "世事不堪频着眼，赢得两眉长皱。", "但东望、故人翘首。", "木落山空天远大，送飞鸿、北去伤怀久。", "天下事，公知否。", "钱塘风月西湖柳。", "渡江来、百年机会，从前未有。", "唤起东山丘壑梦，莫惜风霜老手。", "要整顿、封疆如旧。", "早晚枢庭开幕府，是英雄、尽为公奔走。", "看金印，大如斗。"]'),
('song-ci-270','贺新郎','戴复古','宋','宋词','song-ci','贺新郎','["\u957f\u6c5f"]','百尺连云起。',141,'宋词/ci.song.13000.json','["百尺连云起。", "试登临、江山人物，一时俱伟。", "旁挹金陵龙虎势，京岘诸峰对峙。", "隐隐接、扬州歌吹。", "雪浪舞从三峡下，乍逢迎、海若谈秋水。", "形胜地，有如此。", "使君一世经纶志。", "把风斤月斧，来此等闲游戏。", "见说楼成无多日，大手一何容易。", "笑天下、纷纷血指。", "酝酿春风与和气，举长江、变作香醪美。", "人共乐，醉桃李。"]'),
('song-ci-271','水调歌头','戴复古','宋','宋词','song-ci','水调歌头','[]','轮奂半天上，胜概压南楼。',114,'宋词/ci.song.13000.json','["轮奂半天上，胜概压南楼。", "筹边独坐，岂欲登览快双眸。", "浪说胸吞云梦，直把气吞残虏，西北望神州。", "百载一机会，人事恨悠悠。", "骑黄鹤，赋鹦鹉，谩风流。", "岳王祠畔，杨柳烟锁古今愁。", "整顿乾坤手段，指授英雄方略，雅志若为酬。", "杯酒不在手，双鬓恐惊秋。"]'),
('song-ci-272','满庭芳','戴复古','宋','宋词','song-ci','满庭芳','["\u957f\u6c5f"]','三日春光，群贤胜践，山阴何似山阳。',118,'宋词/ci.song.13000.json','["三日春光，群贤胜践，山阴何似山阳。", "鹅池墨妙，曲水记流觞。", "自许风流丘壑，何人共、击楫长江。", "新亭上，山河有异，举目恨堂堂。", "使君，经世志，十年边上，两鬓风霜。", "问池边杨柳，因甚凄凉。", "万树重新种了，株株在、桃李花傍。", "仍须待，剩栽兰芷，为国洗河湟。"]'),
('song-ci-273','满庭芳','戴复古','宋','宋词','song-ci','满庭芳','[]','赤壁矶头，临皋亭下，扁舟两度经过。',118,'宋词/ci.song.13000.json','["赤壁矶头，临皋亭下，扁舟两度经过。", "江山如画，风月奈愁何。", "三国英雄安在，而今但、一目烟波。", "风流处，竹楼无恙，相对有东坡。", "登临，还自笑，狂游四海，一向忘家。", "算天寒路远，早早归呵。", "明日片帆东下，沧洲上、千里芦花。", "真堪爱，买鱼沽酒，到处听吴歌。"]'),
('song-ci-274','醉落魄・一斛珠','戴复古','宋','宋词','song-ci','醉落魄・一斛珠','[]','龙山行乐。',67,'宋词/ci.song.13000.json','["龙山行乐。", "何如今日登黄鹤。", "风光政要人酬酢。", "欲赋归来，莫是渊明错。", "江山登览长如昨。", "飞鸿影里秋光薄。", "此怀祗有黄花觉。", "牢裹乌纱，一任西风作。"]'),
('song-ci-275','柳梢青','戴复古','宋','宋词','song-ci','柳梢青','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','袖剑飞吟。',61,'宋词/ci.song.13000.json','["袖剑飞吟。", "洞庭青草，秋水深深。", "万顷波光，岳阳楼上，一快披襟。", "不须携酒登临。", "问有酒、何人共斟。", "变尽人间，君山一点，自古如今。"]'),
('song-ci-276','锦帐春','戴复古','宋','宋词','song-ci','锦帐春','[]','处处逢花，家家插柳。',71,'宋词/ci.song.13000.json','["处处逢花，家家插柳。", "政寒食、清明时候。", "奉板舆行乐，使星随后。", "人间稀有。", "出郭寻仙，绣衣春昼。", "马上列、两行红袖。", "对韶华一笑，劝国夫人酒。", "百千长寿。"]'),
('song-ci-277','行香子','戴复古','宋','宋词','song-ci','行香子','[]','万石崔嵬，二水涟漪。',84,'宋词/ci.song.13000.json','["万石崔嵬，二水涟漪。", "此江山、天下之奇。", "太平气象，百姓熙熙。", "有文章公，经纶手，把州麾。", "满斟寿酒，笑拈梅枝。", "管年年、长见花时。", "佳人休唱，浅近歌词。", "读浯溪颂，愚公记，澹岩诗。"]'),
('song-ci-278','鹊桥仙','戴复古','宋','宋词','song-ci','鹊桥仙','[]','新荷池沼，绿槐庭院。',68,'宋词/ci.song.13000.json','["新荷池沼，绿槐庭院。", "檐外雨声初断。", "喧喧两部乱蛙鸣，怎得似、啼莺睍睆。", "风光流转。", "客游汗漫。", "莫问鬓丝长短。", "即时杯酒醉时歌，算省得、闲愁一半。"]'),
('song-ci-279','木兰花慢','戴复古','宋','宋词','song-ci','木兰花慢','[]','莺啼啼不尽，任燕语、语难通。',122,'宋词/ci.song.13000.json','["莺啼啼不尽，任燕语、语难通。", "这一点闲愁，十年不断，恼乱春风。", "重来故人不见，但依然、杨柳小楼东。", "记得同题粉壁，而今壁破无踪。", "兰皋新涨绿溶溶。", "流恨落花红。", "念著破春衫，当时送别，灯下裁缝。", "相思谩然自苦，算云烟、过眼总成空。", "落日楚天无际，凭栏目送飞鸿。"]'),
('song-ci-280','洞仙歌','戴复古','宋','宋词','song-ci','洞仙歌','[]','卖花担上，菊蕊金初破。',100,'宋词/ci.song.13000.json','["卖花担上，菊蕊金初破。", "说着重阳怎虚过。", "看画城簇簇，酒肆歌楼，奈没个巧处，安排着我。", "家乡煞远哩，抵死思量，枉把眉头万千锁。", "一笑且开怀，小阁团栾，旋簇着、几般蔬果。", "把三杯两盏记时光，问有甚曲儿，好唱一个。"]'),
('song-ci-281','西江月','戴复古','宋','宋词','song-ci','西江月','[]','宿酒才醒又醉，春霄欲雨还晴。',58,'宋词/ci.song.13000.json','["宿酒才醒又醉，春霄欲雨还晴。", "柳边花底听莺声。", "白发莫教临镜。", "过隙光阴易去，浮云富贵难凭。", "但将一笑对公卿。", "我是无名百姓。"]'),
('song-ci-282','西江月','戴复古','宋','宋词','song-ci','西江月','[]','三过武昌台下，却逢三度重阳。',58,'宋词/ci.song.13000.json','["三过武昌台下，却逢三度重阳。", "菊花祗作旧时黄。", "白雪堆人头上。", "昨日将军亭馆，今朝陶令壶觞。", "醉来东望海茫茫。", "家近蓬莱方丈。"]'),
('song-ci-283','贺新郎','戴复古','宋','宋词','song-ci','贺新郎','[]','蜗角争多少。',142,'宋词/ci.song.13000.json','["蜗角争多少。", "是英雄、割据乾坤，到头休了。", "一片泥涂荒草地，尽是鱼龙故道。", "新堤上、风涛难保。", "沧海桑田何时变，怕桑田、未变人先老。", "休为此，生烦恼。", "讼庭不许频频到。", "这官坊、翻来覆去，有何分晓。", "无诤人中为第一，长讼元非吉兆。", "但有恨、平章不早。", "尊酒唤回和气在，看从来、兄弟依然好。", "把前事，付一笑。"]'),
('song-ci-284','沁园春','戴复古','宋','宋词','song-ci','沁园春','[]','请赋林堂，林堂未成，吾何赋哉。',139,'宋词/ci.song.13000.json','["请赋林堂，林堂未成，吾何赋哉。", "想胸中丘壑，山中风月，亭台几所，花木千栽。", "应接光阴，品题胜概，须待堂成我再来。", "听分付，是经行去处，莫放苍苔。", "吾曹不堕尘埃。", "要胸次长随笑口开。", "任江湖浪迹，鸥盟雁序，功名到手，凤阁鸾台。", "它日相寻，有逾此约，酌水浮君三百杯。", "闻斯语，有冠山突兀，袍岭崔嵬。"]'),
('song-ci-285','鹧鸪天','戴复古','宋','宋词','song-ci','鹧鸪天','[]','圉圉洋洋各自由。',64,'宋词/ci.song.13000.json','["圉圉洋洋各自由。", "或行或舞或沈浮。", "观鱼未必知鱼乐，政恐清波照白头。", "休结纲，莫垂钩。", "机心一露使鱼愁。", "终知不是池中物，掉尾江湖汗漫游。"]'),
('song-ci-286','减字木兰花','戴复古','宋','宋词','song-ci','减字木兰花','[]','羊城旧路。',52,'宋词/ci.song.13000.json','["羊城旧路。", "檀板一声惊客去。", "不拟重来。", "白发飘飘上越台。", "故人居处。", "曲巷深深通竹所。", "问讯桃花。", "欲访刘郎不在家。"]'),
('song-ci-287','减字木兰花','戴复古','宋','宋词','song-ci','减字木兰花','[]','天台狂客。',52,'宋词/ci.song.13000.json','["天台狂客。", "醉里不知秋鬓白。", "应接风光。", "忆在江亭醉几场。", "吴姬劝酒。", "唱得廉颇能饭否。", "西雨东晴。", "人道无情又有情。"]'),
('song-ci-288','减字木兰花','戴复古','宋','宋词','song-ci','减字木兰花','[]','阻风中酒。',52,'宋词/ci.song.13000.json','["阻风中酒。", "流落江湖成白首。", "历尽艰关。", "赢得虚名在世间。", "浩然归去。", "忆着石屏茅屋趣。", "想见山村。", "树有交柯犊有孙。"]'),
('song-ci-289','浣溪沙','戴复古','宋','宋词','song-ci','浣溪沙','[]','病起无聊倚绣床。',48,'宋词/ci.song.13000.json','["病起无聊倚绣床。", "玉容清瘦懒梳妆。", "水沈烟冷橘花香。", "说个话儿方有味，吃些酒子又何妨。", "一声啼鴂断人肠。"]'),
('song-ci-290','清平乐','戴复古','宋','宋词','song-ci','清平乐','[]','醉狂痴作。',54,'宋词/ci.song.13000.json','["醉狂痴作。", "误信青楼约。", "酒醒梅花吹画角。", "翻得一场寂寞。", "相如谩赋凌云。", "琴台不遇文君。", "江上琵琶旧曲，只堪分付商人。"]'),
('song-ci-291','临江仙','戴复古','宋','宋词','song-ci','临江仙','[]','误入风尘门户，驱来花月楼台。',68,'宋词/ci.song.13000.json','["误入风尘门户，驱来花月楼台。", "樽前几度得徘徊。", "可怜容易别，不见牡丹开。", "莫恨银瓶酒尽，但将妾泪添杯。", "江头恰限北风回。", "再三相祝去，千万寄书来。"]'),
('song-ci-292','鹊桥仙','戴复古','宋','宋词','song-ci','鹊桥仙','[]','西山岩壑，东湖亭馆，尽是经行旧路。',68,'宋词/ci.song.13000.json','["西山岩壑，东湖亭馆，尽是经行旧路。", "别时方见有荷花，还又见、梅花岁暮。", "宋家兄弟，黄家兄弟，一一烦君传语。", "相忘不寄一行书，元自有、不相忘处。"]'),
('song-ci-293','祝英台近','戴复古','宋','宋词','song-ci','祝英台近','[]','泛杭川，临尘水。',95,'宋词/ci.song.13000.json','["泛杭川，临尘水。", "几日共游戏。", "歌笑开怀，酒醒又还醉。", "奈何一但分携，连宵风雨，剪不断、客愁千里。", "水云际。", "遥望一片飞鸿，苦是失群地。", "满眼春风，管甚闲桃李。", "此行归老家山，相逢难又，但一味、相思而已。"]'),
('song-ci-294','大江西上曲・念奴娇','戴复古','宋','宋词','song-ci','大江西上曲・念奴娇','[]','大江西去，郁孤台八境，人间图画。',120,'宋词/ci.song.13000.json','["大江西去，郁孤台八境，人间图画。", "地涌千峰摇翠浪，两派玉虹如泻。", "弹压江山，品题风月，四海今王谢。", "风流人物，如公一世雄也。", "一片忧国丹心，弹丝吹笛，未必能陶写。", "西北风尘方澒洞，宰相闲归绿野。", "月斧争鸣，风斤运巧，不用修亭榭。", "紫枢黄阁，要公整顿天下。"]'),
('song-ci-295','满江红','戴复古','宋','宋词','song-ci','满江红','[]','太守风流，何人似、金华仙伯。',115,'宋词/ci.song.13000.json','["太守风流，何人似、金华仙伯。", "试看取、珠篇玉句，银钩铁画。", "叶叶柳眉齐抹翠，梢梢花脸争匀白。", "比池塘、春草梦来诗，尤奇绝。", "胸中有，蛾眉月。", "笔头带，蓬□雪。", "笑归来万里，不登今阙。", "鹿瑞堂前冬日暖，螺山江上春波阔。", "但伤时、一念不能休，添华发。"]'),
('song-ci-296','望江南・忆江南','戴复古','宋','宋词','song-ci','望江南・忆江南','[]','壶山好，博古又通今。',64,'宋词/ci.song.13000.json','["壶山好，博古又通今。", "结屋三间藏万卷，挥毫一字直千金。", "四海有知音。", "门外路，咫尺是湖阴。", "万柳堤边行处乐，百花洲上醉时吟。", "不负一生心。"]'),
('song-ci-297','望江南・忆江南','戴复古','宋','宋词','song-ci','望江南・忆江南','[]','壶山好，胆气不妨粗。',64,'宋词/ci.song.13000.json','["壶山好，胆气不妨粗。", "手奋空拳成活计，眼穿故纸下功夫。", "处世未全疏。", "生涯事，近日果何如。", "背锦奚奴能检典，画眉老妇出交租。", "且喜有赢馀。"]'),
('song-ci-298','望江南・忆江南','戴复古','宋','宋词','song-ci','望江南・忆江南','[]','壶山好，文字满胸中。',64,'宋词/ci.song.13000.json','["壶山好，文字满胸中。", "诗律变成长庆体，歌词渐有稼轩风。", "最会说穷通。", "中年后，虽老未成翁。", "儿大相传书种在，客来不放酒尊空。", "相对醉颜红。"]'),
('song-ci-299','望江南・忆江南','戴复古','宋','宋词','song-ci','望江南・忆江南','[]','壶山好，也解忆狂夫。',64,'宋词/ci.song.13000.json','["壶山好，也解忆狂夫。", "转首便成千里别，经年不寄一行书。", "浑似不相疏。", "催归曲，一唱一愁予。", "有剑卖来酤酒吃，无钱归去买山居。", "安处即吾庐。"]'),
('song-ci-300','望江南・忆江南','戴复古','宋','宋词','song-ci','望江南・忆江南','[]','石屏老，家住海东云。',64,'宋词/ci.song.13000.json','["石屏老，家住海东云。", "本是寻常田舍子，如何呼唤作诗人。", "无益费精神。", "千首富，不救一生贫。", "贾岛形模元自瘦，杜陵言语不妨村。", "谁解学西崑。"]'),
('song-ci-301','望江南・忆江南','戴复古','宋','宋词','song-ci','望江南・忆江南','[]','石屏老，长忆少年游。',64,'宋词/ci.song.13000.json','["石屏老，长忆少年游。", "自谓虎头须食肉，谁知猿臂不封侯。", "身世一虚舟。", "平生事，说着也堪羞。", "四海九州双脚底，千愁万恨两眉头。", "白发早归休。"]'),
('song-ci-302','望江南・忆江南','戴复古','宋','宋词','song-ci','望江南・忆江南','[]','石屏老，悔不住山林。',64,'宋词/ci.song.13000.json','["石屏老，悔不住山林。", "注定一生知有命，老来万事付无心。", "巧语不如喑。", "贫亦乐，莫负好光阴。", "但愿有头生白发，何忧无地觅黄金。", "遇酒且须斟。"]'),
('song-ci-303','清平乐','戴复古','宋','宋词','song-ci','清平乐','[]','今朝欲去。',54,'宋词/ci.song.13000.json','["今朝欲去。", "忽有留人处。", "说与江头杨柳树。", "系我扁舟且住。", "十分酒兴诗肠。", "难禁冷落秋光。", "借取春风一笑，狂夫到老犹狂。"]'),
('song-ci-304','醉太平','戴复古','宋','宋词','song-ci','醉太平','[]','长亭短亭。',46,'宋词/ci.song.13000.json','["长亭短亭。", "春风酒醒。", "无端惹起离情。", "有黄鹂数声。", "芙蓉绣茵。", "江山画屏。", "梦中昨夜分明。", "悔先行一程。"]'),
('song-ci-305','满庭芳','戴复古','宋','宋词','song-ci','满庭芳','[]','草木生春，楼台不夜，团团月上云霄。',118,'宋词/ci.song.13000.json','["草木生春，楼台不夜，团团月上云霄。", "太平官府，民物共逍遥。", "指点江梅一笑，几番负、雨秀风娇。", "今年好，花边把酒，歌舞醉元宵。", "风流，贤太守，青云志气，玉树丰标。", "是神仙班里，旧日王乔。", "出奉板舆行乐，金莲照、十里笙箫。", "收灯后，看看丹诏，催入圣明朝。"]'),
('song-ci-306','渔父・渔歌子','戴复古','宋','宋词','song-ci','渔父・渔歌子','[]','渔父饮，不须钱。',22,'宋词/ci.song.13000.json','["渔父饮，不须钱。", "柳枝斜贯锦鳞鲜。", "换酒却归船。"]'),
('song-ci-307','渔父・渔歌子','戴复古','宋','宋词','song-ci','渔父・渔歌子','[]','渔父醉，钓竿闲。',22,'宋词/ci.song.13000.json','["渔父醉，钓竿闲。", "柳下呼儿牢系船。", "高眠风月天。"]'),
('song-ci-308','渔父・渔歌子','戴复古','宋','宋词','song-ci','渔父・渔歌子','[]','渔父醒，荻花洲。',22,'宋词/ci.song.13000.json','["渔父醒，荻花洲。", "三千六百钓鱼钩。", "从头下复休。"]'),
('song-ci-309','渔父・渔歌子','戴复古','宋','宋词','song-ci','渔父・渔歌子','[]','渔父笑，笑何人。',22,'宋词/ci.song.13000.json','["渔父笑，笑何人。", "古来豪杰尽成尘。", "江山秋复春。"]'),
('song-ci-310','沁园春','戴复古','宋','宋词','song-ci','沁园春','["\u8861\u5c71"]','访衡山之顶，雪鸿渺渺，湘江之上，梅竹娟娟。',39,'宋词/ci.song.13000.json','["访衡山之顶，雪鸿渺渺，湘江之上，梅竹娟娟。", "寄语波臣，传言鸥鹭，稳护渠侬书画船。"]'),
('song-ci-311','祝英台近','戴复古妻','宋','宋词','song-ci','祝英台近','[]','惜多才，怜薄命，无计可留汝。',95,'宋词/ci.song.13000.json','["惜多才，怜薄命，无计可留汝。", "揉碎花笺，忍写断肠句。", "道傍杨柳依依，千丝万缕，抵不住、一分愁绪。", "如何诉。", "便教缘尽今生，此身已轻许。", "捉月盟言，不是梦中语。", "后回君若重来，不相忘处，把杯酒、浇奴坟土。"]'),
('song-ci-312','玉楼春','李子酉','宋','宋词','song-ci','玉楼春','[]','纱窗春睡朦胧著。',64,'宋词/ci.song.13000.json','["纱窗春睡朦胧著。", "相见尚怀相别恶。", "梦随城上角声残，泪逐楼前花片落。", "东风不解吹愁却。", "明月几番乖后约。", "当时惟恐不多情，今日情多无处著。"]'),
('song-ci-313','醉太平','徐梦龙','宋','宋词','song-ci','醉太平','[]','冰肌玉容。',46,'宋词/ci.song.13000.json','["冰肌玉容。", "情真意浓。", "小楼几度春风。", "醉琉璃酒钟。", "关山万重。", "何时又逢。", "思量雨迹云踪。", "似襄王梦中。"]'),
('song-ci-314','浣溪沙','赵扩','宋','宋词','song-ci','浣溪沙','[]','花似醺容上玉肌。',48,'宋词/ci.song.13000.json','["花似醺容上玉肌。", "方论时事却嫔妃。", "芳阴人醉漏声迟。", "珠箔半钩风乍暖，雕梁新语燕初飞。", "斜阳犹送水精卮。"]'),
('song-ci-315','西江月','方信孺','宋','宋词','song-ci','西江月','[]','碧洞青崖著雨，红泉白石生寒。',58,'宋词/ci.song.13000.json','["碧洞青崖著雨，红泉白石生寒。", "朅来十月九湖山。", "人笑元郎太漫。", "绝壑偏宜叠鼓，夕阳休唤归鞍。", "兹游未必胜骖鸾。", "聊作湖南公案。"]'),
('song-ci-316','失调名','龚大明','宋','宋词','song-ci','失调名','[]','山居好。',32,'宋词/ci.song.13000.json','["山居好。", "山居好。", "鹤唳猿啼饯昏晓。", "碧窗柏子炷炉香，跌坐蒲团诵黄老。"]'),
('song-ci-317','失调名','龚大明','宋','宋词','song-ci','失调名','[]','山居好。',32,'宋词/ci.song.13000.json','["山居好。", "山居好。", "门对青山水环绕。", "一榻烟霞梦寐清，我以不贪为至宝。"]'),
('song-ci-318','失调名','龚大明','宋','宋词','song-ci','失调名','[]','山居好。',32,'宋词/ci.song.13000.json','["山居好。", "山居好。", "竹杖芒鞋恣幽讨。", "坐分苔石树阴凉，闲数落花听啼鸟。"]'),
('song-ci-319','失调名','龚大明','宋','宋词','song-ci','失调名','[]','山居好。',32,'宋词/ci.song.13000.json','["山居好。", "山居好。", "斫月锄云种瑶草。", "泠泠碧涧响寒泉，簌簌落花风自扫。"]'),
('song-ci-320','失调名','龚大明','宋','宋词','song-ci','失调名','[]','清高绝，雪崖翁。',32,'宋词/ci.song.13000.json','["清高绝，雪崖翁。", "向上玄机顿观通。", "金鼎有丹成九转，凝然宴坐白云中。"]'),
('song-ci-321','西江月','龚大明','宋','宋词','song-ci','西江月','[]','我本无为野客，飘飘浪迹人间。',58,'宋词/ci.song.13000.json','["我本无为野客，飘飘浪迹人间。", "一时被命住名山。", "未免随机应变。", "识破尘劳扰扰，何如乐取清闲。", "流霞细酌咏诗篇。", "且与白云为伴。"]'),
('song-ci-322','水调歌头','陈楠','宋','宋词','song-ci','水调歌头','[]','夺取天机妙，夜半看辰杓。',114,'宋词/ci.song.13000.json','["夺取天机妙，夜半看辰杓。", "一些珠露，阿谁运倒稻花头。", "便向此时采取，宛如碧莲合蕊，滴破玉池秋。", "万籁风初起，明月一沙鸥。", "紫河车，乘赤凤，入琼楼。", "谓之玉汞，与铅与土正相投。", "五气三花聚顶，吹著自然真火，炼得似红榴。", "十月胎仙出，雷电送金虬。"]'),
('song-ci-323','鹊桥仙','陈楠','宋','宋词','song-ci','鹊桥仙','[]','红莲含蕊，露珠凝碧，飞落华池滴滴。',68,'宋词/ci.song.13000.json','["红莲含蕊，露珠凝碧，飞落华池滴滴。", "运归金鼎唤丁公，炼得似、一枚朱橘。", "三花喷火，五云拥月，上有金胎神室。", "洞房云雨正春风，十个月、胎仙了毕。"]'),
('song-ci-324','真珠帘','陈楠','宋','宋词','song-ci','真珠帘','[]','金丹大药人人有。',119,'宋词/ci.song.13000.json','["金丹大药人人有。", "要须是、心传口授。", "一片白龙肝，一盏醍醐酒。", "只为离无寻坎有。", "移却南宸回北斗。", "好笑。", "见金翁姹女，两个厮斗。", "些儿铅汞调匀，观汉月海潮，抽添火候。", "一箭透三关，方表神仙手。", "兔子方来乌处住，龟儿便把蛇吞了。", "知否。", "那两个锺吕，是吾师友。"]'),
('song-ci-325','望江南・忆江南','陈楠','宋','宋词','song-ci','望江南・忆江南','[]','黄中宝，须向胆中求。',64,'宋词/ci.song.13000.json','["黄中宝，须向胆中求。", "春气令人生万物，乾坤膝下与吾俦。", "百脉自通流。", "施造化，左右火双抽。", "浩浩腾腾光宇宙，苦烟烟上霭环楼。", "夫妇渐相谋。"]'),
('song-ci-326','望江南・忆江南','陈楠','宋','宋词','song-ci','望江南・忆江南','[]','玄珠降，丹窟在中宫。',64,'宋词/ci.song.13000.json','["玄珠降，丹窟在中宫。", "九候息调重九数，赤波或进太阳东。", "心肾遂交通。", "逢六变，重六息阴功。", "火自海门朝帝坐，水从莲萼佐丁公。", "紫电透玲珑。"]'),
('song-ci-327','望江南・忆江南','陈楠','宋','宋词','song-ci','望江南・忆江南','[]','毛发薄，三转运行阳。',64,'宋词/ci.song.13000.json','["毛发薄，三转运行阳。", "胎色渐红阴渐缩，推移岁运助阳刚。", "育火养中央。", "成物象，五转辨微茫。", "出入尚迟形上小，晨昏时饮玉壶浆。", "天籁奏笙簧。"]'),
('song-ci-328','望江南・忆江南','陈楠','宋','宋词','song-ci','望江南・忆江南','[]','丹已返，四转运行阴。',64,'宋词/ci.song.13000.json','["丹已返，四转运行阴。", "逢六闭藏阳户气，三关全透合丁壬。", "龟游任浮沉。", "时出入，无碍贯他心。", "游戏神通常出面，圆光周匝绕千寻。", "寒暑不相侵。"]'),
('song-ci-329','望江南・忆江南','陈楠','宋','宋词','song-ci','望江南・忆江南','[]','珠自右，紫电入丹城。',64,'宋词/ci.song.13000.json','["珠自右，紫电入丹城。", "内养婴儿成赤象，时逢五转采阳精。", "火自水中生。", "烧鬼岳，紫电起峥嵘。", "随意嬉游寰海内，寐如砂碛卧长鲸。", "时序与偕行。"]'),
('song-ci-330','望江南・忆江南','陈楠','宋','宋词','song-ci','望江南・忆江南','[]','日精满，阴魄化无形。',64,'宋词/ci.song.13000.json','["日精满，阴魄化无形。", "每遇月圆开地户，神龟时饮碧瑶精。", "清洁复如冰。", "阳砂赤，阴粉色微青。", "粉换肉兮砂换骨，凡胎换尽圣胎灵。", "飞举似流星。"]'),
('song-ci-331','望江南・忆江南','陈楠','宋','宋词','song-ci','望江南・忆江南','[]','形透日，七转任飞腾。',64,'宋词/ci.song.13000.json','["形透日，七转任飞腾。", "幽静深岩图宴坐，息无来往气坚凝。", "却粒著其能。", "生成火，返本气澄清。", "九候浴时开地户，月中取火日求冰。", "五内换重新。"]'),
('song-ci-332','望江南・忆江南','陈楠','宋','宋词','song-ci','望江南・忆江南','[]','内外变，八转始还元。',64,'宋词/ci.song.13000.json','["内外变，八转始还元。", "地带长垂主坎户，周行胎息贯天门。", "太始道方存。", "纯一体，赤黑气常喷。", "丹火发时烧内景，冷泉涌处浴猴孙。", "神水赤龟吞。"]'),
('song-ci-333','失调名','史弥巩','宋','宋词','song-ci','失调名','[]','羊左合人我。',44,'宋词/ci.song.13000.json','["羊左合人我。", "左既绝粮甘自饿。", "羊仕楚王官职大。", "依旧杀身蓬颗。", "颜公畴昔曾经过。", "佳咏至今传播。"]'),
('song-ci-334','水调歌头','徐鹿卿','宋','宋词','song-ci','水调歌头','[]','廊庙补天手，夷夏想威名。',114,'宋词/ci.song.13000.json','["廊庙补天手，夷夏想威名。", "上前张胆明目，倾倒汉公卿。", "二百年来章贡，前赵后萧相□，今古两豪英。", "四海望霖雨，可但总祥刑。", "自儿时，文字里，已心倾。", "魁躔邈在霄汉，薄宦偶趋承。", "山见崆峒秀丽，水见玉虹清绝，犹愿见先生。", "寄语二三子，洙泗在江城。"]'),
('song-ci-335','酹江月・念奴娇','徐鹿卿','宋','宋词','song-ci','酹江月・念奴娇','[]','雪销平野，正云开天宇，灯辉花市。',120,'宋词/ci.song.13000.json','["雪销平野，正云开天宇，灯辉花市。", "明灭吐吞无尽藏，巧斗飞桥激水。", "铁马响冰，牙旗穿夜，箫鼓声歌沸。", "丰年欢笑，酿成千里和气。", "相欢交□游嬉，卖薪买酒，歌舞升平里。", "记得前年随玉辇，吹下天香扑鼻。", "璧月腾辉，仙球稳缒，归有传柑遗。", "来年此夜，通明仍许归侍。"]'),
('song-ci-336','水调歌头','徐鹿卿','宋','宋词','song-ci','水调歌头','[]','岭峤转和气，英簜挟新凉。',114,'宋词/ci.song.13000.json','["岭峤转和气，英簜挟新凉。", "登车搅辔慷慨，风采肃台纲。", "第一澄清官府，次第咨询民瘼，馀事到囷仓。", "谨勿养稂莠，莠盛稻苗伤。", "金芝秀，蒲涧碧，荔枝香。", "此中风味不恶，暂借使星光。", "毋薄炎荒瘴海，曾著广平李勉，归去□平章。", "唤起昔贤梦，千载续遗芳。"]'),
('song-ci-337','贺新郎','徐鹿卿','宋','宋词','song-ci','贺新郎','["\u957f\u6c5f"]','解组轻千里。',141,'宋词/ci.song.13000.json','["解组轻千里。", "趁朝来、风高气爽，波平如砥。", "试问馀恩深几许，江阔秋清无底。", "看两径、棠阴舞翠。", "明月归艎轻似叶，只梅花、香里诗千纸。", "端不愧，西江水。", "谪仙才气兰亭字。", "更清姿雅度，修竹长松标致。", "官职几人曾此过，萱草春风谁似。", "任彩服、蹁跹娱戏。", "去此云霄真一握，算令公、勋业浑馀事。", "中书考，从今始。"]'),
('song-ci-338','减字木兰花','徐鹿卿','宋','宋词','song-ci','减字木兰花','[]','狂吟江浦。',52,'宋词/ci.song.13000.json','["狂吟江浦。", "不食人间烟火语。", "韦曲名家。", "也试河阳一县花。", "群仙推去。", "暂寄岭梅清绝处。", "笑俯清溪。", "只有清风明月知。"]'),
('song-ci-339','减字木兰花','徐鹿卿','宋','宋词','song-ci','减字木兰花','[]','云横远浦。',52,'宋词/ci.song.13000.json','["云横远浦。", "一段秋光烦著语。", "月下谁家。", "丹桂迎风一两花。", "双凫来去。", "不踏人间风日处。", "才入云溪。", "问我来时总不知。"]'),
('song-ci-340','酹江月・念奴娇','徐鹿卿','宋','宋词','song-ci','酹江月・念奴娇','[]','薰风有意，还年年吹下，九天纶绋。',120,'宋词/ci.song.13000.json','["薰风有意，还年年吹下，九天纶绋。", "庾岭高哉知几仞，不隔清名突兀。", "明月扁舟，图书之外，所载无南物。", "襄公往矣，辽辽直到今日。", "南来北地开藩，甘棠好在，一夜春光入。", "父老欢迎相告语，依旧朱颜绿发。", "四海无波，四江无讼，是先生清德。", "岭梅迎笑，和羹□□消息。"]'),
('song-ci-341','水调歌头','徐鹿卿','宋','宋词','song-ci','水调歌头','[]','五剡乃脱选，通籍入金闺。',114,'宋词/ci.song.13000.json','["五剡乃脱选，通籍入金闺。", "祖宗立法初意，正欲猎英奇。", "近世流风薄矣，强者立跻霄汉，弱者困尘泥。", "流水伯牙操，底处有锺期。", "公为政，民不扰，吏无欺。", "春风桃李满县，当路几人知。", "五马宏开公道，一鹗首旌治最，迟乃速之基。", "不枉受人荐，更看荐人时。"]'),
('song-ci-342','水调歌头','徐鹿卿','宋','宋词','song-ci','水调歌头','[]','别驾映旋轸，父老绕称觥。',114,'宋词/ci.song.13000.json','["别驾映旋轸，父老绕称觥。", "西风底事于役，造物岂无情。", "知道神生崧岳，大庾岭边和气，未足助欢声。", "小试活人手，详谳命公行。", "赣滩石，青原雨，快阁晴。", "西江一带风物，尽把祝长生。", "福与此江无尽，寿与此江俱远，名与此江清。", "江水直到海，公亦上蓬瀛。"]'),
('song-ci-343','汉宫春','徐鹿卿','宋','宋词','song-ci','汉宫春','["\u897f\u6e56"]','庾岭梅花，到江空岁晚，始放南枝。',118,'宋词/ci.song.13000.json','["庾岭梅花，到江空岁晚，始放南枝。", "岂徒冰雪蹊径，不受侵欺。", "孤高自负，尽炎凉、变态无期。", "便瘴雨、蛮烟如许，淡妆也不随时。", "未肯移根上苑，且竹边院落，月下园篱。", "除却西湖句子，此后无诗。", "向□红紫，要十分、妩媚因谁。", "算只有、天怜清苦，纷纷蜂蝶争知。"]'),
('song-ci-344','汉宫春','徐鹿卿','宋','宋词','song-ci','汉宫春','[]','吏隐南昌，问盘根几世，长子孙枝。',118,'宋词/ci.song.13000.json','["吏隐南昌，问盘根几世，长子孙枝。", "仙风道骨如此，信不吾欺。", "素姿倾国，□难昏、坐觉愆期。", "算好与、水仙作配，又还恨不同时。", "岁晚寻盟有几，早兰辞湘浦，竹谢东篱。", "自向月中弄影，雪里评诗。", "角声吹动，这一天、清兴关谁。", "刚唤起、赤松孤竹，此心惟许君知。"]'),
('song-ci-345','满江红','徐鹿卿','宋','宋词','song-ci','满江红','[]','斗大横江，旧曾著、周程夫子。',58,'宋词/ci.song.13000.json','["斗大横江，旧曾著、周程夫子。", "谭道处，疏梅迎笑，双松延翠。", "百载高风勤景仰，数椽老屋重经始。", "更大书、留与后人看，公归矣。"]'),
('song-ci-346','木兰花・玉楼春','邹应龙','宋','宋词','song-ci','木兰花・玉楼春','[]','吾家二老。',52,'宋词/ci.song.13000.json','["吾家二老。", "前有高平生癸卯。", "若到今辰。", "讵止荣华九十龄。", "共惟伯母。", "九十新年还又五。", "五五相承。", "好看重逢乙已春。"]'),
('song-ci-347','鹧鸪天','邹应龙','宋','宋词','song-ci','鹧鸪天','[]','九十吾家两寿星。',64,'宋词/ci.song.13000.json','["九十吾家两寿星。", "今夫人赛昔夫人。", "百年转眼新开帙，十月循环小有春。", "生日到，转精神。", "目光如镜步如云。", "年年长侍华堂宴，子子孙孙孙又孙。"]'),
('song-ci-348','鹧鸪天','邹应龙','宋','宋词','song-ci','鹧鸪天','[]','寿母开年九十三。',64,'宋词/ci.song.13000.json','["寿母开年九十三。", "佳辰就养大江南。", "缇屏晃耀新宁国，绣斧斓斑老朴庵。", "倾玉斝，擘黄柑。", "两孙垂绶碧於蓝。", "便当刊颂崆峒顶，留与千年作美谈。"]'),
('song-ci-349','鹧鸪天','邹应龙','宋','宋词','song-ci','鹧鸪天','["\u897f\u6e56"]','帝里风光别是天。',64,'宋词/ci.song.13000.json','["帝里风光别是天。", "花如锦绣柳如烟。", "还逢令节春三二，又庆慈闱岁八千。", "斟寿斝，列长筵。", "子孙何以咏高年。", "各裒千首西湖什，一度生朝献一篇。"]'),
('song-ci-350','鹧鸪天','邹应龙','宋','宋词','song-ci','鹧鸪天','[]','彩结轻车五马随。',64,'宋词/ci.song.13000.json','["彩结轻车五马随。", "倾城争出看花枝。", "笙歌十里岩前去，灯火千门月下归。", "莲炬引，老莱衣。", "蛾眉无数卷帘窥。", "谁知万里逢灯夕，却胜寻常三五时。"]'),
('song-ci-351','卜算子','邹应龙','宋','宋词','song-ci','卜算子','[]','满二望三时，春景方明媚。',52,'宋词/ci.song.13000.json','["满二望三时，春景方明媚。", "又见蟠桃结子来，王母初筵启。", "无数桂林山，不尽漓江水。", "总入今朝祝寿杯，永保千千岁。"]'),
('song-ci-352','感皇恩','邹应博','宋','宋词','song-ci','感皇恩','[]','觅得个州儿，稍供彩戏。',81,'宋词/ci.song.13000.json','["觅得个州儿，稍供彩戏。", "多谢天公为排备。", "一轮明月，酝作清廉滋味。", "倾入寿杯里，何妨醉。", "我有禄书，呈母年万计。", "八十三那里暨。", "便和儿算，恰一百四十地。", "这九千馀岁，长随侍。"]'),
('song-ci-353','鹧鸪天','邹应博','宋','宋词','song-ci','鹧鸪天','[]','天遣丰年祝母龄。',64,'宋词/ci.song.13000.json','["天遣丰年祝母龄。", "人人安业即安亲。", "探支十日新阳福，来献千秋古佛身。", "儿捧盏，妇倾瓶。", "更欣筵上有嘉宾。", "紫驼出釜双台馈，玉节升堂两使星。"]'),
('song-ci-354','鹧鸪天','邹应博','宋','宋词','song-ci','鹧鸪天','[]','诸佛林中女寿星。',64,'宋词/ci.song.13000.json','["诸佛林中女寿星。", "千祥百福产心田。", "喜归王母初生地，满劝麻姑不老泉。", "吾梦佛，半千员。", "一年一佛护庭萱。", "数过九十从头数，四百馀零一十年。"]'),
('song-ci-355','浪淘沙','黄某','宋','宋词','song-ci','浪淘沙','[]','八十加三迎九十，还似婴童。',13,'宋词/ci.song.13000.json','["八十加三迎九十，还似婴童。"]'),
('song-ci-356','醉落魄・一斛珠','叶秀发','宋','宋词','song-ci','醉落魄・一斛珠','[]','胸襟洒落。',67,'宋词/ci.song.13000.json','["胸襟洒落。", "光风霁月澄寥廓。", "生平素志惟丘壑。", "随分田园，花木四时乐。", "儿孙不用千金橐。", "吾家自有诗书粕。", "生朝有酒团栾酌。", "因笑渠侬，痴呆画松鹤。"]'),
('song-ci-357','贺新郎','李刘','宋','宋词','song-ci','贺新郎','["\u9ec4\u6cb3"]','鹄立通明殿。',141,'宋词/ci.song.13000.json','["鹄立通明殿。", "又重逢、揆余初度，梦庚华旦。", "不学花奴簪红槿，且看秋香宜晚。", "任甲子、从新重换。", "天欲东都修车马，故降神生甫维周翰。", "歌崧岳，咏江汉。", "明堂朝罢夷琛献。", "引星辰、万人共听，风尘长算。", "清昼山东诸将捷，席卷黄河两岸。", "问谁在、玉皇香案。", "师保万民功业别，向西京、原庙行圭瓒。", "定郏鄏，卜瀍涧。"]'),
('song-ci-358','鱼游春水','李刘','宋','宋词','song-ci','鱼游春水','[]','湖南三千里。',106,'宋词/ci.song.13000.json','["湖南三千里。", "百万人家争送喜。", "元戎初度，和气水流山峙。", "荆楚中间寿域开，翼轸傍边台躔起。", "崧岳降神，维箕骑尾。", "见说君王注倚。", "问舟楫、盐梅谁是。", "国人争望周公，东归几几。", "功名多载旗常上，福禄平分天壤里。", "家家弦管，年年弧矢。"]'),
('song-ci-359','水调歌头','李刘','宋','宋词','song-ci','水调歌头','[]','万里碧鸡使，叱驭问邛崃。',114,'宋词/ci.song.13000.json','["万里碧鸡使，叱驭问邛崃。", "枪旗有烨，川秦奔走送龙媒。", "好在灵均初度，唤起长庚佳梦，霜月照金罍。", "寿似武侯柏，香在草堂梅。", "舞娉婷，斟凿落，沃崔嵬。", "神尧孙子，向来八九上三台。", "挂了桑弧蓬矢，便恐彤弓秬瓒，分宝下天阶。", "归赋梁园雪，试唤长卿来。"]'),
('song-ci-360','酹江月・念奴娇','李刘','宋','宋词','song-ci','酹江月・念奴娇','[]','汉庭用老，想君王也忆、潜郎白首。',120,'宋词/ci.song.13000.json','["汉庭用老，想君王也忆、潜郎白首。", "底事煌煌金玉节，奔走天涯许久。", "江右风流，湖南清绝，更借诗翁手。", "明年七十，人间此事希有。", "固是守得堂间，鲂斋亭下，要称归来柳。", "上恐夜深□贾傅，便有锋车迎候。", "寿岳峰前，寿星池畔，且寿长沙酒。", "期颐三万，祖风应管依旧。"]'),
('song-ci-361','满庭芳','李刘','宋','宋词','song-ci','满庭芳','[]','郑履声传，倪经业绍，半千贤运重开。',118,'宋词/ci.song.13000.json','["郑履声传，倪经业绍，半千贤运重开。", "妙年阔步，高折桂枝回。", "卿月郎星历遍，都贪把、符竹南来。", "棠阴永，仍持玉节，臬事副钦哉。", "吾生，真幸会，旧家桃李，曾费栽培。", "更春风次第，吹到寒荄。", "遥望绂麟祥旦，霄躔邈、阻奉琅杯。", "谁知道，清源路远，直上即蓬莱。"]'),
('song-ci-362','生查子','李刘','宋','宋词','song-ci','生查子','[]','湘江贯地维，衡岳生人杰。',48,'宋词/ci.song.13000.json','["湘江贯地维，衡岳生人杰。", "谁遣益州星，暂伴峨眉月。", "初度庆今朝，绣斧双龙节。", "为国罩嘉鱼，趣觐黄金阙。"]'),
('song-ci-363','浣溪沙','李刘','宋','宋词','song-ci','浣溪沙','[]','濯锦江边玉树明。',48,'宋词/ci.song.13000.json','["濯锦江边玉树明。", "碧油幢里彩衣荣。", "当年此日下长庚。", "细酌成都千岁酒，闲看嶰谷一阳春。", "归听云母隔屏声。"]'),
('song-ci-364','朝中措','李刘','宋','宋词','song-ci','朝中措','[]','我生辰在斗牛中。',57,'宋词/ci.song.13000.json','["我生辰在斗牛中。", "井路有何功。", "运转峨眉山月，按行雪界天风。", "归欤老矣，愁添鬓白，酒借颜红。", "丘壑堪容我辈，轩裳分付诸公。"]'),
('song-ci-365','水调歌头','李刘','宋','宋词','song-ci','水调歌头','[]','端正九秋月，今夜始生明。',114,'宋词/ci.song.13000.json','["端正九秋月，今夜始生明。", "扬辉毓秀，飘然海上跨长鲸。", "认得灵均初度，直用望舒为御，重耀紫枢庭。", "何事乘槎使，尚藉执珪卿。", "合东西，瞻使节，镜中行。", "腾腾渐渐，绕枝乌鹊不须惊。", "太白擒胡了未，即墨降城安否，玉斧仗修成。", "圆却山河影，捣药兔长生。"]'),
('song-ci-366','鹧鸪天','李刘','宋','宋词','song-ci','鹧鸪天','[]','恰则重阳信宿前。',64,'宋词/ci.song.13000.json','["恰则重阳信宿前。", "菊潭先寿濮阳仙。", "暂陪明月清风夜，共醉孤云落照边。", "群玉府，紫微天。", "看看东壁二星连。", "月中斫桂吴夫子，定是长生不记年。"]'),
('song-ci-367','生查子','李刘','宋','宋词','song-ci','生查子','[]','万里彩衣远，旬日黄花后。',48,'宋词/ci.song.13000.json','["万里彩衣远，旬日黄花后。", "蓬矢纪佳辰，莲幕翻新奏。", "更看桂枝香，归献灵椿寿。", "同对小蟠桃，共醉长生酒。"]'),
('song-ci-368','念奴娇','郑清之','宋','宋词','song-ci','念奴娇','[]','楚天霜晓，看老来秋圃，寒花犹在。',120,'宋词/ci.song.13000.json','["楚天霜晓，看老来秋圃，寒花犹在。", "金阙栽培端正色，全胜东篱风采。", "雅韵清虚，幽香淡泊，惟有陶家爱。", "由他尘世，落红愁处如海。", "多少风雨飘摇，夫君何素，晚节应难改。", "休道三闾曾旧识，轻把木兰相对。", "延桂同盟，索梅为友，不复娇春态。", "年年秋后，笑观芳草萧艾。"]'),
('song-ci-369','失调名','陈鹄','宋','宋词','song-ci','失调名','[]','莫待柳吹绵。',12,'宋词/ci.song.13000.json','["莫待柳吹绵。", "吹绵时杜鹃。"]'),
('song-ci-370','如梦令','李仲虺','宋','宋词','song-ci','如梦令','[]','门外数峰围绕。',40,'宋词/ci.song.13000.json','["门外数峰围绕。", "帖石路儿弯小。", "花老不禁风，委地乱红多少。", "人俏。", "人俏。", "隔叶数声啼鸟。"]'),
('song-ci-371','眼儿媚','黄简','宋','宋词','song-ci','眼儿媚','[]','画楼濒水翠梧阴。',58,'宋词/ci.song.13000.json','["画楼濒水翠梧阴。", "清夜理瑶琴。", "打窗风雨，逼帘烟月，种种关心。", "当时不道春无价，幽梦费重寻。", "难忘最是，鲛绡晕满，蟫锦香沉。"]'),
('song-ci-372','柳梢青','黄简','宋','宋词','song-ci','柳梢青','[]','病酒心情。',61,'宋词/ci.song.13000.json','["病酒心情。", "唤愁无限，可奈流莺。", "又是一年，花惊寒食，柳认清明。", "天涯翠巘层层。", "是多少、长亭短亭。", "倦倚东风，只凭好梦，飞到银屏。"]'),
('song-ci-373','玉楼春','黄简','宋','宋词','song-ci','玉楼春','[]','龟纹晓扇堆云母。',64,'宋词/ci.song.13000.json','["龟纹晓扇堆云母。", "日上彩阑新过雨。", "眉心犹带宝觥酲，耳性已通银字谱。", "密奁彩索看看午。", "晕素分红能几许。", "妆成挼镜问春风，比似庭花谁解语。"]'),
('song-ci-374','鹧鸪天','陈耆卿','宋','宋词','song-ci','鹧鸪天','[]','莫惜花前泥酒壶。',64,'宋词/ci.song.13000.json','["莫惜花前泥酒壶。", "沙场千步锦平铺。", "将军闲试临边手，按出吴宫小阵图。", "清露里，晓霜馀。", "娇红淡白更怜渠。", "人间落木萧萧下，独倚秋江画不如。"]'),
('song-ci-375','鹧鸪天','陈耆卿','宋','宋词','song-ci','鹧鸪天','[]','艳朵珍丛间舞衣。',64,'宋词/ci.song.13000.json','["艳朵珍丛间舞衣。", "蹴球场外打红围。", "小舆穿入花深处，且住簪花醉一卮。", "秋欲尽，最怜伊。", "江梅未破菊离披。", "情知不与韶华竞，回首西风怨阿谁。"]'),
('song-ci-376','玉漏迟','林表民','宋','宋词','song-ci','玉漏迟','[]','并湖游冶路。',115,'宋词/ci.song.13000.json','["并湖游冶路。", "垂堤万柳，麴尘笼雾。", "草色将春，离思暗伤南浦。", "旧日愔愔坊陌，尚想得、画楼窗户。", "成远阻。", "凤笺空寄，燕梁何许。", "凄凉瘦损文园，记翠管联吟，玉壶通语。", "事逐征鸿，几度悲欢休数。", "莺醉乱花深里，悄难替、愁人分诉。", "空院宇。", "东风晚来吹雨。"]'),
('song-ci-377','渔父词・渔父','薛师石','宋','宋词','song-ci','渔父词・渔父','[]','十载江湖不上船。',32,'宋词/ci.song.13000.json','["十载江湖不上船。", "卷蓬高卧月明天。", "今夜泊，杏花湾。", "只有笭箵当酒钱。"]'),
('song-ci-378','渔父词・渔父','薛师石','宋','宋词','song-ci','渔父词・渔父','[]','邻家船上小姑儿。',32,'宋词/ci.song.13000.json','["邻家船上小姑儿。", "相问如何是别离。", "双坠髻，一湾眉。", "爱看红鳞比目鱼。"]'),
('song-ci-379','渔父词・渔父','薛师石','宋','宋词','song-ci','渔父词・渔父','[]','平明雾霭雨初晴。',32,'宋词/ci.song.13000.json','["平明雾霭雨初晴。", "儿子敲针作钓成。", "香饵小，茧丝轻。", "钓得鱼儿不识名。"]'),
('song-ci-380','渔父词・渔父','薛师石','宋','宋词','song-ci','渔父词・渔父','[]','船系兰芷鲙长鲈。',32,'宋词/ci.song.13000.json','["船系兰芷鲙长鲈。", "曲袷方袍忽访吾。", "神甚爽，貌全枯。", "莫是当年楚大夫。"]'),
('song-ci-381','渔父词・渔父','薛师石','宋','宋词','song-ci','渔父词・渔父','[]','春融水暖百花开。',32,'宋词/ci.song.13000.json','["春融水暖百花开。", "独棹扁舟过钓台。", "鸥与鹭，莫相猜。", "不是逃名不肯来。"]'),
('song-ci-382','渔父词・渔父','薛师石','宋','宋词','song-ci','渔父词・渔父','[]','夜来采石渡头眠。',32,'宋词/ci.song.13000.json','["夜来采石渡头眠。", "月下相逢李谪仙。", "歌一曲，别无言。", "白鹤飞来雪满船。"]'),
('song-ci-383','渔父词・渔父','薛师石','宋','宋词','song-ci','渔父词・渔父','[]','莫论轻重钓竿头。',32,'宋词/ci.song.13000.json','["莫论轻重钓竿头。", "住得船归即便休。", "酒味薄，胜空瓯。", "事事何须著意求。"]'),
('song-ci-384','绮罗香','史达祖','宋','宋词','song-ci','绮罗香','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','做冷欺花，将烟困柳，千里偷催春暮。',128,'宋词/ci.song.13000.json','["做冷欺花，将烟困柳，千里偷催春暮。", "尽日冥迷，愁里欲飞还住。", "惊粉重、蝶宿西园，喜泥润、燕归南浦。", "最妨它、佳约风流，钿车不到杜陵路。", "沈沈江上望极，还被春潮晚急，难寻官渡。", "隐约遥峰，和泪谢娘眉妩。", "临断岸、新绿生时，是落红、带愁流处。", "记当日、门掩梨花，翦灯深夜语。"]'),
('song-ci-385','双双燕','史达祖','宋','宋词','song-ci','双双燕','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','过春社了，度帘幕中间，去年尘冷。',119,'宋词/ci.song.13000.json','["过春社了，度帘幕中间，去年尘冷。", "差池欲住，试入旧巢相并。", "还相雕梁藻井。", "又软语、商量不定。", "飘然快拂花梢，翠尾分开红影。", "芳径。", "芹泥雨润。", "爱贴地争飞，竞夸轻俊。", "红楼归晚，看足柳昏花暝。", "应自栖香正稳。", "便忘了、天涯芳信。", "愁损翠黛双蛾，日日画阑独凭。"]'),
('song-ci-386','阳春曲・阳春','史达祖','宋','宋词','song-ci','阳春曲・阳春','[]','杏花烟，梨花月，谁与晕开春色。',130,'宋词/ci.song.13000.json','["杏花烟，梨花月，谁与晕开春色。", "坊巷晓愔愔，东风断、旧火销处近寒食。", "少年踪迹。", "愁暗隔、水南山北。", "还是宝络雕鞍，被莺声、唤来香陌。", "记飞盖西园，寒犹凝结。", "惊醉耳、谁家夜笛。", "灯前重帘不挂，殢华裾、粉泪曾拭。", "如今故里信息。", "赖海燕、年时相识。", "奈芳草、正锁江南，梦春衫怨碧。"]'),
('song-ci-387','海棠春令・海棠春','史达祖','宋','宋词','song-ci','海棠春令・海棠春','[]','似红如白含芳意。',58,'宋词/ci.song.13000.json','["似红如白含芳意。", "锦宫外、烟轻雨细。", "燕子不知愁，惊堕黄昏泪。", "烛花偏在红帘底。", "想人怕、春寒正睡。", "梦著玉环娇，又被东风醉。"]'),
('song-ci-388','夜行船','史达祖','宋','宋词','song-ci','夜行船','[]','不翦春衫愁意态。',68,'宋词/ci.song.13000.json','["不翦春衫愁意态。", "过收灯、有些寒在。", "小雨空帘，无人深巷，已早杏花先卖。", "白发潘郎宽沈带。", "怕看山、忆它眉黛。", "草色拖裙，烟光惹鬓，常记故园挑菜。"]'),
('song-ci-389','东风第一枝','史达祖','宋','宋词','song-ci','东风第一枝','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','巧沁兰心，偷黏草甲，东风欲障新暖。',122,'宋词/ci.song.13000.json','["巧沁兰心，偷黏草甲，东风欲障新暖。", "谩凝碧瓦难留，信知暮寒轻浅。", "行天入镜，做弄出、轻松纤软。", "料故园、不卷重帘，误了乍来双燕。", "青未了、柳回白眼。", "红欲断、杏开素面。", "旧游忆著山阴，厚盟遂妨上苑。", "寒炉重暖，便放慢春衫针线。", "恐凤靴、挑菜归来，万一灞桥相见。"]'),
('song-ci-390','东风第一枝','史达祖','宋','宋词','song-ci','东风第一枝','[]','草脚愁苏，花心梦醒，鞭香拂散牛土。',123,'宋词/ci.song.13000.json','["草脚愁苏，花心梦醒，鞭香拂散牛土。", "旧歌空忆珠帘，彩笔倦题绣户。", "黏鸡贴燕，想立断、东风来处。", "暗惹起、一掬相思，乱若翠盘红缕。", "今夜觅、梦池秀句。", "明日动、探花芳绪。", "寄声沽酒人家，预约俊，游伴侣。", "怜它梅柳，乍忍俊、天街酥雨。", "待过了一月灯期，日日醉扶归去。"]'),
('song-ci-391','东风第一枝','史达祖','宋','宋词','song-ci','东风第一枝','[]','酒馆歌云，灯街舞绣，笑声喧似箫鼓。',123,'宋词/ci.song.13000.json','["酒馆歌云，灯街舞绣，笑声喧似箫鼓。", "太平京国多欢，大酺绮罗几处。", "东风不动，照花影、一天春聚。", "耀翠光、金缕相交，苒苒细吹香雾。", "羞醉玉、少年丰度。", "怀艳雪、旧家伴侣。", "闭门明月关心，倚窗小梅索句。", "吟情欲断，念娇俊、知人无据。", "想袖寒、珠络藏香，夜久带愁归去。"]'),
('song-ci-392','玉楼春','史达祖','宋','宋词','song-ci','玉楼春','[]','游人等得春晴也。',64,'宋词/ci.song.13000.json','["游人等得春晴也。", "处处旗亭堪系马。", "雨前秾杏尚娉婷，风后残梅无顾藉。", "忌拈针线还逢社。", "斗草赢多裙欲卸。", "明朝双燕定归来，叮嘱重帘休放下。"]'),
('song-ci-393','玉楼春','史达祖','宋','宋词','song-ci','玉楼春','[]','玉容寂寞谁为主。',64,'宋词/ci.song.13000.json','["玉容寂寞谁为主。", "寒食心情愁几许。", "前身清澹似梅妆，遥夜依微留月住。", "香迷胡蝶飞时路。", "雪在秋千来往处。", "黄昏著了素衣裳，深闭重门听夜雨。"]'),
('song-ci-394','喜迁莺','史达祖','宋','宋词','song-ci','喜迁莺','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','月波疑滴。',126,'宋词/ci.song.13000.json','["月波疑滴。", "望玉壶天近，了无尘隔。", "翠眼圈花，冰丝织练，黄道宝光相直。", "自怜诗酒瘦，难应接、许多春色。", "最无赖，是随香趁烛，曾伴狂客。", "踪迹。", "谩记忆。", "老了杜郎，忍听东风笛。", "柳院灯疏，梅厅雪在，谁与细倾春碧。", "旧情拘未定，犹自学、当年游历。", "怕万一，误玉人、夜寒帘隙。"]'),
('song-ci-395','万年欢','史达祖','宋','宋词','song-ci','万年欢','[]','两袖梅风，谢桥边、岸痕犹带阴雪。',122,'宋词/ci.song.13000.json','["两袖梅风，谢桥边、岸痕犹带阴雪。", "过了匆匆灯市，草根青发。", "燕子春愁未醒，误几处、芳音辽绝。", "烟溪上、采绿人归，定应愁沁花骨。", "非干厚情易歇。", "奈燕台句老，难道离别。", "小径吹衣，曾记故里风物。", "多少惊心旧事，第一是、侵阶罗袜。", "如今但、柳发晞春，夜来和露梳月。"]'),
('song-ci-396','阮郎归','史达祖','宋','宋词','song-ci','阮郎归','[]','龙香吹袖白藤鞭。',56,'宋词/ci.song.13000.json','["龙香吹袖白藤鞭。", "帽檐冲柳烟。", "一春几度画桥边。", "东风听管弦。", "花活计，酒因缘。", "从人嘲少年。", "真须吟就绿杨篇。", "湾头寄小怜。"]'),
('song-ci-397','阮郎归','史达祖','宋','宋词','song-ci','阮郎归','[]','旧时明月旧时身。',56,'宋词/ci.song.13000.json','["旧时明月旧时身。", "旧时梅萼新。", "旧时月底似梅人。", "梅春人不春。", "香入梦，粉成尘。", "情多多断魂。", "芙蓉孔雀夜温温。", "愁痕即泪痕。"]'),
('song-ci-398','眼儿媚','史达祖','宋','宋词','song-ci','眼儿媚','[]','潘郎心老不成春。',58,'宋词/ci.song.13000.json','["潘郎心老不成春。", "风味隔花尘。", "帘波浸笋，窗纱分柳，还过天津。", "近时无觅湘云处，不记是行人。", "楼高望远，应将秦镜，多照施颦。"]'),
('song-ci-399','眼儿媚','史达祖','宋','宋词','song-ci','眼儿媚','[]','儿家七十二鸳鸯。',58,'宋词/ci.song.13000.json','["儿家七十二鸳鸯。", "珠佩锁瑶箱。", "期花等月，秦台吹玉，贾袖传香。", "十年白玉堂前见，直是翦柔肠。", "将愁去也，不成今世，终误王昌。"]'),
('song-ci-400','忆瑶姬','史达祖','宋','宋词','song-ci','忆瑶姬','[]','娇月笼烟，下楚领、香分两朵湘云。',130,'宋词/ci.song.13000.json','["娇月笼烟，下楚领、香分两朵湘云。", "花房渐密时，弄杏笺初会，歌里殷勤。", "沈沈夜久西窗，屡隔兰灯幔影昏。", "自彩鸾、飞入芳巢，绣屏罗荐粉光新。", "十年未始轻分。", "念此飞花，可怜柔脆销春。", "空馀双泪眼，到旧家时郎谩染愁巾。", "袖止说道凌虚，一夜相思玉样人。", "但起来、梅发窗前，哽咽疑是君。"]'),
('song-ci-401','南歌子','史达祖','宋','宋词','song-ci','南歌子','[]','采绿随双桨，看山藉一筇。',62,'宋词/ci.song.13000.json','["采绿随双桨，看山藉一筇。", "关南桃树几番红。", "昨夜诗情频在、雨声中。", "花径无云隔，苔垣只梦通。", "旧欢一饷可过从。", "试觅鸳鸯新杏、简春风。"]'),
('song-ci-402','风流子','史达祖','宋','宋词','song-ci','风流子','[]','红楼横落日，萧郎去、几度碧云飞。',135,'宋词/ci.song.13000.json','["红楼横落日，萧郎去、几度碧云飞。", "记窗眼递香，玉台妆罢，马蹄敲月，沙路人归。", "如今但，一莺通信息，双燕说相思。", "入耳旧歌，怕听琴缕，断肠新句，羞染乌丝。", "相逢南溪上，桃花嫩、娇样浅澹罗衣。", "恰是怨深腮赤，愁重声迟。", "怅东风巷陌，草迷春恨，软尘庭户，花误幽期。", "多少寄来芳字，都待还伊。"]'),
('song-ci-403','风流子','史达祖','宋','宋词','song-ci','风流子','[]','飞琼神仙客，因游戏、误落古桃源。',135,'宋词/ci.song.13000.json','["飞琼神仙客，因游戏、误落古桃源。", "藉吟笺赋笔，试融春恨，舞裙歌扇，聊应尘缘。", "遣人怨，乱云天一角，弱水路三千。", "还因秀句，意流江外，便随轻梦，身堕愁边。", "风流休相误，寻芳纵来晚，尚有它年。", "只为赋情不浅，弹泪风前。", "想雾帐吹香，独怜奇俊，露杯分酒，谁伴婵娟。", "好在夜轩凉月，空自团圆。"]'),
('song-ci-404','金盏子','史达祖','宋','宋词','song-ci','金盏子','[]','奖绿催红，仰一番膏雨，始张春色。',124,'宋词/ci.song.13000.json','["奖绿催红，仰一番膏雨，始张春色。", "未踏画桥烟，江南岸、应是草秾花密。", "尚忆溅裙苹溪，觉诗愁相觅。", "光风外，除是倩莺烦燕，谩通消息。", "梨花夜来白。", "相思梦、空阑一林月。", "深深柳枝巷陌，难重遇、弓弯两袖云碧。", "见说倦理秦筝，怯春葱无力。", "空遣恨，当时留秀句，苍苔蠹壁。"]'),
('song-ci-405','杏花天','史达祖','宋','宋词','song-ci','杏花天','[]','软波拖碧蒲芽短。',65,'宋词/ci.song.13000.json','["软波拖碧蒲芽短。", "画桥外、花晴柳暖。", "今年自是清明晚。", "便觉芳情较懒。", "春衫瘦、东风翦翦。", "过花坞、香吹醉面。", "归来立马斜阳岸。", "隔岸歌声一片。"]'),
('song-ci-406','杏花天','史达祖','宋','宋词','song-ci','杏花天','[]','古城官道花如霰。',65,'宋词/ci.song.13000.json','["古城官道花如霰。", "便恰限、花间再见。", "双眉最现愁深浅。", "隔雨春山两点。", "回头但、垂杨带苑。", "想今夜、铜驼梦远。", "行人去了莺声怨。", "此度关心未免。"]'),
('song-ci-407','杏花天','史达祖','宋','宋词','song-ci','杏花天','[]','细风微月垂杨院。',65,'宋词/ci.song.13000.json','["细风微月垂杨院。", "记年少、春愁一点。", "栖莺未觉花梢颤。", "踏损残红几片。", "长安共、日边近远。", "况老去，芳情渐减。", "屏山几夜春寒浅。", "却将因而梦见。"]'),
('song-ci-408','杏花天','史达祖','宋','宋词','song-ci','杏花天','[]','扇香曾靠腮边粉。',65,'宋词/ci.song.13000.json','["扇香曾靠腮边粉。", "旧尘埋、月轮有晕。", "南风未似愁来近。", "前事临窗隐隐。", "凉花畔、云歌露饮。", "梦断了、终难再问。", "鸳鸯带上三生恨。", "将泪揩磨不尽。"]'),
('song-ci-409','三姝媚','史达祖','宋','宋词','song-ci','三姝媚','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','烟光摇缥瓦。',122,'宋词/ci.song.13000.json','["烟光摇缥瓦。", "望晴檐多风，柳花如洒。", "锦瑟横床，想泪痕尘影，凤弦常下。", "倦出犀帷，频梦见、王孙骄马。", "讳道相思，偷理绡裙，自惊腰衩。", "惆怅南楼遥夜。", "记翠箔张灯，枕肩歌罢。", "又入铜驼，遍旧家门巷，首询声价。", "可惜东风，将恨与、闲花俱谢。", "记取崔徽模样，归来暗写。"]'),
('song-ci-410','寿楼春','史达祖','宋','宋词','song-ci','寿楼春','[]','裁春衫寻芳。',124,'宋词/ci.song.13000.json','["裁春衫寻芳。", "记金刀素手，同在晴窗。", "几度因风残絮，照花斜阳。", "谁念我今无肠。", "自少年、消磨疏狂。", "但听雨挑灯，敧床病酒，多梦睡时妆。", "飞花去，良宵长。", "有丝阑旧曲，金谱新腔。", "最恨湘云人散，楚兰魂伤。", "身是客，愁为乡。", "算玉箫、犹逢韦郎。", "近寒食人家，相思未忘苹藻香。"]'),
('song-ci-411','于飞乐','史达祖','宋','宋词','song-ci','于飞乐','[]','绮翼□□，问谁常借春陂。',90,'宋词/ci.song.13000.json','["绮翼□□，问谁常借春陂。", "生愁近渚风微。", "紫山深，金殿暖，日暮同归。", "白头相守，情虽定、事却难期。", "带恨飞来，烟埋秦草，年年枉梦红衣。", "旧沙间，香颈冷，合是单栖。", "将终怨魂，何年化、连理芳枝。"]'),
('song-ci-412','南浦','史达祖','宋','宋词','song-ci','南浦','[]','玉树晓飞香，待倩它、和愁点破妆镜。',127,'宋词/ci.song.13000.json','["玉树晓飞香，待倩它、和愁点破妆镜。", "轻嫩一天春，平白地、都护雨昏烟暝。", "幽花露湿，定应独把阑干凭。", "谢屐未蜡，安排共文鹓，重游芳径。", "年来梦里扬州，怕事随歌残，情趁云冷。", "娇眄隔东风，无人会、莺燕暗中心性。", "深盟纵约，尽同晴雨全无定。", "海棠梦在，相思过西园，秋千红影。"]'),
('song-ci-413','探芳信','史达祖','宋','宋词','song-ci','探芳信','[]','谢池晓。',108,'宋词/ci.song.13000.json','["谢池晓。", "被酒滞春眠，诗萦芳草。", "正一阶梅粉，都未有人扫。", "细禽啼处东风软，嫩约关心早。", "未烧灯，怕有残寒，故园稀到。", "说道试妆了。", "也为我相思，占它怀抱。", "静数窗棂，最欢听鹊声好。", "半年白玉台边话，屡见钩小。", "指芳期，夜月花阴梦老。"]'),
('song-ci-414','祝英台近','史达祖','宋','宋词','song-ci','祝英台近','[]','柳枝愁，桃叶恨，前事怕重记。',95,'宋词/ci.song.13000.json','["柳枝愁，桃叶恨，前事怕重记。", "红药开时，新梦又溱洧。", "此情老去须休，春风多事。", "便老去、越难回避。", "阻幽会。", "应念偷翦酴醿，柔条暗萦系。", "节物移人，春暮更憔悴。", "可堪竹院题诗，藓阶听雨，寸心外、安愁无地。"]'),
('song-ci-415','祝英台近','史达祖','宋','宋词','song-ci','祝英台近','[]','绾流苏，垂锦绶。',95,'宋词/ci.song.13000.json','["绾流苏，垂锦绶。", "烟外红尘逗。", "莫倚莓墙，花气酽如酒。", "便愁醺醉青虬，蜿蜿无力，戏穿碎、一屏新绣。", "谩怀旧。", "如今姚魏俱无，风标较消瘦。", "露点摇香，前度翦花手。", "见郎和笑拖裙，匆匆欲去，蓦忽地、罥留芳袖。"]'),
('song-ci-416','祝英台近','史达祖','宋','宋词','song-ci','祝英台近','["\u897f\u6e56"]','落花深，芳草暗，春到断肠处。',95,'宋词/ci.song.13000.json','["落花深，芳草暗，春到断肠处。", "金勒骄风，欲过大堤去。", "翠楼葛领西边，恰如曾约，画阑映、一枝琼树。", "正凝伫。", "芳意欺月矜春，浑欲便偷许。", "多少莺声，不敢寄愁与。", "谢郎日日西湖，如今归后，几时见、倚帘吹絮。"]'),
('song-ci-417','钗头凤・撷芳词','史达祖','宋','宋词','song-ci','钗头凤・撷芳词','[]','春愁远。',76,'宋词/ci.song.13000.json','["春愁远。", "春梦乱。", "凤钗一股轻尘满。", "江烟白。", "江波碧。", "柳户清明，燕帘寒食。", "忆忆忆。", "莺声晓，箫声短。", "落花不许春拘管。", "新相识。", "休相失。", "翠陌吹衣，画楼横笛。", "得得得。"]'),
('song-ci-418','西江月','史达祖','宋','宋词','song-ci','西江月','[]','西月澹窥楼角，东风暗落檐牙。',58,'宋词/ci.song.13000.json','["西月澹窥楼角，东风暗落檐牙。", "一灯初见影窗纱。", "又是重帘不下。", "幽思屡随芳草，闲愁多似杨花。", "杨花芳草遍天涯。", "绣被春寒夜夜。"]'),
('song-ci-419','西江月','史达祖','宋','宋词','song-ci','西江月','[]','三十六宫月冷，百单八颗香悬。',58,'宋词/ci.song.13000.json','["三十六宫月冷，百单八颗香悬。", "只宜结赠散花天。", "金粟分身显现。", "指嫩香随甲影，颈寒秋入云边。", "未忘灵鹫旧因缘。", "赢得今生圆转。"]'),
('song-ci-420','西江月','史达祖','宋','宋词','song-ci','西江月','[]','一片秋香世界，几层凉雨阑干。',58,'宋词/ci.song.13000.json','["一片秋香世界，几层凉雨阑干。", "青天不惜烂银盘。", "借与先生为劝。", "酒唤诗来酒外，人言身在人间。", "如何得似碧云闲。", "且共嫦娥相伴。"]'),
('song-ci-421','西江月','史达祖','宋','宋词','song-ci','西江月','[]','裙摺绿罗芳草，冠梁白玉芙蓉。',58,'宋词/ci.song.13000.json','["裙摺绿罗芳草，冠梁白玉芙蓉。", "次公筵上见山公。", "红绶欲衔双凤。", "已向冰奁约月，更来玉界乘风。", "凌波袜冷一尊同。", "莫负彩舟凉梦。"]'),
('song-ci-422','庆清朝','史达祖','宋','宋词','song-ci','庆清朝','[]','坠絮孳萍，狂鞭孕竹，偷移红紫池亭。',117,'宋词/ci.song.13000.json','["坠絮孳萍，狂鞭孕竹，偷移红紫池亭。", "馀花未落，似供残蝶经营。", "赋得送春诗了，夏帷撺断绿阴成。", "桑麻外，乳鸠稚燕，别样芳情。", "荀令旧香易冷，叹俊游疏懒，枉自销凝。", "尘侵谢屐，幽径斑驳苔生。", "便觉寸心尚老，故人前度谩丁宁。", "空相误，祓兰曲水，挑菜东城。"]'),
('song-ci-423','桃源忆故人','史达祖','宋','宋词','song-ci','桃源忆故人','[]','双鸳蹙月天津近。',56,'宋词/ci.song.13000.json','["双鸳蹙月天津近。", "归后嫩情常剩。", "灯市一年愁凝。", "心共梅花冷。", "网尘洞户春沈静。", "衰尽冶游情性。", "羞见素娥娇影。", "明似愁鸾镜。"]'),
('song-ci-424','桃源忆故人','史达祖','宋','宋词','song-ci','桃源忆故人','[]','明霞烘透春机杼。',56,'宋词/ci.song.13000.json','["明霞烘透春机杼。", "春在明霞多处。", "我是有诗渔父。", "一梦秦天古。", "柳枝巷陌深朱户。", "墙外风流一树。", "十五年来凝伫。", "弹尽胭脂雨。"]'),
('song-ci-425','花心动','史达祖','宋','宋词','song-ci','花心动','[]','风约帘波，锦机寒、难遮海棠烟雨。',127,'宋词/ci.song.13000.json','["风约帘波，锦机寒、难遮海棠烟雨。", "夜酒未苏，春枕犹敧，曾是误成歌舞。", "半褰薇帐云头散，奈愁味、不随香去。", "尽沈静、文园更渴，有人知否。", "懒记温柔旧处。", "偏只怕、临风见他桃树。", "绣户锁尘，锦瑟空弦，无复画眉心绪。", "待拈银管书春恨，被双燕、替人言语。", "意不尽，垂杨几千万里。"]'),
('song-ci-426','解佩令','史达祖','宋','宋词','song-ci','解佩令','[]','人行花坞。',84,'宋词/ci.song.13000.json','["人行花坞。", "衣沾香雾。", "有新词、逢春分付。", "屡欲传情，奈燕子、不曾飞去。", "倚珠帘、咏郎秀句。", "相思一度。", "秾愁一度。", "最难忘、遮灯私语。", "澹月梨花，借梦来、花边廊庑。", "指春衫、泪曾溅处。"]'),
('song-ci-427','菩萨蛮','史达祖','宋','宋词','song-ci','菩萨蛮','[]','梨花不碍东城月。',52,'宋词/ci.song.13000.json','["梨花不碍东城月。", "月明照见空阑雪。", "雪底夜香微。", "褰帘拜月归。", "锦衾幽梦短。", "明月南堂宴。", "宴罢小楼台。", "春风来不来。"]'),
('song-ci-428','菩萨蛮','史达祖','宋','宋词','song-ci','菩萨蛮','[]','唐昌观里东风软。',52,'宋词/ci.song.13000.json','["唐昌观里东风软。", "齐王宫外芳名远。", "桂子典刑边。", "梅花伯仲间。", "笼茸锼暖雪。", "琐细雕晴月。", "谁驾七香车。", "绿云飞玉沙。"]'),
('song-ci-429','菩萨蛮','史达祖','宋','宋词','song-ci','菩萨蛮','[]','广寒夜捣玄霜细。',52,'宋词/ci.song.13000.json','["广寒夜捣玄霜细。", "玉龙睡重痴涎坠。", "斗合一团娇。", "偎人暖欲消。", "心情虽软弱。", "也要人抟搦。", "宝扇莫惊秋。", "班姬应更愁。"]'),
('song-ci-430','贺新郎','史达祖','宋','宋词','song-ci','贺新郎','[]','花落台池静。',140,'宋词/ci.song.13000.json','["花落台池静。", "自春衫闲来，老了旧香荀令。", "酒既相违诗亦可，此外云沈梦冷。", "又催唤、官河兰艇。", "匝岸烟霏吹不断，望楼阴、欲带朱桥影。", "和草色，入轻暝。", "裙边竹叶多应剩。", "怪南溪见后，无个再来芳信。", "胡蝶一生花里活，难制窃香心性。", "便有段、新愁随定。", "落日年年宫树绿，堕新声、玉笛西风劲。", "谁伴我，月中听。"]'),
('song-ci-431','贺新郎','史达祖','宋','宋词','song-ci','贺新郎','[]','绿障南城树。',140,'宋词/ci.song.13000.json','["绿障南城树。", "有高楼衔城，楼下芰荷无数。", "客自倚阑鱼亦避，恐是持竿伴侣。", "对别浦、扁舟容与。", "杨柳影间风不到，倩诗情、飞过鸳鸯浦。", "人正在，断肠处。", "两山带著冥冥雨。", "想低帘短额，谁见恨时眉妩。", "别为清尊眠锦瑟，怕被歌留愁住。", "便欲趁、采莲归去。", "前度刘郎虽老矣，奈年来、犹道多情句。", "应笑煞，旧鸥鹭。"]'),
('song-ci-432','贺新郎','史达祖','宋','宋词','song-ci','贺新郎','[]','鹊翅西风浅。',140,'宋词/ci.song.13000.json','["鹊翅西风浅。", "乍疏云垂幔，近月银钩将卷。", "天上应闲支机石，前度芳盟谁践。", "便好织、回文锦献。", "乞得秾欢今夜里，算盈盈、一水曾何远。", "宁不会，暗相见。", "彩楼吹断闲针线。", "想幽情嫩约，别有藓庭花院。", "青鸟沈沈音尘绝，烟锁蓬莱宫殿。", "渐木杪、参旗西转。", "不怕天孙成间阻，怕人间、薄幸心肠变。", "又学得，易分散。"]'),
('song-ci-433','贺新郎','史达祖','宋','宋词','song-ci','贺新郎','[]','同住西山下。',140,'宋词/ci.song.13000.json','["同住西山下。", "是天地中间，爱酒能诗之社。", "船向少陵佳处放，尘世必无知者。", "暑不到、云宫风榭。", "楚竹忽然呼月上，被东西，几叶云萦惹。", "云散去，笑声罢。", "清尊莫为婵娟泻。", "为狂吟醉舞，毋失晋人风雅。", "踏碎桥边杨柳影，不听渔樵闲话。", "更欲举、空杯相谢。", "北斗以南如此几，想吾曹、便是神仙也，问今夜，是何夜。"]'),
('song-ci-434','贺新郎','史达祖','宋','宋词','song-ci','贺新郎','[]','西子相思切。',141,'宋词/ci.song.13000.json','["西子相思切。", "委萧萧、风裳水佩，照人清越。", "山染蛾眉波曼睩，聊可与之娱悦。", "便莫赋、湘妃罗袜。", "怕见绿荷相倚恨，恨白鸥、占了凉波阔。", "拣凉处，放船歇。", "道人不是尘埃物。", "纵狂吟魂魄，吹乱一巾凉发。", "不觉引杯浇肺渴，正要清歌骇发。", "更坐上、其人冰雪。", "截取断虹堪作钓，待玉奁、今夜来时节。", "也胜钓，石城月。"]'),
('song-ci-435','夜合花','史达祖','宋','宋词','song-ci','夜合花','[]','冷截龙腰，偷拿鸾爪，楚山长锁秋云。',124,'宋词/ci.song.13000.json','["冷截龙腰，偷拿鸾爪，楚山长锁秋云。", "梅华未落，年年怨入江城。", "千嶂碧，一声清。", "杜人间、儿女箫笙。", "共凄凉处，琵琶湓浦，长啸苏门。", "当时低度西邻。", "天澹阑干欲暮，曾赋高情。", "子期老矣，不堪带酒重听。", "纤手静，七星明。", "有新声、应更魂惊。", "梦回人世，寥寥夜月，空照天津。"]'),
('song-ci-436','夜合花','史达祖','宋','宋词','song-ci','夜合花','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','柳锁莺魂，花翻蝶梦，自知愁染潘郎。',124,'宋词/ci.song.13000.json','["柳锁莺魂，花翻蝶梦，自知愁染潘郎。", "轻衫未揽，犹将泪点偷藏。", "念前事，怯流光。", "早春窥、酥雨池塘。", "向销凝里，梅开半面，情满徐妆。", "风丝一寸柔肠。", "曾在歌边惹恨，烛底萦香。", "芳机瑞锦，如何未织鸳鸯。", "人扶醉，月依墙。", "是当初、谁敢疏狂。", "把闲言语，花房夜久，各自思量。"]'),
('song-ci-437','留春令','史达祖','宋','宋词','song-ci','留春令','[]','秀肌丰靥，韵多香足，绿匀红注。',61,'宋词/ci.song.13000.json','["秀肌丰靥，韵多香足，绿匀红注。", "翦取东风入金盘，断不买、临邛赋。", "宫锦机中春富裕。", "劝玉环休妒。", "等得明朝酒消时，是闲澹、雍容处。"]'),
('song-ci-438','留春令','史达祖','宋','宋词','song-ci','留春令','[]','故人溪上，挂愁无奈，烟梢月树。',61,'宋词/ci.song.13000.json','["故人溪上，挂愁无奈，烟梢月树。", "一涓春水点黄昏，便没顿、相思处。", "曾把芳心深相许。", "故梦劳诗苦。", "闻说东风亦多情，被竹外、香留住。"]'),
('song-ci-439','瑞鹤仙','史达祖','宋','宋词','song-ci','瑞鹤仙','[]','杏烟娇湿鬓。',127,'宋词/ci.song.13000.json','["杏烟娇湿鬓。", "过杜若汀洲，楚衣香润。", "回头翠楼近。", "指鸳鸯沙上，暗藏春恨。", "归鞭隐隐。", "便不念、芳盟未稳。", "自箫声、吹落云东，再数故园花信。", "谁问。", "听歌窗罅，倚月钩阑，旧家轻俊。", "芳心一寸。", "相思后，总灰尽。", "奈春风多事，吹花摇柳，也把幽情唤醒。", "对南溪、桃萼翻红，又成瘦损。"]'),
('song-ci-440','瑞鹤仙','史达祖','宋','宋词','song-ci','瑞鹤仙','[]','馆娃春睡起。',127,'宋词/ci.song.13000.json','["馆娃春睡起。", "为发妆酒暖，脸霞轻腻。", "冰霜一生里。", "厌从来冷澹，粉腮重洗。", "胭脂暗试。", "便无限、芳秾气味。", "向黄昏、竹外寒深，醉里为谁偷倚。", "娇媚。", "春风模样，霜月心肠，瘦来肌体。", "孤香细细。", "吹梦到，杏花底。", "被高楼横管，一声惊断，却对南枝洒泪。", "谩相思、桃叶桃根，旧家姊妹。"]'),
('song-ci-441','点绛唇','史达祖','宋','宋词','song-ci','点绛唇','[]','花落苔香，断无人肯行鹓甃。',50,'宋词/ci.song.13000.json','["花落苔香，断无人肯行鹓甃。", "晚风翻绣。", "吹醒东窗酒。", "犹卧氍毹，明月知人瘦。", "香消后。", "乱愁依旧。", "开□胡酥手。"]'),
('song-ci-442','点绛唇','史达祖','宋','宋词','song-ci','点绛唇','[]','山月随人，翠苹分破秋山影。',50,'宋词/ci.song.13000.json','["山月随人，翠苹分破秋山影。", "钓船归尽。", "桥外诗心迥。", "多少荷花，不盖鸳鸯冷。", "西风定。", "可怜潘鬓。", "偏浸秦台镜。"]'),
('song-ci-443','青玉案','史达祖','宋','宋词','song-ci','青玉案','[]','蕙花老尽离骚句。',80,'宋词/ci.song.13000.json','["蕙花老尽离骚句。", "绿染遍、江头树。", "日午酒消听骤雨。", "青榆钱小，碧苔钱古。", "难买东君住。", "官河不碍遗鞭路。", "被芳草、将愁去。", "多定红楼帘影暮。", "兰灯初上，夜香初炷。", "犹自听鹦鹉。"]'),
('song-ci-444','浣溪沙','史达祖','宋','宋词','song-ci','浣溪沙','[]','不见东山月露香。',48,'宋词/ci.song.13000.json','["不见东山月露香。", "姚家借得小芬芳。", "乱莺随趁过宫墙。", "香珀碾花娇有意，绿茸绣叶涩无光。", "御封春酒几时尝。"]'),
('song-ci-445','蝶恋花','史达祖','宋','宋词','song-ci','蝶恋花','[]','二月东风吹客袂。',70,'宋词/ci.song.13000.json','["二月东风吹客袂。", "苏小门前，杨柳如腰细。", "胡蝶识人游冶地。", "旧曾来处花开未。", "几夜湖山生梦寐。", "评泊寻芳，只怕春寒里。", "令岁清明逢上已。", "相思先到溅裙水。"]'),
('song-ci-446','临江仙','史达祖','宋','宋词','song-ci','临江仙','[]','草脚青回细腻，柳梢绿转条苗。',68,'宋词/ci.song.13000.json','["草脚青回细腻，柳梢绿转条苗。", "旧游重到合魂销。", "棹横春水渡，人凭赤阑桥。", "归梦有时曾见，新愁未肯相饶。", "酒香红被夜迢迢。", "莫交无用月，来照可怜宵。"]'),
('song-ci-447','临江仙','史达祖','宋','宋词','song-ci','临江仙','[]','倦客如今老矣，旧时不奈春何。',68,'宋词/ci.song.13000.json','["倦客如今老矣，旧时不奈春何。", "几曾湖上不经过。", "看花南陌醉，驻马翠楼歌。", "远眼愁随芳草，湘裙忆著春罗。", "枉教装得旧时多。", "向来箫鼓地，犹见柳婆姿。"]'),
('song-ci-448','临江仙','史达祖','宋','宋词','song-ci','临江仙','[]','愁与西风应有约，年年同赴清秋。',70,'宋词/ci.song.13000.json','["愁与西风应有约，年年同赴清秋。", "旧游帘幕记扬州。", "一灯人著梦，双燕月当楼。", "罗带鸳鸯尘暗澹，更须整顿风流。", "天涯万一见温柔。", "瘦应因此瘦，羞亦为郎羞。"]'),
('song-ci-449','汉宫春','史达祖','宋','宋词','song-ci','汉宫春','[]','花隔东垣，咏燕台秀句，结带谋欢。',118,'宋词/ci.song.13000.json','["花隔东垣，咏燕台秀句，结带谋欢。", "匆匆旧盟，有限飞梦重关。", "南塘夜月，照湘琴、别鹤孤鸾。", "天便遣、清愁易长，春衣常恁香寒。", "唐昌故宫何许，顿翦霞裁雾，摆落尘缘。", "一声步虚，婉婉云驻天坛。", "凄凉故里，想香车、不到人间。", "羞再见、东阳带眼，教人依旧思凡。"]'),
('song-ci-450','兰陵王','史达祖','宋','宋词','song-ci','兰陵王','[]','汉江侧。',158,'宋词/ci.song.13000.json','["汉江侧。", "月弄仙人佩色。", "含情久，摇曳楚衣，天水空濛染娇碧。", "文漪簟影织。", "凉骨时将粉饰。", "谁曾见，罗袜去时，点点波间冷云积。", "相思旧飞鹢。", "谩想像风裳，追恨瑶席。", "涉江几度和愁摘。", "记雪映双腕，刺萦丝缕，分开绿盖素袂湿。", "放新句吹入。", "寂寂。", "意犹昔。", "念净社因缘，天许相觅。", "飘萧羽扇摇团白。", "屡侧卧寻梦，倚阑无力。", "风标公子，欲下处、似认得。"]'),
('song-ci-451','风入松','史达祖','宋','宋词','song-ci','风入松','[]','素馨柎萼太寒生。',88,'宋词/ci.song.13000.json','["素馨柎萼太寒生。", "多翦春冰。", "夜深绿雾侵凉月，照晶晶、花叶分明。", "人卧碧纱幮净，香吹雪练衣轻。", "频伽衔得堕南薰。", "不受纤尘。", "若随荔子华清去，定空埋、身外芳名。", "借重玉炉沈炷，起予石鼎汤声。"]'),
('song-ci-452','隔浦莲・隔浦莲近拍','史达祖','宋','宋词','song-ci','隔浦莲・隔浦莲近拍','[]','红尘飞不到处。',89,'宋词/ci.song.13000.json','["红尘飞不到处。", "此地知无暑。", "乱竹分幽径，虚堂中、自回互。", "阴壑生暗雾。", "飞泉注。", "气入闲尊俎。", "快风度。", "齐宫楚榭，如今空锁烟树。", "何人伴我，梦赋雪车冰柱。", "惟有蝉声助冷语。", "惊寤。", "飞雪来献凉雨。"]'),
('song-ci-453','隔浦莲・隔浦莲近拍','史达祖','宋','宋词','song-ci','隔浦莲・隔浦莲近拍','["\u897f\u6e56"]','洛神一醉未醒。',89,'宋词/ci.song.13000.json','["洛神一醉未醒。", "俯鉴窥红影。", "万绿森相卫，西风静、不放冷。", "侵晓鸥梦稳。", "非尘境。", "棹月香千顷。", "锦机靓。", "亭亭不语，多应嗔赋玉井。", "西湖游子，惯识雨愁烟恨。", "只恐吴娃暗折赠。", "耿耿。", "柔丝容易萦损。"]'),
('song-ci-454','凤来朝','史达祖','宋','宋词','song-ci','凤来朝','[]','晕粉就妆镜。',64,'宋词/ci.song.13000.json','["晕粉就妆镜。", "掩金闺、彩丝未整。", "趁无人、学指鸳鸯颈。", "恨谁踏、藓花径。", "一梦蒲香葵冷。", "堕银瓶、脆绳挂井。", "扇底并团圆影。", "只此是、沈郎病。"]'),
('song-ci-455','玉簟凉','史达祖','宋','宋词','song-ci','玉簟凉','[]','秋是愁乡。',120,'宋词/ci.song.13000.json','["秋是愁乡。", "自锦瑟断弦，有泪如江。", "平生花里活，奈旧梦难忘。", "蓝桥云树正绿，料抱月、几夜眠香。", "河汉阻，但凤音传恨，阑影敲凉。", "新妆。", "莲娇试晓，梅瘦破春，因甚却扇临窗。", "红巾衔翠翼，早弱水茫茫。", "柔指各自未翦，问此去、莫负王昌。", "芳信准，更敢寻、红杏西厢。"]'),
('song-ci-456','鹊桥仙','史达祖','宋','宋词','song-ci','鹊桥仙','[]','河深鹊冷，云高鸾远，水佩风裳缥缈。',68,'宋词/ci.song.13000.json','["河深鹊冷，云高鸾远，水佩风裳缥缈。", "却推离恨下人间，第一个、黄昏过了。", "舟行有恨，愁来无限，去去长安渐杳。", "应将巧思入相思，觉泪比、银湾较少。"]'),
('song-ci-457','湘江静','史达祖','宋','宋词','song-ci','湘江静','[]','暮草堆青云浸浦。',129,'宋词/ci.song.13000.json','["暮草堆青云浸浦。", "记匆匆、倦篙曾驻。", "渔榔四起，沙鸥未落，怕愁沾诗句。", "碧袖一声歌，石城怨、西风随去。", "沧波荡晚，菰蒲弄秋，还重到、断魂处。", "酒易醒，思正苦。", "想空山、桂香悬树。", "三年梦冷，孤吟意短，屡烟钟津鼓。", "屐齿厌登临，移橙后、几番凉雨。", "潘郎渐老，风流顿减，闲居未赋。"]'),
('song-ci-458','玲珑四犯','史达祖','宋','宋词','song-ci','玲珑四犯','[]','雨入愁边，翠树晚，无人风叶如翦。',123,'宋词/ci.song.13000.json','["雨入愁边，翠树晚，无人风叶如翦。", "竹尾通凉，却怕小帘低卷。", "孤坐便怯诗悭，念后赏、旧曾题遍。", "更暗尘、偷锁鸾影，心事屡羞团扇。", "卖花门馆生秋草，怅弓弯、几时重见。", "前欢尽属风流梦，天共朱楼远。", "闻道秀骨病多，难自任、从来恩怨。", "料也和、前度金笼鹦鹉，说人情浅。"]'),
('song-ci-459','玲珑四犯','史达祖','宋','宋词','song-ci','玲珑四犯','[]','阔甚吴天，顿放得、江南离绪多少。',123,'宋词/ci.song.13000.json','["阔甚吴天，顿放得、江南离绪多少。", "一雨为秋，凉气小窗先到。", "轻梦听彻风蒲，又散入、楚空清晓。", "问世间、愁在何处，不离澹烟衰草。", "簟纹独浸芙蓉影，想凄凄、欠郎偎抱。", "即今卧得云衣冷，山月仍相照。", "方悔翠袖，易分难聚，有玉香花笑。", "待雁来、先寄新词归去，且教知道。"]'),
('song-ci-460','八归','史达祖','宋','宋词','song-ci','八归','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','秋江带雨，寒沙萦水，人瞰画阁愁独。',138,'宋词/ci.song.13000.json','["秋江带雨，寒沙萦水，人瞰画阁愁独。", "烟蓑散响惊诗思，还被乱鸥飞去，秀句难续。", "冷眼尽归图画上，认隔岸、微茫云屋。", "想半属、渔市樵村，欲暮竞然竹。", "须信风流未老，凭持酒、慰此凄凉心目。", "一鞭南陌，几篙官渡，赖有歌眉舒绿。", "只匆匆眺远，早觉闲愁挂乔木。", "应难奈，故人天际，望彻淮山，相思无雁足。"]'),
('song-ci-461','过龙门・浪淘沙令','史达祖','宋','宋词','song-ci','过龙门・浪淘沙令','[]','一带古苔墙。',64,'宋词/ci.song.13000.json','["一带古苔墙。", "多听寒螀。", "箧中针线早销香。", "燕尾宝刀窗下梦，谁翦秋裳。", "宫漏莫添长。", "空费思量。", "鸳鸯难得再成双。", "昨夜楚山花簟里，波影先凉。"]'),
('song-ci-462','过龙门・浪淘沙令','史达祖','宋','宋词','song-ci','过龙门・浪淘沙令','[]','醉月小红楼。',64,'宋词/ci.song.13000.json','["醉月小红楼。", "锦瑟箜篌。", "夜来风雨晓来收。", "几点落花饶柳絮，同为春愁。", "寄信问晴鸥。", "谁在芳洲。", "绿波宁处有兰舟。", "独对旧时携手地，情思悠悠。"]'),
('song-ci-463','玉胡蝶・玉蝴蝶','史达祖','宋','宋词','song-ci','玉胡蝶・玉蝴蝶','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','晚雨未摧宫树，可怜闲叶，犹抱凉蝉。',124,'宋词/ci.song.13000.json','["晚雨未摧宫树，可怜闲叶，犹抱凉蝉。", "短景归秋，吟思又接愁边。", "漏初长、梦魂难禁，人渐老、风月俱寒。", "想幽欢。", "土花庭甃，虫网阑干。", "无端。", "啼蛄搅夜，恨随团扇，苦近秋莲。", "一笛当楼，谢娘悬泪立风前。", "故园晚、强留诗酒，新雁远、不致寒暄。", "隔苍烟。", "楚香罗袖，谁伴婵娟。"]'),
('song-ci-464','齐天乐','史达祖','宋','宋词','song-ci','齐天乐','[]','秋风早入潘郎鬓，斑斑遽惊如许。',123,'宋词/ci.song.13000.json','["秋风早入潘郎鬓，斑斑遽惊如许。", "暖雪侵梳，晴丝拂领，栽满愁城深处。", "瑶簪谩妒。", "便羞插宫花，自怜衰暮。", "尚想春情，旧吟凄断茂陵女。", "人间公道惟此，叹朱颜也恁，容易堕去。", "涅了重缁，搔来更短，方悔风流相误。", "郎潜几缕。", "渐疏了铜驼，俊游俦侣。", "纵有黟黟，奈何诗思苦。"]'),
('song-ci-465','齐天乐','史达祖','宋','宋词','song-ci','齐天乐','[]','阑干只在鸥飞处，年年怕吟秋兴。',123,'宋词/ci.song.13000.json','["阑干只在鸥飞处，年年怕吟秋兴。", "断浦沈云，空山挂雨，中有诗愁千顷。", "波声未定。", "望舟尾拖凉，渡头笼暝。", "正好登临，有人歌罢翠帘冷。", "悠然魂坠故里，奈闲情未了，还被吹醒。", "拜月虚檐，听蛩坏砌，谁复能怜娇俊。", "忧心耿耿。", "寄桐叶芳题，冷枫新咏。", "莫遣秋声，树头喧夜永。"]'),
('song-ci-466','齐天乐','史达祖','宋','宋词','song-ci','齐天乐','[]','犀纹隐隐莺黄嫩，篱落翠深偷见。',123,'宋词/ci.song.13000.json','["犀纹隐隐莺黄嫩，篱落翠深偷见。", "细雨重移，新霜试摘，佳处一年秋晚。", "荆江未远。", "想橘友荒凉，木奴嗟怨。", "就说风流，草泥来趁蟹螯健。", "并刀寒映素手，醉魂沈夜饮，曾倩排遣。", "沆瀣含酸，金罂裹玉，蔌蔌吴盐轻点。", "瑶姬齿软。", "待惜取团圆，莫教分散。", "入手温存，帕罗香自满。"]'),
('song-ci-467','齐天乐','史达祖','宋','宋词','song-ci','齐天乐','[]','鸳鸯拂破苹花影，低低趁凉飞去。',123,'宋词/ci.song.13000.json','["鸳鸯拂破苹花影，低低趁凉飞去。", "画里移舟，诗边就梦，叶叶碧云分雨。", "芳游自许。", "过柳影闲波，水花平渚。", "见说西风，为人吹恨上瑶树。", "阑干斜照未满，杏墙应望断，春翠偷聚。", "浅约挼香，深盟捣月，谁是窗间青羽。", "孤筝几柱。", "问因甚参差，暂成离阻。", "夜色空庭，待归听俊语。"]'),
('song-ci-468','齐天乐','史达祖','宋','宋词','song-ci','齐天乐','[]','西风来劝凉云去，天东放开金镜。',123,'宋词/ci.song.13000.json','["西风来劝凉云去，天东放开金镜。", "照野霜凝，如河桂湿，一一冰壶相映。", "殊方路永。", "更分破秋光，尽成悲境。", "有客踌躇，古庭空自吊孤影。", "江南朋旧在许，也能怜天际，诗思谁领。", "梦断刀头，书开虿尾，别有相思随定。", "忧心耿耿。", "对风鹊残枝，露蛩荒井。", "斟酌妲娥，九秋宫殿冷。"]'),
('song-ci-469','燕归梁','史达祖','宋','宋词','song-ci','燕归梁','[]','楚梦吹成树外云。',62,'宋词/ci.song.13000.json','["楚梦吹成树外云。", "乍雁影斜分。", "黄花心事一帘尘。", "但频忆、小腰身。", "今宵素壁冰弦冷，怕弹断、沈郎魂。", "秋衣因甚满愁痕。", "是干预、几黄昏。"]'),
('song-ci-470','燕归梁','史达祖','宋','宋词','song-ci','燕归梁','[]','独卧秋窗桂未香。',62,'宋词/ci.song.13000.json','["独卧秋窗桂未香。", "怕雨点飘凉。", "玉人只在楚云傍。", "也著泪、过昏黄。", "西风今夜梧桐冷，断无梦、到鸳鸯。", "秋钲二十五声长。", "请各自，奈思量。"]'),
('song-ci-471','月当厅','史达祖','宋','宋词','song-ci','月当厅','[]','白壁旧带秦城梦，因谁拜下，杨柳楼心。',122,'宋词/ci.song.13000.json','["白壁旧带秦城梦，因谁拜下，杨柳楼心。", "正是夜分，鱼钥不动香深。", "时有露萤自照，占风裳、可喜影麸金。", "坐来久，都将凉意，尽付沈吟。", "残云事绪无人舍，恨匆匆、药娥归去难寻。", "缀取雾窗，会唱几拍清音。", "犹有老来印愁处，冷光应念雪翻簪。", "空独对、西风紧，弄一片桐阴。"]'),
('song-ci-472','秋霁','史达祖','宋','宋词','song-ci','秋霁','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','江水苍苍，望倦柳愁荷，共感秋色。',128,'宋词/ci.song.13000.json','["江水苍苍，望倦柳愁荷，共感秋色。", "废阁先凉，古帘空暮，雁程最嫌风力。", "故园信息。", "爱渠入眼南山碧。", "念上国。", "谁是、脍鲈江汉未归客。", "还又岁晚，瘦骨临风，夜闻秋声，吹动岑寂。", "露蛩悲、清灯冷屋，翻书愁上鬓毛白。", "年少俊游浑断得。", "但可怜处，无奈苒苒魂惊，采香南浦，翦梅烟驿。"]'),
('song-ci-473','满江红','史达祖','宋','宋词','song-ci','满江红','[]','万水归阴，故潮信、盈虚因月。',115,'宋词/ci.song.13000.json','["万水归阴，故潮信、盈虚因月。", "偏只到、凉秋半破，斗成双绝。", "有物揩磨金镜净，何人拿攫银河决。", "想子胥、今夜见嫦娥，沈冤雪。", "光直下，蛟龙穴。", "声直上，蟾蜍窟。", "对望中天地，洞然如刷。", "激气已能驱粉黛，举杯便可吞吴越。", "待明朝、说似与儿曹，心应折。"]'),
('song-ci-474','满江红','史达祖','宋','宋词','song-ci','满江红','[]','好领青衫，全不向、诗书中得。',115,'宋词/ci.song.13000.json','["好领青衫，全不向、诗书中得。", "还也费、区区造物，许多心力。", "未暇买田清颍尾，尚须索米长安陌。", "有当时、黄卷满前头，多惭德。", "思往事，嗟儿剧。", "怜牛后，怀鸡肋。", "奈棱棱虎豹，九重九隔。", "三径就荒秋自好，一钱不直贫相逼。", "对黄花、常待不吟诗，诗成癖。"]'),
('song-ci-475','满江红','史达祖','宋','宋词','song-ci','满江红','[]','缓辔西风，叹三宿、迟迟行客。',115,'宋词/ci.song.13000.json','["缓辔西风，叹三宿、迟迟行客。", "桑梓外、锄耰渐入，柳坊花陌。", "双阙远腾龙凤影，九门空锁鸳鸯翼。", "更无人、擫笛傍宫墙，苔花碧。", "天相汉，民怀国。", "天厌虏，臣离德。", "趁建瓴一举，并收鳌极。", "老子岂无经世术，诗人不预平戎策。", "办一襟、风月看升平，吟春色。"]'),
('song-ci-476','恋绣衾','史达祖','宋','宋词','song-ci','恋绣衾','[]','吴梅初试涧谷春。',68,'宋词/ci.song.13000.json','["吴梅初试涧谷春。", "夜幽幽、江雁叫云。", "人正在、孤窗底，被浓愁、醺破醉魂。", "雨窗只剩残灯影，伴罗衣、无限泪痕。", "瘦骨怕、红绵冷，说年时、斗帐夜分。"]'),
('song-ci-477','恋绣衾','史达祖','宋','宋词','song-ci','恋绣衾','[]','黄花惊破九日愁。',68,'宋词/ci.song.13000.json','["黄花惊破九日愁。", "正寒城、风雨怨秋。", "愁便是、秋心也，又随人、来到画楼。", "因缘幸自天安顿，更题红、不禁御沟。", "待写与、相思话，为怕奴、憔悴且休。"]'),
('song-ci-478','恋绣衾','史达祖','宋','宋词','song-ci','恋绣衾','[]','天风入扇吹苎衣。',68,'宋词/ci.song.13000.json','["天风入扇吹苎衣。", "小红楼、夜气正微。", "有人在、冰弦外，水精帘、花影自移。", "阳台只是虚无梦，便不成、凉夜误伊。", "想闲了、流离簟，就一身、明月伴归。"]'),
('song-ci-479','换巢鸾凤','史达祖','宋','宋词','song-ci','换巢鸾凤','[]','人若梅娇。',123,'宋词/ci.song.13000.json','["人若梅娇。", "正愁横断坞，梦绕溪桥。", "倚风融汉粉，坐月怨秦箫。", "相思因甚到纤腰。", "定知我今，无魂可销。", "佳期晚，谩几度、泪痕相照。", "人悄。", "天眇眇。", "花外语香，时透郎怀抱。", "暗握荑苗，乍尝樱颗，犹恨侵阶芳草。", "天念王昌忒多情，换巢鸾凤教偕老。", "温柔乡，醉芙蓉、一帐春晓。"]'),
('song-ci-480','惜奴娇','史达祖','宋','宋词','song-ci','惜奴娇','[]','香剥酥痕，自昨夜、春愁醒。',94,'宋词/ci.song.13000.json','["香剥酥痕，自昨夜、春愁醒。", "高情寄、冰桥雪岭。", "试约黄昏，便不误、黄昏信。", "人静。", "倩娇娥、留连秀影。", "吟鬓簪香，已断了、多情病。", "年年待、将春管领。", "镂月描云，不枉了、闲心性。", "谩听。", "谁敢把、红儿比并。"]'),
('song-ci-481','龙吟曲・水龙吟','史达祖','宋','宋词','song-ci','龙吟曲・水龙吟','[]','夜寒幽梦飞来，小梅影下东风晓。',126,'宋词/ci.song.13000.json','["夜寒幽梦飞来，小梅影下东风晓。", "蝶魂未冷，吾身良是，悠然一笑。", "竹杖敲苔，布鞋踏冻，岁常先到。", "傍苍林却恨，储风养月，须我辈、新诗吊。", "永以南枝为好。", "怕从今、逢花渐老。", "愁消秀句，寒回斗酒，春心多少。", "之子逃空，伊人遁世，又还惊觉。", "但归来对月，高情耿耿，寄白云杪。"]'),
('song-ci-482','龙吟曲・水龙吟','史达祖','宋','宋词','song-ci','龙吟曲・水龙吟','[]','梦回虚白初生，便凝冷月通窗户。',126,'宋词/ci.song.13000.json','["梦回虚白初生，便凝冷月通窗户。", "不知夜久，都无人见，玉妃起舞。", "银界回天，琼田易地，晃然非故。", "想儿童健意，生愁齐色，情频在、窥帘处。", "一片樵林钓浦。", "是天教、王维画取。", "未如授简，先将高兴，收归妙句。", "江路梅愁，灞陵人老，又骑驴去。", "过章台，记得春风乍见，倚帘吹絮。"]'),
('song-ci-483','龙吟曲・水龙吟','史达祖','宋','宋词','song-ci','龙吟曲・水龙吟','[]','道人越布单衣，兴高爱学苏门啸。',126,'宋词/ci.song.13000.json','["道人越布单衣，兴高爱学苏门啸。", "有时也伴，四佳公子，五陵年少。", "歌里眠香，酒酣喝月，壮怀无挠。", "楚江南，每为神州未复，阑干静、慵登眺。", "今日征夫在道。", "敢辞劳、风沙短帽。", "休吟稷穗，休寻乔木，独怜遗老。", "同社诗囊，小窗针线，断肠秋早。", "看归来，几许吴霜染鬓，验愁多少。"]'),
('song-ci-484','鹧鸪天','史达祖','宋','宋词','song-ci','鹧鸪天','[]','睡袖无端几摺香。',64,'宋词/ci.song.13000.json','["睡袖无端几摺香。", "有人丹脸可占霜。", "半窗月印梅犹瘦，一律瓶笙夜正长。", "情艳艳，酒狂狂。", "小屏谁与画鸳鸯。", "解衣恰恨敲金钏，惊起春风傍枕囊。"]'),
('song-ci-485','鹧鸪天','史达祖','宋','宋词','song-ci','鹧鸪天','[]','御路东风拂醉衣。',64,'宋词/ci.song.13000.json','["御路东风拂醉衣。", "卖灯人散烛笼稀。", "不知月底梅花冷，只忆桥边步袜归。", "闲梦淡，旧游非。", "夜深谁在小帘帏。", "罘罳儿下围炉坐，明处将人立地时。"]'),
('song-ci-486','鹧鸪天','史达祖','宋','宋词','song-ci','鹧鸪天','[]','搭柳阑干倚伫频。',64,'宋词/ci.song.13000.json','["搭柳阑干倚伫频。", "杏帘胡蝶绣床春。", "十年花骨东风泪，几点螺香素壁尘。", "箫外月，梦中云。", "秦楼楚殿可怜身。", "新愁换尽风流性，偏恨鸳鸯不念人。"]'),
('song-ci-487','鹧鸪天','史达祖','宋','宋词','song-ci','鹧鸪天','[]','雁足无书古塞幽。',64,'宋词/ci.song.13000.json','["雁足无书古塞幽。", "一程烟草一程愁。", "帽檐尘重风吹野，帐角香销月满楼。", "情思乱，梦魂浮。", "缃裙多忆敝貂裘。", "官河水静阑干暖，从倚斜阳怨晚秋。"]'),
('song-ci-488','惜黄花','史达祖','宋','宋词','song-ci','惜黄花','[]','涵秋寒渚。',88,'宋词/ci.song.13000.json','["涵秋寒渚。", "染霜丹树。", "尚依稀，是来时、梦中行路。", "时节正思家，远道仍怀古。", "更对著、满城风雨。", "黄花无数。", "碧云欲暮。", "美人兮，美人兮、未知何处。", "独自卷帘栊，谁为开尊俎。", "恨不得、御风归去。"]'),
('song-ci-489','玉烛新','史达祖','宋','宋词','song-ci','玉烛新','[]','疏云萦碧岫。',125,'宋词/ci.song.13000.json','["疏云萦碧岫。", "带晚日摇光，半江寒皱。", "越溪近远，空频向、过雁风边回首。", "酸心一缕。", "念水北、寻芳归后。", "轻醉醒、堤月笼沙，鞍松宝轮飞骤。", "秦楼屡约芳春，记扇背题诗，帕罗沾酒。", "瘦愁易就。", "因惊断、梦里桃源难又。", "临风话旧。", "想日暮、梅花孤瘦。", "还静倚、修竹相思，盈盈翠袖。"]'),
('song-ci-490','一翦梅','史达祖','宋','宋词','song-ci','一翦梅','[]','谁写梅溪字字香。',72,'宋词/ci.song.13000.json','["谁写梅溪字字香。", "沙边幽梦，常恁芬芳。", "不知花解伴昏黄。", "只怕东风，吹断人肠。", "小阁无灯月浸窗。", "香吹罗袖，酒映宫妆。", "如今竹外怕思量。", "谷里佳人，一片冰霜。"]'),
('song-ci-491','一翦梅','史达祖','宋','宋词','song-ci','一翦梅','[]','秦客当楼泣凤箫。',72,'宋词/ci.song.13000.json','["秦客当楼泣凤箫。", "宫衣香断，不见纤腰。", "隔年心事又今宵。", "折尽冰弦，何用鸾胶。", "些子轻魂几度销。", "兰骚蕙些，无计重招。", "东窗一段月华娇。", "也带春愁，飞上梅梢。"]'),
('song-ci-492','醉落魄・一斛珠','史达祖','宋','宋词','song-ci','醉落魄・一斛珠','[]','鸳鸯意惬。',68,'宋词/ci.song.13000.json','["鸳鸯意惬。", "空分付、有情眉睫。", "齐家莲子黄金叶。", "争比秋苔，靴凤几番蹑。", "墙阴月白花重叠。", "匆匆软语屡惊怯。", "宫香锦字将盈箧。", "雨长新寒，今夜梦魂接。"]'),
('song-ci-493','醉落魄・一斛珠','史达祖','宋','宋词','song-ci','醉落魄・一斛珠','[]','江痕妥帖。',67,'宋词/ci.song.13000.json','["江痕妥帖。", "日光熨动黄金叶。", "阑干直下愁相接。", "一朵红莲，飞上越人楫。", "鲤鱼波上丁宁切。", "诗筒如线不曾别。", "明年好个春风客。", "五鹗交飞，身在玉皇阙。"]'),
('song-ci-494','醉公子','史达祖','宋','宋词','song-ci','醉公子','[]','神仙无皋泽。',132,'宋词/ci.song.13000.json','["神仙无皋泽。", "琼裾珠佩，卷下尘陌。", "秀骨依依，误向山中，得与相识。", "溪岸侧。", "倚高情、自锁烟翠，时点空碧。", "念香襟沾恨，酥手翦愁，今后梦魂隔。", "相思暗惊清吟客。", "想玉照堂前、树三百。", "雁翅霜轻，凤羽寒深，谁护春色。", "诗鬓白。", "总多因、水村携酒，烟墅留屐。", "更时带、明月同来，与花为表德。"]'),
('song-ci-495','步月','史达祖','宋','宋词','song-ci','步月','[]','翦柳章台，问梅东阁，醉中携手初归。',120,'宋词/ci.song.13000.json','["翦柳章台，问梅东阁，醉中携手初归。", "逗香帘下，璀璨镂金衣。", "正依约、冰丝射眼，更荏苒、蟾玉西飞。", "轻尘外，双鸳细蹙，谁赋洛滨妃。", "霏霏。", "红雾绕，步摇共鬓影，吹入花围。", "管弦将散，人静烛笼稀。", "泥私语、香樱乍破，怕夜寒、罗袜先知。", "归来也，相偎未肯入重帏。"]'),
('song-ci-496','齐天乐','高观国','宋','宋词','song-ci','齐天乐','[]','碧云阙处无多雨，愁与去帆俱远。',123,'宋词/ci.song.13000.json','["碧云阙处无多雨，愁与去帆俱远。", "倒苇沙闲，枯兰溆冷，寥落寒江秋晚。", "楼阴纵览。", "正魂怯清吟，病多依黯。", "怕挹西风，袖罗香自去年减。", "风流江左久客，旧游得意处，朱帘曾卷。", "载酒春情，吹箫夜约，犹忆玉娇香软。", "尘栖故苑，叹璧月空檐，梦云飞观。", "送绝征鸿，楚峰烟数点。"]'),
('song-ci-497','齐天乐','高观国','宋','宋词','song-ci','齐天乐','[]','丛幽一笑东篱晓，霜华又随香冷。',123,'宋词/ci.song.13000.json','["丛幽一笑东篱晓，霜华又随香冷。", "晕色黄娇，低枝翠婉，来趁登高佳景。", "谁偏管领。", "是彭泽归来，未荒三径。", "最惬清觞，道家标致自风韵。", "南山依旧翠倚，采花无限思，西风吹醒。", "万蕊金寒，三秋梦好，曾记餐英清咏。", "斓斑泪沁。", "怕节去蜂愁，雨荒烟暝。", "明日重阳，为谁簪短鬓。"]'),
('song-ci-498','齐天乐','高观国','宋','宋词','song-ci','齐天乐','[]','晚云知有关山念，澄霄卷开清霁。',123,'宋词/ci.song.13000.json','["晚云知有关山念，澄霄卷开清霁。", "素景分中，冰盘正溢，何啻婵娟千里。", "危阑静倚。", "正玉管吹凉，翠觞留醉。", "记约清吟，锦袍初唤醉魂起。", "孤光天地共影，浩歌谁与舞，凄凉风味。", "古驿烟寒，幽垣梦冷，应念秦楼十二。", "归心对此。", "想斗插天南，雁横辽水。", "试问妲娥，有谁能为寄。"]'),
('song-ci-499','玉楼春','高观国','宋','宋词','song-ci','玉楼春','[]','几双海燕来金屋。',64,'宋词/ci.song.13000.json','["几双海燕来金屋。", "春满离宫三十六。", "春风翦草碧纤纤，春雨浥花红扑扑。", "卫姬郑女腰如束。", "齐唱阳春新制曲。", "曲终移宴起笙箫，花下晚寒生翠縠。"]'),
('song-ci-500','玉楼春','高观国','宋','宋词','song-ci','玉楼春','[]','燕脂染出春风锦。',64,'宋词/ci.song.13000.json','["燕脂染出春风锦。", "生怕黄昏人有恨。", "雨难揩泪玉环娇，烟不遮愁红袖冷。", "醉魂吹断香魂静。", "拂拂翠眉羞带粉。", "最怜新燕识风流，只为春寒消瘦损。"]'),
('song-ci-501','玉楼春','高观国','宋','宋词','song-ci','玉楼春','[]','多时不踏章台路。',64,'宋词/ci.song.13000.json','["多时不踏章台路。", "依旧东风芳草渡。", "莺声唤起水边情，日影炙开花上雾。", "谢娘不信佳期误。", "认得马嘶迎绣户。", "今宵翠被不春寒，只恐香浓春又去。"]'),
('song-ci-502','玉楼春','高观国','宋','宋词','song-ci','玉楼春','[]','春烟澹澹生春水。',64,'宋词/ci.song.13000.json','["春烟澹澹生春水。", "曾记芳洲兰棹舣。", "岸花香到舞衣边，汀草色分歌扇底。", "棹沈云去情千里。", "愁压双鸳飞不起。", "十年春事十年心，怕说湔裙当日事。"]'),
('song-ci-503','玉蝴蝶','高观国','宋','宋词','song-ci','玉蝴蝶','[]','唤起一襟凉思，未成晚雨，先做秋阴。',124,'宋词/ci.song.13000.json','["唤起一襟凉思，未成晚雨，先做秋阴。", "楚客悲残，谁解此意登临。", "古台荒、断霞斜照，新梦黯、微月疏砧。", "总难禁。", "尽将幽恨，分付孤斟。", "从今。", "倦看青镜，既迟勋业，可负烟林。", "断梗无凭，岁华摇落又惊心。", "想莼汀、水云愁凝，闲蕙帐、猿鹤悲吟。", "信沈沈。", "故园归计，休更侵寻。"]'),
('song-ci-504','临江仙','高观国','宋','宋词','song-ci','临江仙','[]','俱是洛阳年少客，才华迥出天真。',70,'宋词/ci.song.13000.json','["俱是洛阳年少客，才华迥出天真。", "青衫惯拂软红尘。", "酒狂因月舞，诗俊为梅新。", "寄语长安风月道，莺花缓作青春。", "披风沐露问前津。", "客中春不当，归去倍还人。"]'),
('song-ci-505','临江仙','高观国','宋','宋词','song-ci','临江仙','[]','风月生来人世，梦魂飞堕仙津。',68,'宋词/ci.song.13000.json','["风月生来人世，梦魂飞堕仙津。", "青春日日醉芳尘。", "一鞭花陌晓，双桨柳桥春。", "前度诗留醉袖，昨宵香浥罗巾。", "小姬飞燕是前身。", "歌随流水咽，眉学远山颦。"]'),
('song-ci-506','金人捧露盘','高观国','宋','宋词','song-ci','金人捧露盘','[]','梦湘云，吟湘月，吊湘灵。',100,'宋词/ci.song.13000.json','["梦湘云，吟湘月，吊湘灵。", "有谁见、罗袜尘生。", "凌波步弱，背人羞整六铢轻。", "娉娉袅袅，晕娇黄、玉色轻明。", "香心静，波心冷，琴心怨，客心惊。", "怕佩解、却返瑶京。", "杯擎清露，醉春兰友与梅兄。", "苍烟万顷，断肠是、雪冷江清。"]'),
('song-ci-507','金人捧露盘','高观国','宋','宋词','song-ci','金人捧露盘','[]','念瑶姬，翻瑶佩，下瑶池。',100,'宋词/ci.song.13000.json','["念瑶姬，翻瑶佩，下瑶池。", "冷香梦、吹上南枝。", "罗浮梦杳，忆曾清晓见仙姿。", "天寒翠袖，可怜是、倚竹依依。", "溪痕浅，云痕冻，月痕澹，粉痕微。", "江楼怨、一笛休吹。", "芳音待寄，玉堂烟驿两凄迷。", "新愁万斛，为春瘦、却怕春知。"]'),
('song-ci-508','金人捧露盘','高观国','宋','宋词','song-ci','金人捧露盘','[]','楚宫闲，金成屋，玉为阑。',100,'宋词/ci.song.13000.json','["楚宫闲，金成屋，玉为阑。", "断云梦、容易惊残。", "骊歌几叠，至今愁思怯阳关。", "清音恨阻，抱哀筝、知为谁弹。", "年华晚，月华冷，霜华重，鬓华斑。", "也须念、闲损雕鞍。", "斜缄小字，锦江三十六鳞寒。", "此情天阔，正梅信、笛里关山。"]'),
('song-ci-509','凤栖梧・蝶恋花','高观国','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','云唤阴来鸠唤雨。',70,'宋词/ci.song.13000.json','["云唤阴来鸠唤雨。", "谢了江梅，可踏江头路。", "拼却一番花信阻。", "不成日日春寒去。", "见说东风桃叶渡。", "岸隔青山，依旧修眉妩。", "归雁不如筝上柱。", "一行常见相思苦。"]'),
('song-ci-510','凤栖梧・蝶恋花','高观国','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','岩室归来非待聘。',70,'宋词/ci.song.13000.json','["岩室归来非待聘。", "渺渺千崖，漠漠江千顷。", "明月清风休弄影。", "只愁踏破苍苔径。", "摘取香芝医鹤病。", "正要臞仙，相伴清闲性。", "朝市不闻心耳静。", "一声长啸烟霞冷。"]'),
('song-ci-511','凤栖梧・蝶恋花','高观国','宋','宋词','song-ci','凤栖梧・蝶恋花','["\u897f\u6e56"]','西子湖边眉翠妩。',70,'宋词/ci.song.13000.json','["西子湖边眉翠妩。", "魂冷孤山，谁是风烟主。", "相唤吟诗天欲雨。", "嫩凉不隔鸥飞处。", "移下天孙云锦渚。", "翠盖牵风，绰约凌波女。", "清约已成君记取。", "月明夜半鱼龙舞。"]'),
('song-ci-512','贺新郎','高观国','宋','宋词','song-ci','贺新郎','["\u897f\u6e56"]','月冷霜袍拥。',142,'宋词/ci.song.13000.json','["月冷霜袍拥。", "见一枝、年华又晚，粉愁香冻。", "云隔溪桥人不度，的皪春心未纵。", "清影怕、寒波摇动。", "更没纤毫尘俗态，倚高情、预得春风宠。", "沈冻蝶，挂么凤。", "一杯正要吴姬捧。", "想见那、柔酥弄白，暗香偷送。", "回首罗浮今在否，寂寞烟迷翠拢。", "又争奈、桓伊三弄。", "开遍西湖春意烂，算群花、正作江山梦。", "吟思怯，暮云重。"]'),
('song-ci-513','喜迁莺','高观国','宋','宋词','song-ci','喜迁莺','[]','歌声凄怨。',126,'宋词/ci.song.13000.json','["歌声凄怨。", "是几度诉春，春都不管。", "感绿惊红，颦烟啼月，长是为春消黯。", "玉骨瘦无一把，粉泪愁多千点。", "可怜损，任尘侵粉蠹，舞裙歌扇。", "转盼。", "尘梦断。", "峡里云归，空想春风面。", "燕子楼空，玉台妆冷，湖外翠峰眉浅。", "绮陌断魂名在，宝箧返魂香远。", "此情苦，问落花流水，何时重见。"]'),
('song-ci-514','喜迁莺','高观国','宋','宋词','song-ci','喜迁莺','[]','凉云归去。',126,'宋词/ci.song.13000.json','["凉云归去。", "再约著，晚来西楼风雨。", "水静帘阴，鸥闲菰影，秋到露汀烟浦。", "试省唤回幽恨，尽是愁边新句。", "倦登眺，动悲凉还在，残蝉吟处。", "凄楚。", "空见说，香锁雾扃，心似秋莲苦。", "宝瑟弹冰，玉台窥月，浅澹可怜偷聚。", "几时翠沟题叶，无复绣帘吹絮。", "鬓华晚，念庾郎情在，风流谁与。"]'),
('song-ci-515','菩萨蛮','高观国','宋','宋词','song-ci','菩萨蛮','[]','春风吹绿湖边草。',52,'宋词/ci.song.13000.json','["春风吹绿湖边草。", "春光依旧湖边道。", "玉勒锦障泥。", "少年游冶时。", "烟明花似绣。", "且醉旗亭酒。", "斜日照花西。", "归鸦花外啼。"]'),
('song-ci-516','菩萨蛮','高观国','宋','宋词','song-ci','菩萨蛮','[]','红云半压秋波碧。',52,'宋词/ci.song.13000.json','["红云半压秋波碧。", "艳妆泣露娇啼色。", "佳梦入仙城。", "风流石曼卿。", "宫袍呼醉醒。", "休卷西风锦。", "明日粉香残。", "六朝烟水寒。"]'),
('song-ci-517','菩萨蛮','高观国','宋','宋词','song-ci','菩萨蛮','[]','玉鳞熬出香凝软。',52,'宋词/ci.song.13000.json','["玉鳞熬出香凝软。", "并刀断处冰丝颤。", "红缕间堆盘。", "轻明相映寒。", "纤柔分劝处。", "腻滑难停筋。", "一洗醉魂清。", "真成醒酒冰。"]'),
('song-ci-518','菩萨蛮','高观国','宋','宋词','song-ci','菩萨蛮','[]','玉阑秋色知谁主。',52,'宋词/ci.song.13000.json','["玉阑秋色知谁主。", "隔阑一架葡萄雨。", "绿藓怕啼螀。", "可堪宫漏长。", "乌丝吟古怨。", "清泪消尘砚。", "梦冷不成云。", "□峰峰外情。"]'),
('song-ci-519','菩萨蛮','高观国','宋','宋词','song-ci','菩萨蛮','[]','何须急管吹云暝。',52,'宋词/ci.song.13000.json','["何须急管吹云暝。", "高寒滟滟开金饼。", "今夕不登楼。", "一年空过秋。", "桂花香雾冷。", "梧叶西风影。", "客醉倚河桥。", "清光愁玉箫。"]'),
('song-ci-520','菩萨蛮','高观国','宋','宋词','song-ci','菩萨蛮','[]','云娇雪嫩羞相倚。',52,'宋词/ci.song.13000.json','["云娇雪嫩羞相倚。", "凌波共酌春风醉。", "的皪玉台寒。", "肯教金盏单。", "只疑双蝶梦。", "翠袖和香拥。", "香外有鸳鸯。", "风流烟水乡。"]'),
('song-ci-521','青玉案','高观国','宋','宋词','song-ci','青玉案','["\u897f\u6e56"]','平生似欠西湖债。',80,'宋词/ci.song.13000.json','["平生似欠西湖债。", "每拼了、金貂解。", "妩媚烟云多变态。", "雕鞍来处，画船归去，花柳春风隘。", "玉京相接蓬壶界。", "入画遥山翠分黛。", "苏小不来时节改。", "一堤风月，六桥烟水，鹭约鸥盟在。"]'),
('song-ci-522','醉落魄・一斛珠','高观国','宋','宋词','song-ci','醉落魄・一斛珠','[]','钩帘翠湿。',68,'宋词/ci.song.13000.json','["钩帘翠湿。", "寒江上、雨晴风急。", "乱峰低处明残日。", "雁字成行，写破暮天碧。", "故人天外长为客。", "倚阑一望情何极。", "新来得个归消息。", "去棹回舟，数过几千只。"]'),
('song-ci-523','夜合花','高观国','宋','宋词','song-ci','夜合花','[]','斑驳云开，濛松雨过，海棠花外寒轻。',124,'宋词/ci.song.13000.json','["斑驳云开，濛松雨过，海棠花外寒轻。", "湖山翠暖，东风正要新晴。", "又唤醒，旧游情。", "记年时、今日清明。", "隔花阴浅，香随笑语，特地逢迎。", "人生好景难并。", "依旧秋千巷陌，花月蓬瀛。", "春衫抖擞，馀香半染芳尘。", "念嫩约，杳难凭。", "被几声、啼鸟惊心。", "一庭芳草，危阑晚日，无限消凝。"]'),
('song-ci-524','花心动','高观国','宋','宋词','song-ci','花心动','[]','碧藓封枝，点寒英、疏疏玉清冰洁。',127,'宋词/ci.song.13000.json','["碧藓封枝，点寒英、疏疏玉清冰洁。", "梦忆旧家，春与新恩，曾映寿阳妆额。", "绿裙青袂南邻伴，应怪我、精神都别。", "恨衰晚、春风意思，顿成羞怯。", "犹念横斜性格。", "恼和靖吟魂，自来清绝。", "斜傍劲松，偷倚修篁，总是岁寒相识。", "绿阴结子当时意，到如今、芳心消歇。", "小桥夜，清愁倦陪澹月。"]'),
('song-ci-525','昭君怨','高观国','宋','宋词','song-ci','昭君怨','[]','一棹莫愁烟艇。',48,'宋词/ci.song.13000.json','["一棹莫愁烟艇。", "飞破玉壶清影。", "水溅粉绡寒。", "渺云鬟。", "不肯凌波微步。", "却载春愁归去。", "风澹楚魂惊。", "隔瑶京。"]'),
('song-ci-526','杏花天','高观国','宋','宋词','song-ci','杏花天','[]','霁烟消处寒犹嫩。',65,'宋词/ci.song.13000.json','["霁烟消处寒犹嫩。", "乍门巷、愔愔昼永。", "池塘芳草魂初醒。", "秀句吟春未稳。", "仙源阻、春风瘦损。", "又燕子、来无芳信。", "小桃也自知人恨。", "满面羞红难问。"]'),
('song-ci-527','杏花天','高观国','宋','宋词','song-ci','杏花天','[]','远山学得修眉翠。',65,'宋词/ci.song.13000.json','["远山学得修眉翠。", "看眉展、春愁无际。", "雨痕半湿东风外。", "不管梨花有泪。", "西园路、青鞋暗记。", "怕行入、秋千径里。", "一春多少相思意。", "说与新来燕子。"]'),
('song-ci-528','杏花天','高观国','宋','宋词','song-ci','杏花天','[]','花凝露湿燕脂透。',65,'宋词/ci.song.13000.json','["花凝露湿燕脂透。", "是彩笔、丹青染就。", "粉绡帕入班姬手。", "舒卷清寒时候。", "春禽静、来窥晴昼。", "问冷落、芳心知否。", "不愁院宇东风骤。", "日日娇红如旧。"]'),
('song-ci-529','杏花天','高观国','宋','宋词','song-ci','杏花天','[]','玉坛消息春寒浅。',65,'宋词/ci.song.13000.json','["玉坛消息春寒浅。", "露红玉、娇生靓艳。", "小怜鬓湿燕脂染。", "只隔粉墙相见。", "花阴外、故宫梦远。", "想未识、莺莺燕燕。", "飘零翠径红千点。", "桃李春风已晚。"]'),
('song-ci-530','祝英台近','高观国','宋','宋词','song-ci','祝英台近','[]','拥红妆，翻翠盖，花影暗南浦。',95,'宋词/ci.song.13000.json','["拥红妆，翻翠盖，花影暗南浦。", "波面澄霞，兰艇采香去。", "有人水溅红裙，相招晚醉，正月上、凉生风露。", "两凝伫。", "别后歌断云闲，娇姿黯无语。", "魂梦西风，端的此心苦。", "遥想芳脸轻颦，凌波微步，镇输与、沙边鸥鹭。"]'),
('song-ci-531','祝英台近','高观国','宋','宋词','song-ci','祝英台近','[]','一窗闲，孤烬冷，独自个春睡。',95,'宋词/ci.song.13000.json','["一窗闲，孤烬冷，独自个春睡。", "绣被熏香，不似旧风味。", "静听滴滴檐声，惊愁搅梦，更不管、庾郎心碎。", "念芳意。", "一并十日春寒，梅花煞憔悴。", "懒做新词，春在可怜里。", "几时挑菜踏青，云沈雨断，尽分付、楚天之外。"]'),
('song-ci-532','江城子','高观国','宋','宋词','song-ci','江城子','[]','绿丛篱菊点娇黄。',86,'宋词/ci.song.13000.json','["绿丛篱菊点娇黄。", "过重阳。", "转愁伤。", "风急天高，归雁不成行。", "此去郎边知近远，秋水阔，碧天长。", "郎心如妾妾如郎。", "两离肠。", "一思量。", "春到春愁，秋色亦凄凉。", "近得新词知怨妾，无处诉，泣兰房。"]'),
('song-ci-533','生查子','高观国','宋','宋词','song-ci','生查子','[]','野泉春吐芽，泥湿随飞燕。',48,'宋词/ci.song.13000.json','["野泉春吐芽，泥湿随飞燕。", "碧涧一杯羹，夜韭无人翦。", "玉钗和露香，鹅管随春软。", "野意重殷勤，持以君王献。"]'),
('song-ci-534','生查子','高观国','宋','宋词','song-ci','生查子','[]','芙蓉羞粉香，倚竹窥烟霁。',48,'宋词/ci.song.13000.json','["芙蓉羞粉香，倚竹窥烟霁。", "眼带楚波寒，骨艳春风醉。", "谁传侧帽情，想解遗鞭意。", "红叶可怜秋，不寄相思字。"]'),
('song-ci-535','生查子','高观国','宋','宋词','song-ci','生查子','[]','蓬莱一捻云，彻骨龙涎染。',48,'宋词/ci.song.13000.json','["蓬莱一捻云，彻骨龙涎染。", "风味韵而芳，笑语柔而婉。", "花娇绿鬓寒，酒凝清歌怨。", "翠幄已烟浓，银烛重休翦。"]'),
('song-ci-536','生查子','高观国','宋','宋词','song-ci','生查子','[]','春笼云润香，露湿青蛟瘦。',48,'宋词/ci.song.13000.json','["春笼云润香，露湿青蛟瘦。", "偷学汉宫妆，舞彻霓裳后。", "酥胸紫领巾，冰翦柔荑手。", "有意入罗囊，不肯成春酒。"]'),
('song-ci-537','生查子','高观国','宋','宋词','song-ci','生查子','[]','飞花澹澹风，破暖疏疏雨。',48,'宋词/ci.song.13000.json','["飞花澹澹风，破暖疏疏雨。", "香润玉阶尘，翠湿纱窗雾。", "钿筝离雁行，宝箧留钗股。", "惟有凤楼魂，夜夜江南路。"]'),
('song-ci-538','生查子','高观国','宋','宋词','song-ci','生查子','[]','香惊楚驿寒，瘦倚湘筠暮。',48,'宋词/ci.song.13000.json','["香惊楚驿寒，瘦倚湘筠暮。", "一笛已黄昏，片月尤清楚。", "沈沈冰玉魂，漠漠烟云浦。", "酸泪不成弹，又向春心聚。"]'),
('song-ci-539','解连环','高观国','宋','宋词','song-ci','解连环','[]','露条烟叶。',132,'宋词/ci.song.13000.json','["露条烟叶。", "惹长亭旧恨，几番风月。", "爱细缕、先窣轻黄，渐拂水藏鸦，翠阴相接。", "纤软风流，眉黛浅、三眠初歇。", "奈年华又晚，萦绊游蜂，絮飞晴雪。", "依依灞桥怨别。", "正千丝万绪，难禁愁绝。", "怅岁久、应长新条，念曾系花骢，屡停兰楫。", "弄影摇晴，恨闲损、春风时节。", "隔邮亭，故人望断，舞腰瘦怯。"]'),
('song-ci-540','解连环','高观国','宋','宋词','song-ci','解连环','[]','浪摇新绿。',131,'宋词/ci.song.13000.json','["浪摇新绿。", "漫芳洲翠渚，雨痕初足。", "荡霁色、流入横塘，看风外漪漪，皱纹如縠。", "藻荇萦回，似留恋、鸳飞鸥浴。", "爱娇云蘸色，媚日挼蓝，远迷心目。", "仙源漾舟岸曲。", "照芳容几树，香浮红玉。", "记那回、西洛桥边，裙翠传情，玉纤轻掬。", "三十六陂，锦鳞渺、芳音难续。", "隔垂阳，故人望断，浸愁万斛。"]'),
('song-ci-541','烛影摇红','高观国','宋','宋词','song-ci','烛影摇红','["\u897f\u6e56"]','别浦潮平，远村帆落烟江冷。',116,'宋词/ci.song.13000.json','["别浦潮平，远村帆落烟江冷。", "征鸿相唤著行飞，不耐霜风紧。", "雪意垂垂未定。", "正惨惨、云横冻影。", "酒醒情绪，日晚登临，凄凉谁问。", "行乐京华，软红不断香尘喷。", "试将心事卜归期，终是无凭准。", "寥落年华将尽。", "误玉人、高楼凝恨。", "第一休负，西子湖边，江梅春信。"]'),
('song-ci-542','忆秦娥','高观国','宋','宋词','song-ci','忆秦娥','[]','栖乌惊。',56,'宋词/ci.song.13000.json','["栖乌惊。", "隔窗月色寒於冰。", "寒於冰。", "澹移梅影，冷印疏棂。", "幽香未觉魂先清。", "无端勾起相思情。", "相思情。", "恼人无睡，直到天明。"]'),
('song-ci-543','忆秦娥','高观国','宋','宋词','song-ci','忆秦娥','[]','歌声闲。',56,'宋词/ci.song.13000.json','["歌声闲。", "兰舟只隔芙蓉湾。", "芙蓉湾。", "扇摇波影，风卷云鬟。", "馀音袅袅留馀欢。", "双鸳飞处传情难。", "传情难。", "曲终人去，愁寄湖山。"]'),
('song-ci-544','清平乐','高观国','宋','宋词','song-ci','清平乐','[]','盘枝翦翠。',54,'宋词/ci.song.13000.json','["盘枝翦翠。", "叶叶西风意。", "吹上玉人云□底。", "无限新凉气味。", "飘萧露卷烟柔。", "绝怜不逐宫流。", "寄语多情宋玉，悲秋得似宜秋。"]'),
('song-ci-545','清平乐','高观国','宋','宋词','song-ci','清平乐','[]','春蒲雨湿。',54,'宋词/ci.song.13000.json','["春蒲雨湿。", "燕子低飞急。", "云压前山群翠失。", "烟水满湖轻碧。", "小莲相见湾头。", "清寒不到青楼。", "请上琵琶弦索，今朝破得春愁。"]'),
('song-ci-546','更漏子','高观国','宋','宋词','song-ci','更漏子','[]','玉箫闲，清韵咽。',58,'宋词/ci.song.13000.json','["玉箫闲，清韵咽。", "人倚画兰愁绝。", "云恼月，月羞云。", "半溪梅影昏。", "恨春风，萧散后。", "夜夜数残更漏。", "情悄悄，思依依。", "天寒一雁飞。"]'),
('song-ci-547','东风第一枝','高观国','宋','宋词','song-ci','东风第一枝','[]','玉洁生英，冰清孕秀，一枝天地春早。',123,'宋词/ci.song.13000.json','["玉洁生英，冰清孕秀，一枝天地春早。", "素盟江国芳寒，旧约汉宫梦晓。", "溪桥独步，看洒落、仙人风表。", "似妙句、何逊扬州，最惜细吟清峭。", "香暗度、照影波渺。", "春暗寄、付情云杳。", "爱随青女横陈，更怜素娥窈窕。", "调羹雅意，好赞助、清时廊庙。", "羡韵高、只有松筠，共结岁寒难老。"]'),
('song-ci-548','东风第一枝','高观国','宋','宋词','song-ci','东风第一枝','[]','烧色回青，冰痕绽白，娇云先酿酥雨。',123,'宋词/ci.song.13000.json','["烧色回青，冰痕绽白，娇云先酿酥雨。", "纵寒不压葭尘，应时已鞭黛土。", "东君入夜，怕预恼、诗边心绪。", "意转新，无奈吟魂，醉里已题春句。", "香梦醒、几花暗吐。", "绿睡起、几丝偷舞。", "酒醅清惜重斟，菜甲嫩怜细缕。", "玉纤彩胜，愿岁岁、春风相遇。", "要等得、明日新晴，第一待寻芳去。"]'),
('song-ci-549','摊破浣溪沙・山花子','高观国','宋','宋词','song-ci','摊破浣溪沙・山花子','[]','袅袅天风响佩环。',56,'宋词/ci.song.13000.json','["袅袅天风响佩环。", "鹊桥有女夜乘鸾。", "也恨别多相见少，似人间。", "银浦无声云路渺，金风有信玉机闲。", "生怕河梁分袂处，晓光寒。"]'),
('song-ci-550','浣溪沙','高观国','宋','宋词','song-ci','浣溪沙','[]','遮坐银屏度水沈。',48,'宋词/ci.song.13000.json','["遮坐银屏度水沈。", "障风罗幕皱泥金。", "日迟宫院静愔愔。", "繁杏半窥红日薄，小怜低唱绿窗深。", "试拈犀管写春心。"]'),
('song-ci-551','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','落日下平楚，秋色到方塘。',114,'宋词/ci.song.13000.json','["落日下平楚，秋色到方塘。", "人间袢暑难耐，独有此清凉。", "龙卷八荒霖雨，鹤閟十州风露。", "回薄水云乡。", "欲识千里润，记取玉流芳。", "石兰衣，江蓠佩，芰荷裳。", "个中自有服媚，何必锦名堂。", "吸取玻璃清涨，唤起逍遥旧梦，人物俨相望。", "矫首望归路，三十六虚皇。"]'),
('song-ci-552','贺新郎','魏了翁','宋','宋词','song-ci','贺新郎','[]','独立西风里。',142,'宋词/ci.song.13000.json','["独立西风里。", "渺无尘、明河挂斗，碧天如洗。", "鳷鹊楼前迎风处，吹堕乘槎星使。", "弄札札、机中巧思。", "织就天孙云锦段，尚轻阴、朱阁留纤翳。", "亲为挽，天潢水。", "等闲富贵浮云似。", "须存留、几分清论，护持元气。", "曾把古今兴亡事，奏向前旒十二。", "虽去国、言犹在耳。", "念我独兮谁与共，谩凝思、一日如三岁。", "夜耿耿，不皇寐。"]'),
('song-ci-553','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','溥露浸秋色，零雨濯湖弦。',114,'宋词/ci.song.13000.json','["溥露浸秋色，零雨濯湖弦。", "做成特地风月，管领老臞仙。", "雁落村间柸影，鱼识桥边柱杖，虑澹境长偏。", "祗恐未免耳，惊搅日高眠。", "龙握节，貂插案，鹿衔轓。", "於公元只馀事，所乐不存焉。", "手植蓝田种子，无数阶庭成树，郁郁紫生烟。", "富贵姑勿道，借问此何缘。"]'),
('song-ci-554','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','轻露沦残暑，哉魄拟初弦。',114,'宋词/ci.song.13000.json','["轻露沦残暑，哉魄拟初弦。", "天台万八千丈，中有紫霞仙。", "正理中枢旧武，却忆邻环昨梦，重上蜀青天。", "只守伯禽法，с野万云烟。", "锦川星，郎位宿，又移躔。", "为无结辈十数，踏遍蜀山川。", "人识绍兴奉使，家有显谟科约，慧命得公传。", "从此造朝去，两地亦青毡。"]'),
('song-ci-555','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','岁岁为公寿，著语不能新。',114,'宋词/ci.song.13000.json','["岁岁为公寿，著语不能新。", "自公持节北去，我亦有遐征。", "坐我碧瑶洞府，被我石楠嘉荫，冰柱向人清。", "待屈西风指，王事有期程。", "我尝闻，由汉水，达河津。", "痴牛呆女会处，应有泛槎人。", "便向汉川东畔，直透银河左界，去上白云京。", "袖有传婿研，我欲丐馀芬。"]'),
('song-ci-556','摸鱼儿','魏了翁','宋','宋词','song-ci','摸鱼儿','[]','知年来、几番拜疏。',142,'宋词/ci.song.13000.json','["知年来、几番拜疏。", "但言归去归去。", "问归有底匆忙事，得恁陈情良苦。", "天未许。", "将花绶藻衣，为插仪庭羽。", "掉头不顾。", "念白发翁儿，本来天分，不是折腰具。", "从头数。", "多少汉庭簪组。", "滔滔车马成雾。", "争如祖帐东门外，父子缥缥高举。", "峨眉下、有几许湖山，无著春风处。", "留君不住。", "但远景楼前，追陪杖屦，莫忘却、别时语。"]'),
('song-ci-557','朝中措','魏了翁','宋','宋词','song-ci','朝中措','[]','沙堤除道火成城。',57,'宋词/ci.song.13000.json','["沙堤除道火成城。", "换得午桥清。", "寒色般添酒令，野芳抵当鉶羹。", "松馨花气，岸容山意，浦思溪情。", "谁记一时胜引，坐中喜得间平。"]'),
('song-ci-558','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','曾记武林日，岁上德星堂。',114,'宋词/ci.song.13000.json','["曾记武林日，岁上德星堂。", "相君襟度夷雅，容我少年狂。", "辇路升平风月，禁陌清时锺鼓，嗺送紫霞觞。", "回首十年事，解后衮衣乡。", "古今梦，元一辙，谩千场。", "纷纷间较目睫，谁解识方将。", "霜落南山秋实，风卷北邻夜燎，世事正匆忙。", "天意那可问，只愿善人昌。"]'),
('song-ci-559','临江仙','魏了翁','宋','宋词','song-ci','临江仙','[]','晓色昽昒云日澹，绰开坦坦长途。',70,'宋词/ci.song.13000.json','["晓色昽昒云日澹，绰开坦坦长途。", "西宁太守问程初。", "梅梢迎候骑，柳树困平芜。", "九折邛峡浑可事，不妨叱驭先驱。", "平平岂是策真无。", "抚摩迂事业，细密钝功夫。"]'),
('song-ci-560','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','人物正寥阔，有美万夫望。',114,'宋词/ci.song.13000.json','["人物正寥阔，有美万夫望。", "七年填拊方面，帏幄自金汤。", "千尺玉龙衔诏，六尺宝靮照路，载绩满旗常。", "富贵姑勿道，难得此芬芳。", "尝试看，今古梦，几千场。", "人情但较目睫，谁解识方将。", "霜落南山秋实，风卷北邻夜燎，世事正匆忙。", "海内知公者，只愿寿而臧。"]'),
('song-ci-561','临江仙','魏了翁','宋','宋词','song-ci','临江仙','[]','怪见江乡文物地，轻豪争逐春妍。',70,'宋词/ci.song.13000.json','["怪见江乡文物地，轻豪争逐春妍。", "银花斜□紫金鞭。", "千灯浑是泪，一笑不论钱。", "今岁遨头穷相眼，繁华不学常年。", "只余底事索人怜。", "诗书真气味，农扈老风烟。"]'),
('song-ci-562','鹧鸪天','魏了翁','宋','宋词','song-ci','鹧鸪天','[]','日日春风满范围。',64,'宋词/ci.song.13000.json','["日日春风满范围。", "海棠又发去年枝。", "月笼火树更深后，露滴燕支晓起时。", "看不足，醉为期。", "宵征宁问角巾敧。", "一春好处无多子，不分西园掇取归。"]'),
('song-ci-563','临江仙','魏了翁','宋','宋词','song-ci','临江仙','[]','脚踏西郊红世界，才知春意分明。',70,'宋词/ci.song.13000.json','["脚踏西郊红世界，才知春意分明。", "不须更说锦官城。", "春来游冶骑，得得为渠停。", "停到花眠人且去，酒杯苦欲留行。", "直须醉饮到参横。", "不因歌白雪，三日作狂酲。"]'),
('song-ci-564','柳梢青','魏了翁','宋','宋词','song-ci','柳梢青','[]','撺掇花枝，趱那天气，一半春休。',61,'宋词/ci.song.13000.json','["撺掇花枝，趱那天气，一半春休。", "未分真休，平湖新涨，稚绿初抽。", "等闲作个扁舟。", "便都把、湖光卷收。", "世事元来，都缘本有，不在他求。"]'),
('song-ci-565','摸鱼儿','魏了翁','宋','宋词','song-ci','摸鱼儿','[]','向江头、几回凝望，垂杨那畔舟才舣。',141,'宋词/ci.song.13000.json','["向江头、几回凝望，垂杨那畔舟才舣。", "江神似识东归意。", "故放一篙春水。", "却总被。", "三百里人家、祖帐连天起。", "且行且止。", "便为汝迟留，三朝两日，如此只如此。", "还须看，世上忧端如猬。", "一枰白黑棋子。", "肥边瘦腹都闲事。", "毕竟到头何似。", "当此际。", "要默识沈思，一著惺惺地。", "目前谁是。", "料当局诸公，敛容缩手，日夜待公至。"]'),
('song-ci-566','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','有匪碧岩使，长佩奏琅球。',114,'宋词/ci.song.13000.json','["有匪碧岩使，长佩奏琅球。", "门前初暑才涨，一室淡於秋。", "帘卷峨眉烟雨，袖挟西川风露，满眼绿阴稠。", "人物眇然甚，得似此风流。", "此何时，公犹滞，剑南州。", "分明忧在目睫，只恁付悠悠。", "未问人谋当否，须信天生贤哲，不只等闲休。", "努力崇明德，巨浸要平舟。"]'),
('song-ci-567','贺新郎','魏了翁','宋','宋词','song-ci','贺新郎','[]','汉使来何许。',142,'宋词/ci.song.13000.json','["汉使来何许。", "到如今、天边又是，薰弦三度。", "见说山深人睡稳，细雨自催茶户。", "向滴博、云间看取。", "料得权奇空却后，指浮云、万里追风去。", "跨燕越，抹秦楚。", "不妨且为斯人驻。", "正年来、忧端未歇，壮怀谁吐。", "顷刻阴晴千万态，怎解绸缪未雨。", "算此事、谁宽西顾。", "待洗岷峨凄怆气，为八荒、更著深长虑。", "间两社，辅明主。"]'),
('song-ci-568','念奴娇','魏了翁','宋','宋词','song-ci','念奴娇','[]','固陵江上，暮云急、一夜打头风雨。',119,'宋词/ci.song.13000.json','["固陵江上，暮云急、一夜打头风雨。", "催送江船上水，笑指□山归去。", "靴帽丛中，渔樵席上，总是安行处。", "惟馀旧话，为公今日拈取。", "见说家近岷山，翠云平楚，万古青如故。", "要把平生三万轴，唤取山灵分付。", "庐阜嵩高，睢阳岳麓，会与岷为伍。", "及时须做，鬓边应未迟暮。"]'),
('song-ci-569','木兰花慢','魏了翁','宋','宋词','song-ci','木兰花慢','[]','怕年来年去，渐雅志、易华颠。',122,'宋词/ci.song.13000.json','["怕年来年去，渐雅志、易华颠。", "叹梦里青藜，间边银信，望外朱轓。", "十年竟成何事，虽万锺、於我曷加焉。", "海上潮生潮落，山头云去云还。", "人生天地两仪间。", "只住百来年。", "今三纪虚过，七旬强半，四帙看看。", "当时只忧未见，恐如今、见得又徒然。", "夜静花间明露，晓凉竹外晴烟。"]'),
('song-ci-570','满江红','魏了翁','宋','宋词','song-ci','满江红','[]','有美人兮，招不至、几回凝伫。',115,'宋词/ci.song.13000.json','["有美人兮，招不至、几回凝伫。", "应只为、家山自好，不堪他顾。", "忙里抽头真得计，闲中袖手看成趣。", "念从前、出处总无心，天分付。", "云冉冉，更吞吐。", "泉活活，无朝暮。", "与自家意思，一般容与。", "月壑晓寒垂叶露，风窗午睡连山雨。", "看苍颜、白发两闲人，摩今古。"]'),
('song-ci-571','满江红','魏了翁','宋','宋词','song-ci','满江红','[]','宇宙中间，还独笑、谁疏谁密。',112,'宋词/ci.song.13000.json','["宇宙中间，还独笑、谁疏谁密。", "正从容行处，山停川溢。", "锺鼎勒铭模物象，山林赐路开行荜。", "要不如、胸次祗熙熙，无今昔。", "便百中，穿牙戟。", "怕六凿，生虚室。", "为幽香小伫，旋供吟笔。", "人事未须劳预虑，天公浑不消余力。", "看雨馀、云卷约帘旌，明红日。"]'),
('song-ci-572','鹧鸪天','魏了翁','宋','宋词','song-ci','鹧鸪天','[]','尚忆都门祖帐时。',64,'宋词/ci.song.13000.json','["尚忆都门祖帐时。", "重来动是十年期。", "云拖暮雨留行色，露挟秋凉入酒卮。", "湖上雁，水边犀。", "未须矫首叹来迟。", "北风满地尘沙暗，宣室方劳丙夜思。"]'),
('song-ci-573','满江红','魏了翁','宋','宋词','song-ci','满江红','[]','秋意冷然，对宇宙、一尊相属。',115,'宋词/ci.song.13000.json','["秋意冷然，对宇宙、一尊相属。", "君看取、都无凝滞，天机纯熟。", "水拍池塘鸿雁聚，露浓庭畹芝兰馥。", "笑何曾、一事上眉头，萦心曲。", "兴不浅，船明玉。", "人更健，巾横幅。", "问人间底处，升沉迟速。", "气压暗岩虹半吐，眼明平楚云相逐。", "但年年、屈指问西风，篘新醁。"]'),
('song-ci-574','鹧鸪天','魏了翁','宋','宋词','song-ci','鹧鸪天','[]','月落星稀露气香。',64,'宋词/ci.song.13000.json','["月落星稀露气香。", "烟销日出晓光凉。", "天东扶木三千丈，一片丹心似许长。", "淇以北，洛之阳。", "买花移竹且迷藏。", "九重阊阖开黄道，未信低回两鬓霜。"]'),
('song-ci-575','满江红','魏了翁','宋','宋词','song-ci','满江红','[]','湖水平漪，与我意、一般容与。',115,'宋词/ci.song.13000.json','["湖水平漪，与我意、一般容与。", "任多少、双凫乘雁，落花飞絮。", "露冷云寒烟外竹，霜明日洁梅边路。", "怪天随、人意作阴晴，无非数。", "方寸地，图书府。", "老太史，亲分付。", "况身名四海，未为不遇。", "用舍行藏皆有命，时来将相还须做。", "且闲中、袖手阅时人，摩今古。"]'),
('song-ci-576','虞美人','魏了翁','宋','宋词','song-ci','虞美人','[]','许时闭户间疏散。',66,'宋词/ci.song.13000.json','["许时闭户间疏散。", "风月无人管。", "自从阳律一番新。", "又把前回风月、送西邻。", "浮云富贵非公愿。", "只愿公身健。", "更教剩活百来年。", "此老终须不枉、在人间。"]'),
('song-ci-577','醉落魄・一斛珠','魏了翁','宋','宋词','song-ci','醉落魄・一斛珠','[]','无边春色。',67,'宋词/ci.song.13000.json','["无边春色。", "试从汉谕堂边觅。", "儿前上寿孙扶掖。", "九十娘娘，身是五朝客。", "眼前富贵浑闲历。", "个中真乐天然的。", "儿孙强劝持馀沥。", "娘道休休，明日儿生日。"]'),
('song-ci-578','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','古说士夫郡，犹欠殿头魁。',114,'宋词/ci.song.13000.json','["古说士夫郡，犹欠殿头魁。", "记曾分付公等，行矣勉之哉。", "世事弈棋无定，甲子循还复尔，不免且低回。", "人物价自定，万事付衔杯。", "试与公，同握手，上春台。", "繁红丽紫何限，转首便尘埃。", "欲识化工定处，须向报秋时节，未用较先开。", "休道屋犹矮，卿相个中来。"]'),
('song-ci-579','临江仙','魏了翁','宋','宋词','song-ci','临江仙','[]','天为西南分八使，更分四道蕃臣。',80,'宋词/ci.song.13000.json','["天为西南分八使，更分四道蕃臣。", "争如齿宿彩衣新。", "亲年开百岁，又见子生孙。", "一度平反供一笑，无边桃李皆春。", "便归天上极恩荣。", "为君图寿母，去年曾以寿母图为献。", "更看太夫人。"]'),
('song-ci-580','鹧鸪天','魏了翁','宋','宋词','song-ci','鹧鸪天','[]','遥想庭闱上寿时。',64,'宋词/ci.song.13000.json','["遥想庭闱上寿时。", "芝兰玉树俨成围。", "问娘鼎鼎修何行，一样都生及第儿。", "春淡沲，日熹微。", "两头娘子玉东西。", "一杯更为诸孙寿，子舍新来恰上楣。"]'),
('song-ci-581','柳梢青','魏了翁','宋','宋词','song-ci','柳梢青','[]','记得年年。',61,'宋词/ci.song.13000.json','["记得年年。", "阿奴碌碌，常在眼前。", "彩舫吴天，锦轮蜀地，阅尽山川。", "今年苦恋家园。", "便咫尺、千山万山。", "但想称觞，三荆树下，丛桂堂边。"]'),
('song-ci-582','谒金门','魏了翁','宋','宋词','song-ci','谒金门','[]','那复有。',53,'宋词/ci.song.13000.json','["那复有。", "气味醲於春酒。", "犹向故乡怀印绶。", "相过何日又。", "吐出心肠锦绣。", "问我阿娘依旧。", "娘亦祝君如柏寿。", "相看霜雪后。"]'),
('song-ci-583','清平乐','魏了翁','宋','宋词','song-ci','清平乐','[]','蓝田玉种。',54,'宋词/ci.song.13000.json','["蓝田玉种。", "为我酬清供。", "香压冰肌犹怕重。", "更倩留仙群捧。", "看花美倩偏工。", "举花消息方浓。", "此笑知谁领解，无言独倚东风。"]'),
('song-ci-584','清平乐','魏了翁','宋','宋词','song-ci','清平乐','[]','谁分天种。',54,'宋词/ci.song.13000.json','["谁分天种。", "来上花鬘供。", "绿叶素云姿雅重。", "那得愁心频捧。", "他花自是无工。", "不关香淡香浓。", "才问为谁含笑，盈盈靴面敧风。"]'),
('song-ci-585','临江仙','魏了翁','宋','宋词','song-ci','临江仙','[]','双荔堂前呼大撇，蚪枝看取垂垂。',70,'宋词/ci.song.13000.json','["双荔堂前呼大撇，蚪枝看取垂垂。", "帝怜尘土著冰姿。", "故教冻雨过，浴出万红衣。", "绿幄赪圆高下处，中含玉色清夷。", "涴人应笑太真肥。", "破除千古恨，须待谪仙诗。"]'),
('song-ci-586','浣溪沙','魏了翁','宋','宋词','song-ci','浣溪沙','[]','晓镜摇空髻耸丫。',48,'宋词/ci.song.13000.json','["晓镜摇空髻耸丫。", "夜盘承露掌分叉。", "翠芳绰约总无华。", "欲往从之空怅望，潜虽伏矣莫藏遮。", "淤泥深处瑞莲花。"]'),
('song-ci-587','浣溪沙','魏了翁','宋','宋词','song-ci','浣溪沙','[]','一日嘉名万口传。',48,'宋词/ci.song.13000.json','["一日嘉名万口传。", "都凭新乐播芳鲜。", "非关呈瑞作人妍。", "地褊不妨金步稳，境幽生怕鼓声填。", "馀尊相与重留连。"]'),
('song-ci-588','浣溪沙','魏了翁','宋','宋词','song-ci','浣溪沙','[]','密叶留香护境天。',48,'宋词/ci.song.13000.json','["密叶留香护境天。", "好风时雨媚清涟。", "亭亭双秀倚湖弦。", "造化曾居公掌握，呈祥宁许百花先。", "聊占棣萼蒂芳连。"]'),
('song-ci-589','浣溪沙','魏了翁','宋','宋词','song-ci','浣溪沙','[]','试问伊谁若是班。',48,'宋词/ci.song.13000.json','["试问伊谁若是班。", "二乔铜雀锁孱颜。", "千年痕露尚馀潸。", "羞向眼前供妩媚，独於静处惬幽娴。", "人情多少逐河间。"]'),
('song-ci-590','贺新郎','魏了翁','宋','宋词','song-ci','贺新郎','[]','只记来时节。',142,'宋词/ci.song.13000.json','["只记来时节。", "又三年、朱炜过了，恰如时霎。", "独立薰风苍凉外，笑傍环湖花月。", "多少事、欲拈还辍。", "扶木之阴三千丈，远茫茫、无计推华发。", "容易过，三十八。", "此身待向清尊说。", "似江头、泛乎不系，扁舟一叶。", "将我东西南北去，都任长年旋折。", "风不定、川云如撇。", "惟有君恩浑未报，又故山、猿鹤催归切。", "将进酒，缓歌阕。"]'),
('song-ci-591','满江红','魏了翁','宋','宋词','song-ci','满江红','[]','物象芸芸，知几许、功夫来格。',115,'宋词/ci.song.13000.json','["物象芸芸，知几许、功夫来格。", "更时把、荷衣芰制，从容平熨。", "云淡天空诗献状，竹深花静机藏密。", "对窗前、屏岫老仪刑，真颜色。", "商古道，谁俦匹。", "评今士，谁钧敌。", "向平舟问雁，久间霜翮。", "枰上举棋元不定，磨边旋蚁何曾息。", "傥天公、有意要平治，饶华发。"]'),
('song-ci-592','念奴娇','魏了翁','宋','宋词','song-ci','念奴娇','[]','修姱人物，元如许、谁把屏星留却。',120,'宋词/ci.song.13000.json','["修姱人物，元如许、谁把屏星留却。", "弄破峨眉山月影，似作平分消息。", "卷雾名谭，翳云长袖，未称三池客。", "且然袖手，人间烦暑方剧。", "分手未见前期，风前耿耿，目断斜阳角。", "亦欲乘风归去也，问讯故山猿鹤。", "紞鼓催鸡，挥弦送雁，转首成乖各。", "愿加飡饭，书来频寄新作。"]'),
('song-ci-593','贺新郎','魏了翁','宋','宋词','song-ci','贺新郎','[]','久向闲边著。',142,'宋词/ci.song.13000.json','["久向闲边著。", "对沧江、烟轻日淡，雨疏云薄。", "一片闲心无人会，独倚团团羊角。", "便舍瑟、铿然而作。", "容室中间分明见，暮鸢飞、不尽天空阔。", "青山外，断霞末。", "看来此意无今昨。", "都不论、穷通得失，镇长和乐。", "此道舒之弥八极，卷却不盈一握。", "但长把、根基恢拓。", "将相时来皆可做，似君家、祖烈弥关洛。", "康国步，整戎略。"]'),
('song-ci-594','鹊桥仙','魏了翁','宋','宋词','song-ci','鹊桥仙','[]','银潢濯月，金茎团露，一日清於一日。',68,'宋词/ci.song.13000.json','["银潢濯月，金茎团露，一日清於一日。", "昨宵云雨暗河桥，似划地、不如今夕。", "乘查信断，搘机人去，误了桥边消息。", "天孙问我巧何如，正为怕、不曾陈乞。"]'),
('song-ci-595','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','["\u897f\u6e56"]','促织谁遣汝，唧唧不能休。',114,'宋词/ci.song.13000.json','["促织谁遣汝，唧唧不能休。", "揽衣起观，四顾河汉淡如油。", "露下南山荟蔚，风抹西湖菱芰，客感浩悠悠。", "尚此推不去，岁寿两公侯。", "自侯归，闲日月，几春秋。", "东方千骑，何事白首去为州。", "会有葛公清侣，携上神仙官府，玉案侍前旒。", "却袖经纶手，归伴赤松游。"]'),
('song-ci-596','八声甘州','魏了翁','宋','宋词','song-ci','八声甘州','[]','自王家无怨住襄城，世总生贤。',116,'宋词/ci.song.13000.json','["自王家无怨住襄城，世总生贤。", "似谢阶兰玉，马庭梧竹，一一堪怜。", "富贵关人何事，且问此何缘。", "又踏前朝脚，领蜀山川。", "点检重关复阁，尚甘棠匝地，乔木参天。", "中兴规画，父老至今传。", "六十年、山河未改，只芳菲、不断紧相联。", "相将又，参陪宰席，还似当年。"]'),
('song-ci-597','贺新郎','魏了翁','宋','宋词','song-ci','贺新郎','[]','此别情何限。',142,'宋词/ci.song.13000.json','["此别情何限。", "最关情、一林醒石，重湖宾雁。", "几度南楼携手上，十二阑干凭暖。", "肯容我、樽前疏散。", "底事匆匆催人去，黯西风、别恨千千万。", "截不断，整仍乱。", "三年瞥忽如飞电。", "记从前、心情双亮，意词交划。", "千古黎苏登临意，人道於今重见。", "又分付、水流冰冸。", "满腹馀疑今谁问，上牛头、净拭乾坤眼。", "聊尔耳，恐不免。"]'),
('song-ci-598','贺新郎','魏了翁','宋','宋词','song-ci','贺新郎','[]','多少龙头客。',143,'宋词/ci.song.13000.json','["多少龙头客。", "数从前、何官不做，清名难得。", "万里将旜归报汉，青锁还应催当夕。", "又一叶、扁舟去国。", "许史庐前车成雾，未如公、正怕云霄逼。", "留不尽，二三策。", "一声千里楼前笛。", "遏天涯、浮云不断，镇长秋色。", "试上层楼分明看，无数水遥山碧。", "问此意、有谁曾识。", "独抱孤衷苍茫外，满阑干，都是长安日。", "终有待，佐皇极。"]'),
('song-ci-599','虞美人','魏了翁','宋','宋词','song-ci','虞美人','[]','一年一度屠苏酒。',66,'宋词/ci.song.13000.json','["一年一度屠苏酒。", "老我惊多又。", "明年岂是更无年。", "已是虚过、三十八年前。", "世间何物堪称好。", "家有斑衣老。", "相期他日早还归。", "怕似瞻由、出处不曾齐。"]'),
('song-ci-600','念奴娇','魏了翁','宋','宋词','song-ci','念奴娇','[]','岸容山意，随春好，人在春风独立。',120,'宋词/ci.song.13000.json','["岸容山意，随春好，人在春风独立。", "立尽闲云来又去，目断一天红日。", "岂不怀归，於焉信宿，此意无人识。", "只看鬓发，丝丝都为人白。", "风露正满人间，齁齁睡息，浑不知南北。", "要上南山披荟蔚，谁是同心相觅。", "天运无穷，事机难料，只有储才急。", "愿公寿考，养成元祐人物。"]'),
('song-ci-601','朝中措','魏了翁','宋','宋词','song-ci','朝中措','[]','天公只解作丰年。',57,'宋词/ci.song.13000.json','["天公只解作丰年。", "不相冶游天。", "小队春旗不动，行庖晚突无烟。", "吟须拈断，寒炉拨尽，雁自天边。", "唤起主人失笑，寒灰依旧重然。"]'),
('song-ci-602','洞庭春色・沁园春','魏了翁','宋','宋词','song-ci','洞庭春色・沁园春','[]','花帽檐行，宝钗梁畔，还是上元。',136,'宋词/ci.song.13000.json','["花帽檐行，宝钗梁畔，还是上元。", "看去年芳草，如今又绿，当时皓月，此夕仍圆。", "节序驱人人不解，道岁岁年年都一般。", "看承处，有烛龙照夜，铁凤连天。", "东风不知倦客，又吹向楼阁山巅。", "任管弦闹处，诗豪得志，绮罗香里，侠少当权。", "客与溪翁无一事，但随俗簪花含笑看。", "无限意，更醉骑花影，饱看丰年。"]'),
('song-ci-603','鹧鸪天','魏了翁','宋','宋词','song-ci','鹧鸪天','[]','春漏逢欢恐不深。',64,'宋词/ci.song.13000.json','["春漏逢欢恐不深。", "银花火树粲成林。", "酒中和乐无穷味，烛里光明一寸心。", "金马朔，玉堂寻。", "风流文献未如今。", "连宵坐我东风里，春满肝脾月满襟。"]'),
('song-ci-604','念奴娇','魏了翁','宋','宋词','song-ci','念奴娇','[]','刘郎初度随春到，尚记彩衣春立。',119,'宋词/ci.song.13000.json','["刘郎初度随春到，尚记彩衣春立。", "又上夫人千岁寿，相望不争旬日。", "琴瑟仪刑，山河态度，长是春风识。", "都将和气，蒸成满院红白。", "我被五斗红陈，三升官酒，驱到郪城北。", "解后相逢同一笑，此会几年难觅。", "宝蜡烧春，花光缟夜，未放觥筹急。", "天然真乐，傥来知是疣物。"]'),
('song-ci-605','玉楼春','魏了翁','宋','宋词','song-ci','玉楼春','["\u957f\u6c5f"]','射洪官酒元曾醉。',67,'宋词/ci.song.13000.json','["射洪官酒元曾醉。", "又六十八年重至。", "长江驿畔水如蓝，也应似、向人重翠。", "人生岂必高官贵。", "愿长对、诗书习气。", "陶家髻子作宾筵，有如个、嘉宾也未。"]'),
('song-ci-606','贺新郎','魏了翁','宋','宋词','song-ci','贺新郎','[]','谁主谁为客。',142,'宋词/ci.song.13000.json','["谁主谁为客。", "叹人生、别离容易，会逢难得。", "省户高门十年梦，瞥忽浑如昨夕。", "风不定、乱云飞急。", "本自无心图富贵，也元知、富贵无缘逼。", "且还我，兔园策。", "谁知一曲柯亭笛。", "向天涯、依然解后，长安本色。", "怪我阿奶今老眼，已是看朱成碧。", "但犹记、黄裳曾识。", "多谢殷勤无以报，愿阿奶、长健如今日。", "送公子，上霄极。"]'),
('song-ci-607','洞仙歌','魏了翁','宋','宋词','song-ci','洞仙歌','[]','人生一世。',101,'宋词/ci.song.13000.json','["人生一世。", "如此元如此。", "造化都从起时起。", "看庭前桃李，弄蕊开花，还又看，一度成阴结子。", "母寿亲认取，叶叶枝枝，一气分来结成底。", "更得故人书，遗我新词，把寸心、分明指似。", "信过眼、浮华几何时，剩培植根心，等闲千岁。"]'),
('song-ci-608','西江月','魏了翁','宋','宋词','song-ci','西江月','[]','曾记刘安鸡犬，误随鼎灶登仙。',58,'宋词/ci.song.13000.json','["曾记刘安鸡犬，误随鼎灶登仙。", "十年尘土涴行缠。", "怪见霞觞频劝。", "会合元非择地，乖逢宁得非天。", "妇闻风月正б娟。", "亲泼床头醅面。"]'),
('song-ci-609','念奴娇','魏了翁','宋','宋词','song-ci','念奴娇','[]','梦中犹记，来时路、五马踟蹰攒立。',120,'宋词/ci.song.13000.json','["梦中犹记，来时路、五马踟蹰攒立。", "江北城南春澹沲，山锁一天晴日。", "伊轧征车，徊徨去意，只有东风识。", "如今还在，谁人伴我浮白。", "天外一曲阳春，依然有脚，来到萱堂北。", "不是奇情双照亮，肯寄鳞鸿相觅。", "酒引曹醇，歌翻楚调，触拨归心急。", "醉魂时绕，莺花世界风物。"]'),
('song-ci-610','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','人道三十九，岁暮日斜时。',114,'宋词/ci.song.13000.json','["人道三十九，岁暮日斜时。", "儿今如许，才觉三十九年非。", "昨被玉山楼取，今仗牛山挽住，役役不知疲。", "自己未能信，漫仕亦何为。", "亦何为，应自叹，不如归。", "问归亦有何好，堂上彩成围。", "上下东冈南陌，来往北邻西舍，逖地看儿啼。", "富贵适然耳，此乐几人知。"]'),
('song-ci-611','蝶恋花','魏了翁','宋','宋词','song-ci','蝶恋花','[]','早岁腾身隮辇路。',70,'宋词/ci.song.13000.json','["早岁腾身隮辇路。", "秋月春风，只作浑闲度。", "手挟雷公驱电母。", "袖中双剑蛟龙舞。", "如此壮心空浪许。", "四十明朝，忍把流年数。", "又过一番生日去。", "寿觞羞对亲朋举。"]'),
('song-ci-612','醉蓬莱','魏了翁','宋','宋词','song-ci','醉蓬莱','[]','又一番雨过，倚阁炎威，探支秋色。',120,'宋词/ci.song.13000.json','["又一番雨过，倚阁炎威，探支秋色。", "前度刘郎，为故园一出。", "黄发丝丝，赤心片片，俨中朝人物。", "诗里香山，酒中六一，花前康节。", "倦客才归，新亭恰就，萱径荫浓，卜林香发。", "尊酒相逢，看露花风叶。", "跃跃静神，生生意思，入眼浑如涤。", "更祝天公，收回积潦，放开晴日。"]'),
('song-ci-613','江城子','魏了翁','宋','宋词','song-ci','江城子','[]','水花湖荡翠连天。',86,'宋词/ci.song.13000.json','["水花湖荡翠连天。", "记年年。", "甚因缘。", "斗鸭阑干，云雾踏青妍。", "人似风流唐太白，披紫绮，卧青莲。", "如今别思浩如川。", "欲腾骞。", "隔风烟。", "月到天心，人影在长编。", "只有此身飞不去，翔雁侧，狎鸥边。"]'),
('song-ci-614','贺新郎','魏了翁','宋','宋词','song-ci','贺新郎','[]','千里楼前客。',142,'宋词/ci.song.13000.json','["千里楼前客。", "数从前、几般契分，更谁同得。", "尚记流莺催人去，又见莎鸡当夕。", "叹天运、相煎何急。", "幸自江山皆吾土，被南薰、吹信还相逼。", "临大路，控长策。", "向来风月苏家笛。", "问天边、玉堂何似，黄冈秋色。", "万事无心随处好，风定一川澄碧。", "些个事、非公谁识。", "我亦年来知此意，但聪明、不及於前日。", "谁为我，指无极。"]'),
('song-ci-615','满江红','魏了翁','宋','宋词','song-ci','满江红','[]','许大才名，知几许、功夫做得。',115,'宋词/ci.song.13000.json','["许大才名，知几许、功夫做得。", "独自殿、三朝耆旧，岿然山立。", "出处只从心打当，去留不管人忻戚。", "抱孤衷、脉脉倚秋风，无人识。", "龙可养，凡鳞匹。", "鸾可挚，凡禽敌。", "便翩然归作，玉龙仙客。", "枰上举棋元不定，磨边旋蚁何曾息。", "傥天公、有意要平治，须华发。"]'),
('song-ci-616','江城子','魏了翁','宋','宋词','song-ci','江城子','[]','一襟满贮梓城春。',86,'宋词/ci.song.13000.json','["一襟满贮梓城春。", "笑声频。", "笔挥银。", "自有江山，长是管将迎。", "不似如今归去客，云外步，水边身。", "萧然今代杰魁人。", "混光尘。", "越精神。", "不把浮云，轩冕拂天真。", "化洽堂边应创见，人物旧，榜颜新。"]'),
('song-ci-617','江城子','魏了翁','宋','宋词','song-ci','江城子','[]','如公何地不阳春。',86,'宋词/ci.song.13000.json','["如公何地不阳春。", "往来频。", "醉倾银。", "闻道河阳，童稚正欢迎。", "移向德威堂上著，疑潞国，是前身。", "行人还又送行人。", "夜无尘。", "对丰神。", "自古心知，别语转情真。", "须信人生归去好，三径旧，四时新。"]'),
('song-ci-618','江城子','魏了翁','宋','宋词','song-ci','江城子','[]','西来紫马倦行春。',86,'宋词/ci.song.13000.json','["西来紫马倦行春。", "上书频。", "阙排银。", "愿听臣归，子舍便将迎。", "又为老臣全晚节，关教化，系臣身。", "帝心终眷老成人。", "想音尘。", "倍留神。", "且把闲风，淡月与全真。", "出处如公都有数，今古梦，几番新。"]'),
('song-ci-619','江城子','魏了翁','宋','宋词','song-ci','江城子','[]','与君同醉梓州春。',86,'宋词/ci.song.13000.json','["与君同醉梓州春。", "不辞频。", "漏更银。", "尚记梅时，出郭喜相迎。", "又对西风斟别酒，云过眼，月分身。", "傥来官职不关人。", "等微尘。", "苦劳神。", "更向中间，谩说假和真。", "只有交朋关分义，无久近，与陈新。"]'),
('song-ci-620','鹧鸪天','魏了翁','宋','宋词','song-ci','鹧鸪天','[]','公在春官我已归。',64,'宋词/ci.song.13000.json','["公在春官我已归。", "公来东蜀我居西。", "及公自遂移潼日，正我由潼使遂时。", "如有碍，巧相违。", "人生禁得几分飞。", "只祈彼此身长健，同处何曾有别离。"]'),
('song-ci-621','木兰花慢','魏了翁','宋','宋词','song-ci','木兰花慢','[]','记北人骑屋，看龙首、许仲元。',120,'宋词/ci.song.13000.json','["记北人骑屋，看龙首、许仲元。", "自拥节来归，持荷直上，谁与争先。", "好官到头做彻，些儿欠缺便徒然。", "我爱庆元龙首，当春不逐时妍。", "人生天地两仪间。", "且住百来年。", "数初度庚寅，未来甲子，尽自宽闲。", "太平竟须公等，终不成、造物谩生贤。", "拓取面前路径，著身常要平宽。"]'),
('song-ci-622','木兰花慢','魏了翁','宋','宋词','song-ci','木兰花慢','[]','记薰风殿上，曾当暑、侍君王。',122,'宋词/ci.song.13000.json','["记薰风殿上，曾当暑、侍君王。", "看绛服临轩，白袍当殿，流汗翻浆。", "今年诏书催发，趁槐庭、初夏午阴凉。", "瘦马行时腊雪，叠猿啼处年光。", "大科异等士之常。", "难得姓名香。", "叹陋习相承，驹辕垂耳，麟楦成行。", "平生学为何事，到得时、遇主忍留藏。", "看取杏花归路，身名浑是芬芳。"]'),
('song-ci-623','木兰花慢','魏了翁','宋','宋词','song-ci','木兰花慢','[]','问梅花月里，谁解唱、小秦王。',122,'宋词/ci.song.13000.json','["问梅花月里，谁解唱、小秦王。", "向三叠声中，兰桡荃棹，桂醑椒浆。", "明朝濮渝江上，对暮云、平野北风凉。", "准拟八千里路，破除九十春光。", "砚涵槐影漾旗常。", "披拂御炉香。", "念人世难逢，玉阶方寸，陛楯颜行。", "休言举人文字，系一生、穷达与行藏。", "凡卉都随岁换，幽兰不为人芳。"]'),
('song-ci-624','西江月','魏了翁','宋','宋词','song-ci','西江月','[]','一段同云似练，更无剩幅间边。',58,'宋词/ci.song.13000.json','["一段同云似练，更无剩幅间边。", "玉娥不怕五更寒。", "剪就飞花片片。", "酒里吟边竞爽，枝头枝底争妍。", "入春无物不芳鲜。", "只我依然颜面。"]'),
('song-ci-625','减字木兰花','魏了翁','宋','宋词','song-ci','减字木兰花','[]','新符旧历。',52,'宋词/ci.song.13000.json','["新符旧历。", "交割新年馀七日。", "谁识春华。", "元住东川太守家。", "一年一曲。", "拟尽形容无可祝。", "愿似庭梅。", "长向春风伴斗魁。"]'),
('song-ci-626','满江红','魏了翁','宋','宋词','song-ci','满江红','[]','见说新来，把闲事、都齐阁束。',115,'宋词/ci.song.13000.json','["见说新来，把闲事、都齐阁束。", "日用处、浑无凝滞，天机纯熟。", "帘卷春风琴静好，庭移晓日兰芬馥。", "笑可曾，些子上眉头，萦心曲。", "吞宇宙，船明玉。", "批风月，诗成轴。", "问人间底处，升沈荣辱。", "与我言兮虽我愿，不吾以也吾常足。", "但年年、先后放灯时，篘新醁。"]'),
('song-ci-627','海棠春令・海棠春','魏了翁','宋','宋词','song-ci','海棠春令・海棠春','[]','东君惯得花无赖。',58,'宋词/ci.song.13000.json','["东君惯得花无赖。", "看不尽、冶容娇态。", "拟傍小车来，又被轻阴绐。", "阴晴长与随人改。", "且特地、留花相待。", "荣悴故寻常，生意长如海。"]'),
('song-ci-628','临江仙','魏了翁','宋','宋词','song-ci','临江仙','[]','自有天然真富贵，本来不为人妍。',70,'宋词/ci.song.13000.json','["自有天然真富贵，本来不为人妍。", "谨将醉眼著繁边。", "更擎高烛照，惊搅夜深眠。", "花不能言还自笑，何须有许多般。", "满空明月四垂天。", "柳边红沁露，竹外翠微烟。"]'),
('song-ci-629','朝中措','魏了翁','宋','宋词','song-ci','朝中措','[]','玳筵绮席绣芙蓉。',57,'宋词/ci.song.13000.json','["玳筵绮席绣芙蓉。", "客意乐融融。", "吟罢风头摆翠，醉馀日脚沈红。", "简书绊我，赏心无托，笑口难逢。", "梦草闲眠暮雨，落花独倚春风。"]'),
('song-ci-630','临江仙','魏了翁','宋','宋词','song-ci','临江仙','[]','去岁玉堂山下住，母旁后弟前哥。',70,'宋词/ci.song.13000.json','["去岁玉堂山下住，母旁后弟前哥。", "今年作县古松坡。", "静参朱祭酒，间印马头陀。", "去路更无山隔断，春风跋马经过。", "不妨缓辔尽婆娑。", "愿申临别语，长使得天多。"]'),
('song-ci-631','柳梢青','魏了翁','宋','宋词','song-ci','柳梢青','[]','昨夕相逢。',61,'宋词/ci.song.13000.json','["昨夕相逢。", "烟苞沁绿，月艳羞红。", "旭日生时，初春景里，太极光中。", "别来三日东风。", "已非复、吴中阿蒙。", "须信中间、阴阳大造，雨露新功。"]'),
('song-ci-632','小重山','魏了翁','宋','宋词','song-ci','小重山','[]','养得儿男百不中。',70,'宋词/ci.song.13000.json','["养得儿男百不中。", "年年随举子，踏春风。", "寿觞庭院燕泥融。", "将雏处、长是半西东。", "移孝便为忠。", "儿行虽在远，母心同。", "若将一念答天公。", "归来拜，也胜橘双红。"]'),
('song-ci-633','南柯子・南歌子','魏了翁','宋','宋词','song-ci','南柯子・南歌子','[]','暮雨收尘马，薰风起箨龙。',62,'宋词/ci.song.13000.json','["暮雨收尘马，薰风起箨龙。", "夜凉人锁武成宫。", "却忆亲旁、寿饼荐油葱。", "谁锡诗人类，应晞颖谷封。", "儿行虽远母心通。", "触拨今宵、梦逐彩云东。"]'),
('song-ci-634','眼儿媚','魏了翁','宋','宋词','song-ci','眼儿媚','[]','梦魂不踏正牙班。',58,'宋词/ci.song.13000.json','["梦魂不踏正牙班。", "直作五云闲。", "简编真乐，埙篪雅韵，菽水清欢。", "都将瞥忽荣华事，春梦晓云看。", "只期他日，实愿受用，大耐高官。"]'),
('song-ci-635','眼儿媚','魏了翁','宋','宋词','song-ci','眼儿媚','[]','不居上界列仙班。',58,'宋词/ci.song.13000.json','["不居上界列仙班。", "梅隐寄幽闲。", "玉堂云晓，玉珍雨夜，总是真欢。", "如兄才誉居人上，鹏路正看看。", "只祈兄弟，长随母健，不爱高官。"]'),
('song-ci-636','洞仙歌','魏了翁','宋','宋词','song-ci','洞仙歌','[]','寿觞庭户，正柳明桃炫。',100,'宋词/ci.song.13000.json','["寿觞庭户，正柳明桃炫。", "拟斫江鱼脍银线。", "被春风吹入，花锦城中、惟有梦，时到轻轩翠幰。", "归来春已过，桃柳成阴，但喜庭闱镇强健。", "更得故人书，遗我瑰词，应重记、去年相见。", "望白鹤朱霞杳难攀，谩芳草如烟，青青河畔。"]'),
('song-ci-637','鹧鸪天','魏了翁','宋','宋词','song-ci','鹧鸪天','[]','夫子同年第太常。',64,'宋词/ci.song.13000.json','["夫子同年第太常。", "偶然二内亦同乡。", "其间更有真同处，道义场中无别香。", "花入思，绣为肠。", "不妨冬月作重阳。", "家人但歉今年会，犹欠腰金与鞠黄。"]'),
('song-ci-638','满江红','魏了翁','宋','宋词','song-ci','满江红','[]','彼美人兮，不肯为、时人妆束。',115,'宋词/ci.song.13000.json','["彼美人兮，不肯为、时人妆束。", "空自爱、北窗睡美，东邻醅熟。", "不道有人成离索，直教无计分膏馥。", "望鹤飞、不到暮云高，阑干曲。", "驹在谷，人金玉。", "盘在陆，人宽轴。", "笑吾今何苦，耐司空辱。", "应为嗷嗷乌反哺，真成落落蛇安足。", "到梓州、旧事上心来，呼杯醁。"]'),
('song-ci-639','眼儿媚','魏了翁','宋','宋词','song-ci','眼儿媚','[]','北风不竞帝师班。',58,'宋词/ci.song.13000.json','["北风不竞帝师班。", "雨足桔槔闲。", "且容湖使，静中藏拙，忙里偷欢。", "一枰黑白终何若，未可目前看。", "自量愚分，不堪世用，只称田官。"]'),
('song-ci-640','洞庭春色・沁园春','魏了翁','宋','宋词','song-ci','洞庭春色・沁园春','[]','四十之年，头颅如此，岂不自知。',136,'宋词/ci.song.13000.json','["四十之年，头颅如此，岂不自知。", "正东家尼父，叹无闻日，鄹人孟子，不动心时。", "顾我未能真自信，算三十九年浑是非。", "随禄仕，便加齐卿相，於我何为。", "人间郁蒸难耐，谁借我五万蒲葵。", "上玉台百尺，天连野□，□楼千里，江射晴晖。", "此意分明谁与会，但时把瑶笙和月吹。", "吾归矣，有鸿相与和，鹤自由飞。"]'),
('song-ci-641','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','冻雨洗烦浊，烈日霁威光。',114,'宋词/ci.song.13000.json','["冻雨洗烦浊，烈日霁威光。", "逸人去作太守，旗志倍精芒。", "莎外马蹄香湿，柳下旟阴晨润，景气踏苍苍。", "夹道气成雾，我独犯颜行。", "对颜行，斟尾酒，点头网。", "请君釂此，更伴顷刻笑谭香。", "为问锦屏富贵，孰与熙宁谏议，千古蔚仪章。", "世道正颓靡，此意傥毋忘。"]'),
('song-ci-642','洞庭春色・沁园春','魏了翁','宋','宋词','song-ci','洞庭春色・沁园春','[]','安石声名，买臣富贵，我不敢知。',137,'宋词/ci.song.13000.json','["安石声名，买臣富贵，我不敢知。", "谩扬州泛泛，浮湛随水，阊门轨轨，开阖从时。", "满目浮荣何与我，只赢得一场闲是非。", "诚知此，问不归何待，不饮胡为。", "岩松涧篁易老，应只能、采菽烹葵。", "看风沙漠漠，未清紫逻，烟云冉冉，时露晴晖。", "谁唤当年刘越石，为携取胡笳乘月吹。", "吾无用，但寤言独宿，奋不能飞。"]'),
('song-ci-643','鹧鸪天','魏了翁','宋','宋词','song-ci','鹧鸪天','[]','内贵何妨知我希。',64,'宋词/ci.song.13000.json','["内贵何妨知我希。", "芳荪纽佩石兰衣。", "不教尘外专云壑，准向人间驾使騑。", "忧国梦，绕端闱。", "静言思奋不能飞。", "时因风雨思畴昔，叹两苏公盍不归。"]'),
('song-ci-644','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','桃李眩春昼，松柏傲霜时。',114,'宋词/ci.song.13000.json','["桃李眩春昼，松柏傲霜时。", "春妍不必皆是，晚秀未为非。", "画斧河边瘴雾，叱驭关前险阻，马竭复人疲。", "胡不效侪等，趣取好官为。", "居之安，于胥乐，咏而归。", "毡裘鴂舌成市，书史俨相围。", "月淡秋亭烽影，日静春斋铃索，未听杜鹃啼。", "美酒无深巷，莫道不吾知。"]'),
('song-ci-645','小重山','魏了翁','宋','宋词','song-ci','小重山','[]','开汉江山落手中。',70,'宋词/ci.song.13000.json','["开汉江山落手中。", "满门花粲阑，锦蒙戎。", "与人和气乐融融。", "应怜我，留滞剑南东。", "风味两文忠。", "恍如畴昔夜，一尊同。", "如今海内几刘公。", "觇天意，犹在笑颜红。"]'),
('song-ci-646','临江仙','魏了翁','宋','宋词','song-ci','临江仙','[]','闲放楼前千里目，天边云大如囤。',70,'宋词/ci.song.13000.json','["闲放楼前千里目，天边云大如囤。", "秋风入帽露华新。", "无端忧国梦，应到守封臣。", "旧弼如今都有几，长教燕坐申申。", "折杨笑面背阳春。", "忧酲头欲雪，浊梦肺生尘。"]'),
('song-ci-647','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','三十作龙首，四十珥貂蝉。',114,'宋词/ci.song.13000.json','["三十作龙首，四十珥貂蝉。", "幡然携取名节，锦绣蜀山川。", "揽辔扶桑初晓，饮马咸池未旰，来日尽宽闲。", "兹事亦云足，所乐不存焉。", "女垂髫，儿分鼎，妇供鲜。", "尊章青鬓未改，和气玉生烟。", "造物犹嫌缺陷，要启公侯衮衮，又畀贾嘉贤。", "公更厚封植，自古有丰年。"]'),
('song-ci-648','临江仙','魏了翁','宋','宋词','song-ci','临江仙','[]','七夕长留河汉女，重阳又属骚人。',70,'宋词/ci.song.13000.json','["七夕长留河汉女，重阳又属骚人。", "只馀八八号佳辰。", "中和无与拟，摏作一家春。", "俗事萦人何日了，随缘女嫁男婚。", "却将不系自由身。", "闲中书日月，随处弄儿孙。"]'),
('song-ci-649','贺新郎','魏了翁','宋','宋词','song-ci','贺新郎','[]','旧日重阳日。',142,'宋词/ci.song.13000.json','["旧日重阳日。", "叹满城，阑风去雨，寂寥萧瑟。", "造物翻腾新机杼，不踏诗人陈迹。", "都扫荡、一天云物。", "挟客凭高西风外，暮鸢飞、不尽秋空碧。", "真意思，浩无极。", "糕诗酒帽茱萸席。", "算今朝、无谁不饮，有谁真得。", "子美不生渊明老，千载寥寥佳客。", "无限事、欲忘还忆。", "金气高明弓力劲，正不堪、回首南山北。", "谁弋燕，问消息。"]'),
('song-ci-650','阮郎归','魏了翁','宋','宋词','song-ci','阮郎归','[]','西风吹信趣征鞍。',56,'宋词/ci.song.13000.json','["西风吹信趣征鞍。", "日高鸿雁寒。", "稻粱啄尽不留残。", "侬归阿那边。", "无倚著，只苍天。", "将心何处安。", "长教子骏满人间。", "犹令侬意宽。"]'),
('song-ci-651','浣溪沙','魏了翁','宋','宋词','song-ci','浣溪沙','[]','骊驹未撤客乘鞍。',56,'宋词/ci.song.13000.json','["骊驹未撤客乘鞍。", "征鞭摇晚寒。", "雁边酲梦角惊残。", "关山斜日边。", "求道地，托恩天。", "人情久亦安。", "转移都在笑颦间。", "鄙夫应也宽。"]'),
('song-ci-652','浣溪沙','魏了翁','宋','宋词','song-ci','浣溪沙','[]','云外群鸿逐稻粱。',48,'宋词/ci.song.13000.json','["云外群鸿逐稻粱。", "独乘下泽少游乡。", "赤心片片为人忙。", "俗事萦缠何日了，自身活计孰为长。", "闭门书卷圣贤香。"]'),
('song-ci-653','沁园春','魏了翁','宋','宋词','song-ci','沁园春','[]','惠我田畴，拯民水火，春满蜀东。',138,'宋词/ci.song.13000.json','["惠我田畴，拯民水火，春满蜀东。", "更山连睥睨，长蛇隐雾，红移略约，睢霓横空。", "人卧流苏行席上，公心事夕阑晨枕中。", "长自苦，算无人识得，只有天公。", "天教百般如愿，也应是、天眼惺憁。", "看田间泥饮，门无夜打，水滨庐处，户有朝舂。", "拟上公堂，称兕爵酒，未抵人间春意浓。", "无可愿，愿城池永与，公寿无穷。"]'),
('song-ci-654','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','宇宙一大物，掌握付诸人。',114,'宋词/ci.song.13000.json','["宇宙一大物，掌握付诸人。", "人心不满方寸，坱北浩无垠。", "或者寒蝉自比，不尔秃犀贻笑，龊龊竟何成。", "胡不引贤者，相与共弥纶。", "未如何，尝试使，问苍旻。", "四时迭起代谢，有屈岂无伸。", "昨夜伶伦声里，一气排阴直上，阳德与时新。", "道长自今日，持此庆生申。"]'),
('song-ci-655','眼儿媚','魏了翁','宋','宋词','song-ci','眼儿媚','[]','乃翁表里玉无瑕。',58,'宋词/ci.song.13000.json','["乃翁表里玉无瑕。", "浑是得天多。", "一生受用，不完全处，都补填他。", "郎君心念和平处，似得十分家。", "天何以报，重重印字，滴滴檐窠。"]'),
('song-ci-656','乌夜啼','魏了翁','宋','宋词','song-ci','乌夜啼','[]','不肯呈身觅举，那能随俗为官。',56,'宋词/ci.song.13000.json','["不肯呈身觅举，那能随俗为官。", "梅花寒飐书窗月，一味漂阳酸。", "梅里无边春事，书中千古遐观。", "邻翁不识清闲乐，惊见满堂欢。"]'),
('song-ci-657','虞美人','魏了翁','宋','宋词','song-ci','虞美人','[]','无端嫁得龙头客。',66,'宋词/ci.song.13000.json','["无端嫁得龙头客。", "富贵长相迫。", "云深碧落记骖鸾。", "又逐东方千骑、到人间。", "妇前百拜儿称寿。", "季也参行酒。", "最怜小女太憨生。", "约住两头娘子、索新声。"]'),
('song-ci-658','浪淘沙','魏了翁','宋','宋词','song-ci','浪淘沙','[]','老眼静中看。',64,'宋词/ci.song.13000.json','["老眼静中看。", "知我其天。", "纷纷得失了无关。", "花柳乾坤春世界，著我中间。", "世念久阑珊。", "随寓随安。", "人情犹望衮衣还。", "我愿时清无一事，尽使公闲。"]'),
('song-ci-659','浪淘沙','魏了翁','宋','宋词','song-ci','浪淘沙','[]','鹤外倚楼看。',64,'宋词/ci.song.13000.json','["鹤外倚楼看。", "云飐晴天。", "天高鸡犬碍云关。", "掉臂双仙留不彻，还任人间。", "客佩振珊珊。", "来贺平安。", "年年直待卷灯还。", "似是天公偏著意，占破春闲。"]'),
('song-ci-660','木兰花令','魏了翁','宋','宋词','song-ci','木兰花令','[]','儿前捧劝孙扶掖。',66,'宋词/ci.song.13000.json','["儿前捧劝孙扶掖。", "共庆贺、娘娘七帙。", "此杯不比寻常，百年间、才是省陌。", "眼前彩绣成行立。", "已应是、天公偏惜。", "何须剩觅长年，且只消、一百二十。"]'),
('song-ci-661','醉落魄・一斛珠','魏了翁','宋','宋词','song-ci','醉落魄・一斛珠','[]','才难如此。',67,'宋词/ci.song.13000.json','["才难如此。", "一门生许奇男子。", "长公更是惺惺底。", "千百年间，一寸心为纸。", "人知公在诗书里。", "天知公在诗书外。", "人间百顺由公起。", "公把无心，总备人间事。"]'),
('song-ci-662','小重山','魏了翁','宋','宋词','song-ci','小重山','[]','风雨移春醉梦中。',70,'宋词/ci.song.13000.json','["风雨移春醉梦中。", "忽然吹信息，堕泸戎。", "青炜风物换朱融。", "吾归矣，家在月明东。", "公等为人忠。", "年年称母寿，一尊同。", "恨无佳句可酬公。", "相期意，滴滴小槽红。"]'),
('song-ci-663','临江仙','魏了翁','宋','宋词','song-ci','临江仙','[]','春院绣帘垂□□，一天风月横陈。',70,'宋词/ci.song.13000.json','["春院绣帘垂□□，一天风月横陈。", "慈亲初度纪嘉名。", "每从歌舞地，犹记杰魁人。", "大句忽随乌鹊至，恍如前岁逢春。", "只祈岁岁及兹辰。", "天风吹宝唾，华彩动文星。"]'),
('song-ci-664','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','涪右金华宅，上有蔚蓝天。',114,'宋词/ci.song.13000.json','["涪右金华宅，上有蔚蓝天。", "当年玉女何事，未摆世间缘。", "要把平夷心事，散作吉祥种子，春暖玉生烟。", "回首生处所，更欲与周旋。", "自归来，生处所，已三年。", "山头白鹤候我，应讶久留连。", "已作秋风归梦，忽递春风消息，吹我著泸川。", "安得且归去，绵上饱耕眠。"]'),
('song-ci-665','八声甘州','魏了翁','宋','宋词','song-ci','八声甘州','[]','记幡然、持节下青云，巴月几成弦。',119,'宋词/ci.song.13000.json','["记幡然、持节下青云，巴月几成弦。", "待竹枝歌彻，讼棠匝地，扉草连天。", "却寻当年旧梦，来使蜀东川。", "人物寥寥甚，禁许回旋。", "愧我推挤不去，尚新官对旧，后任如前。", "与故人饮酒，月露写明蠲。", "叹书生、康时无计，谩忧思、时堕酒痕边。", "且只愿、早休兵甲，长见丰年。"]'),
('song-ci-666','贺新郎','魏了翁','宋','宋词','song-ci','贺新郎','[]','霞下天垂宇。',142,'宋词/ci.song.13000.json','["霞下天垂宇。", "倚阑干、月华都在，大明生处。", "扶木元高三千丈，不分闲云无数。", "谩转却、人间朝暮。", "万古兴亡心一寸，只涓涓、日夜随流注。", "奈与世，不同趣。", "齐封冀甸今何许。", "百年间、欲招不住，欲推不去。", "闸断河流障海水，未放游鱼甫甫。", "叹多少、英雄尘土。", "挟客凭高西风外，问举头、还见南山否。", "花烂熳，草蕃庶。"]'),
('song-ci-667','江城子','魏了翁','宋','宋词','song-ci','江城子','[]','梦随瘦马渡晨烟。',96,'宋词/ci.song.13000.json','["梦随瘦马渡晨烟。", "月犹弦。", "稻初眠。", "宇宙平宽，著我一人闲。", "梦破枇杷香满袂，应唤我，驻行鞯。", "王氏之门枇杷花正开。", "雁声砧杵落晴川。", "抚流年。", "叹区缘。", "随世功名，未信果谁贤。", "目断孤云东北角，离复合，断还连。"]'),
('song-ci-668','喜迁莺','魏了翁','宋','宋词','song-ci','喜迁莺','[]','鬓霜盈握。',126,'宋词/ci.song.13000.json','["鬓霜盈握。", "叹刍牧荒墟，稻粱衰索。", "落日牛羊，晚云鸿雁，傍地飞空无托。", "牧人困和雨睡，田父醉连云酌。", "醉梦未醒，虎嗥川谷，麕惊林薄。", "离别。", "谁不恶。", "心事同时，都不论离合。", "眼底时几，鼻端人物，谁辨北征东略。", "最怜世途局趣，只道书生疏阔。", "无可赠君，松阴庭院，菊华篱落。"]'),
('song-ci-669','满江红','魏了翁','宋','宋词','song-ci','满江红','[]','世道何常，都一似、水流云出。',115,'宋词/ci.song.13000.json','["世道何常，都一似、水流云出。", "叹自古、燕巾滥宝，楚山迷璧。", "老我如今观变熟，行藏语嘿惟时适。", "似沧溟、容得乘禽飞，双凫集。", "花露晓，松风夕。", "经味永，山光吸。", "历岩中考第，案头月日。", "物欲强时心节制，才资弱处书扶掖。", "拟棕鞋、桐帽了平生，投簪舄。"]'),
('song-ci-670','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','清燕卧霜角，月魄几回哉。',114,'宋词/ci.song.13000.json','["清燕卧霜角，月魄几回哉。", "一声云雁清叫，推枕赋归来。", "流水落花去路，画象棠阴陈迹，霄观傍楼台。", "别忆入梅艳，愁色上田莱。", "记来时，惊列缺，走吴回。", "人间都失匕箸，老婢亦惊猜。", "匹马晓风鞭袖，孤堞暮烟烽柝，辉却挂蛇杯。", "不负此邦去，笑口也应开。"]'),
('song-ci-671','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','昨夜严家集，霜斗飐晴天。',114,'宋词/ci.song.13000.json','["昨夜严家集，霜斗飐晴天。", "乾坤如许空阔，著我两人闲。", "醉帽三更月影，别袂一帘花气，语隽不知还。", "二十年间事，肝肺写明蠲。", "记相逢，一似昨，两经年。", "风波闹处，推出心胆至今寒。", "也为故人饮酒，也念邦人怀旧，姑为驻征鞍。", "未忍作离语，留待月华圆。"]'),
('song-ci-672','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','更尽一杯酒，春近武陵源。',114,'宋词/ci.song.13000.json','["更尽一杯酒，春近武陵源。", "源头父老迎笑，人似老癯仙。", "检校露桃风叶，问讯渚莎江草，点检旧风烟。", "世界要人拄，公独卧闲边。", "叹从来，分宇宙，有山川。", "主宾均是寄耳，赢得鬓毛班。", "最苦中年相别，更是人才难得，相劝且加餐。", "归为玉昆说，时寄我平安。"]'),
('song-ci-673','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','山岳会元气，初度首王春。',114,'宋词/ci.song.13000.json','["山岳会元气，初度首王春。", "扶持许大穹壤，全德付耆英。", "二万九千日力，四百八旬甲子，酿此杰魁人。", "玉剑卧霜斗，金锁挚天扃。", "学宗师，人气脉，国精神。", "不应闲处袖手，试与入经纶。", "磊落蟠溪感遇，迢递彭篯岁月，远到漆园椿。", "用舍关时运，一片老臣心。"]'),
('song-ci-674','鹧鸪天','魏了翁','宋','宋词','song-ci','鹧鸪天','[]','解后皇华并辔游。',64,'宋词/ci.song.13000.json','["解后皇华并辔游。", "追随世好学风流。", "儿童拍手拦街笑，只是酸寒魏梓州。", "千炬烛，数声讴。", "不知白了几人头。", "惺憁两眼看来惯，且得人心乐便休。"]'),
('song-ci-675','鹧鸪天','魏了翁','宋','宋词','song-ci','鹧鸪天','[]','两便星前秉烛游。',64,'宋词/ci.song.13000.json','["两便星前秉烛游。", "滔滔车马九河流。", "耳听宣政升平曲，目断炎兴未复州。", "闻鼓吹，强欢讴。", "被人嗺送作遨头。", "凭谁为扫妖氛静，却与人间快活休。"]'),
('song-ci-676','临江仙','魏了翁','宋','宋词','song-ci','临江仙','[]','一点阳和浑在里，时来尔许芳妍。',70,'宋词/ci.song.13000.json','["一点阳和浑在里，时来尔许芳妍。", "春风吹上醉痕边。", "隽欢欺浅酌，清晤失佳眠。", "聊把繁华开笑口，须臾雨送风般。", "因花识得自家天。", "炯然长不夜，活处欲生烟。"]'),
('song-ci-677','柳梢青','魏了翁','宋','宋词','song-ci','柳梢青','[]','庄敏传家，文安嫡胄，文惠诸孙。',61,'宋词/ci.song.13000.json','["庄敏传家，文安嫡胄，文惠诸孙。", "两大相辉，晋秦匹国，韩姞盈门。", "天风吹下双轩。", "恰趁得、酴醿牡丹。", "锦绣光中，殿春不老，阅岁长存。"]'),
('song-ci-678','蝶恋花','魏了翁','宋','宋词','song-ci','蝶恋花','[]','可煞潼人真慕顾。',70,'宋词/ci.song.13000.json','["可煞潼人真慕顾。", "接得官时，只道来何暮。", "岁岁何曾摏得住。", "遂人又见迎将去。", "谩自儿曹相尔汝。", "心事同时，千里元相梧。", "况是棠阴随处处。", "秋江夜月春空雾。"]'),
('song-ci-679','菩萨蛮','魏了翁','宋','宋词','song-ci','菩萨蛮','[]','鸣蝉泊雨晴云湿。',52,'宋词/ci.song.13000.json','["鸣蝉泊雨晴云湿。", "游龙翦岸涪江碧。", "气候尔和平。", "满家浑是春。", "公堂虽有酒。", "不敌公真有。", "寿宿对魁星。", "颊红衫鬓青。"]'),
('song-ci-680','青玉案','魏了翁','宋','宋词','song-ci','青玉案','[]','中年怕踏长亭路。',80,'宋词/ci.song.13000.json','["中年怕踏长亭路。", "便自有、离愁苦。", "一自送君趋幕府。", "惺憁莺舌，呢喃燕觜，那解春无语。", "三年山月移朝暮。", "独倚松风等闲度。", "到得除书萦绊住。", "却愁不似，当时皓月，长伴君来去。"]'),
('song-ci-681','西江月','魏了翁','宋','宋词','song-ci','西江月','[]','早厌人间腐鼠，要希云外飞皇。',58,'宋词/ci.song.13000.json','["早厌人间腐鼠，要希云外飞皇。", "羲和不肯系朝阳。", "任向鬓边来往。", "出谷声中气味，编蒲册里晶光。", "至今心胆为渠狂。", "梦倚银潢天上。"]'),
('song-ci-682','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','牛酒享宾客，焦烂列前荣。',114,'宋词/ci.song.13000.json','["牛酒享宾客，焦烂列前荣。", "有人先事早计，残突伴孤星。", "香火家家绘象，鼛鼓村村祠宇，翦不断人情。", "清泪九皋鹤，唤起梦魂惺。", "白苹洲，芳草渡，玉湖亭。", "画帘挂起箓簌，一卷易同盟。", "携手锦江箍隐，觌面墨池玄叟，扶杖蜀君平。", "三老冁然笑，云散太空清。"]'),
('song-ci-683','临江仙','魏了翁','宋','宋词','song-ci','临江仙','[]','红杏花边曾共赏，天涯还是相逢。',70,'宋词/ci.song.13000.json','["红杏花边曾共赏，天涯还是相逢。", "人言契分两重重。", "谁知声利外，别有一般同。", "炯炯奇情双亮处，天光水色相通。", "磨中旋蚁渺何穷。", "共扶天事业，此意政须公。"]'),
('song-ci-684','临江仙','魏了翁','宋','宋词','song-ci','临江仙','[]','千里楼高人与并，个中彻地通天。',70,'宋词/ci.song.13000.json','["千里楼高人与并，个中彻地通天。", "秋风吹发半成宣。", "都将强岁月，空对旧山川。", "养就人才端有意，公今三祖差肩。", "偏轻偏重几番船。", "要公常把柂，容我老闲边。"]'),
('song-ci-685','临江仙','魏了翁','宋','宋词','song-ci','临江仙','[]','占断人间闲富贵，长秋应是长春。',70,'宋词/ci.song.13000.json','["占断人间闲富贵，长秋应是长春。", "前山推月上帘旌。", "缓觞燖旧友，勾拍按新声。", "时倚晴空看过雁，几州明月关情。", "知君早已倦青冥。", "时来那得免，事业一窗萤。"]'),
('song-ci-686','满江红','魏了翁','宋','宋词','song-ci','满江红','[]','逢著公卿，谁不道、人才难得。',115,'宋词/ci.song.13000.json','["逢著公卿，谁不道、人才难得。", "须认取、天根一点，几曾休息。", "未问人间多少士，一门男子头头立。", "只其间、如许广文君，谁人识。", "冠盖会，渔樵席。", "豪气度，清标格。", "要安排稳当，讲帷词掖。", "蜀泮堂堂元不恶，犹嫌偏惠天西壁。", "嘱公卿、著眼看乾坤，搜人物。"]'),
('song-ci-687','千秋岁引','魏了翁','宋','宋词','song-ci','千秋岁引','[]','天生耆德，占断四时先。',103,'宋词/ci.song.13000.json','["天生耆德，占断四时先。", "春院落，锦山川。", "万家灯市明朱紫，一庭花艳傍貂蝉。", "妇承姑，翁抱息，子差肩。", "匼匝是、文公开九帙。", "陆续看、武公逾九十。", "从九九，到千千。", "海风谩送天鸡舞，蛰雷未唤壑龙眠。", "且从他，歌缓缓，鼓咽咽。"]'),
('song-ci-688','醉落魄・一斛珠','魏了翁','宋','宋词','song-ci','醉落魄・一斛珠','[]','无边春色。',67,'宋词/ci.song.13000.json','["无边春色。", "人情苦向南山觅。", "村村箫鼓家家笛。", "祈麦祈蚕，来趁元正七。", "翁前子后孙扶掖。", "商行贾坐农耕织。", "许知此意无今昔。", "会得为人，日日是人日。"]'),
('song-ci-689','南乡子','魏了翁','宋','宋词','song-ci','南乡子','[]','连夕雨盈畴。',66,'宋词/ci.song.13000.json','["连夕雨盈畴。", "先为农家做麦秋。", "更放年头晴甲子，知不。", "应是天公及尔游。", "随事与民求。", "又与随时验乐忧。", "民气乐时天亦好，休休。", "为尔簪花插满头。"]'),
('song-ci-690','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','千古峨眉月，照我别离杯。',114,'宋词/ci.song.13000.json','["千古峨眉月，照我别离杯。", "故人中岁聚散，脉脉若为怀。", "醉帽三更风雨，别袂一帘山色，为放笑眉开。", "握手道旧故，抵掌论人才。", "山中人，灶间婢，亦惊猜。", "江头新涨催发，欲去重裴回。", "世事丝丝满鬓，岁月匆匆上面，渴梦肺生埃。", "酒罢听客去，公亦赋归来。"]'),
('song-ci-691','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','舣棹汉嘉口，更尽渭城杯。',114,'宋词/ci.song.13000.json','["舣棹汉嘉口，更尽渭城杯。", "凌云山色，似为行客苦伤怀。", "横出半天烟雨，锁定一川风景，未放客船开。", "想见此楼上，阅尽蜀人才。", "山猿鹤，江鸥鹭，亦相猜。", "滔滔日夜东注，全璧几人回。", "客亦莞然成笑，多少醉生梦死，转首总成埃。", "信屈四时耳，寒暑往还来。"]'),
('song-ci-692','满江红','魏了翁','宋','宋词','song-ci','满江红','[]','风引舟来，恰趁得、东楼嘉集。',115,'宋词/ci.song.13000.json','["风引舟来，恰趁得、东楼嘉集。", "正满眼、轻红重碧，照筵浮席。", "更是姓黄人作守，重新墨妙亭遗迹。", "对暮天、疏雨话乡情，更筹急。", "嗟世眼，迷朱碧。", "矜气势，才呼吸。", "彼蔡章安在，千年黄笔。", "腐鼠那能鹓凤吓，怒蜩未信冥鹏翼。", "与史君、酌酒酹兴亡，浇今昔。"]'),
('song-ci-693','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','烟雨敛江色，江水大於杯。',114,'宋词/ci.song.13000.json','["烟雨敛江色，江水大於杯。", "蓬窗一枕霄梦，忽忽到无怀。", "苦被江头新涨，推起天涯倦客，万里片帆开。", "收用到我辈，天下岂无才。", "路漫漫，行又止，信还猜。", "渊鱼得失有分，须载月明回。", "寄语鹤山亲友，若访吾庐花柳，为我扫烟埃。", "去去党无辱，振袂早归来。"]'),
('song-ci-694','卜算子','魏了翁','宋','宋词','song-ci','卜算子','[]','江横山簇。',53,'宋词/ci.song.13000.json','["江横山簇。", "柏箭森如束。", "满眼飞蓬撩乱，知几几、未膏沐。", "快意忽破竹。", "一奁明翠玉。", "千古江山只麽，人都道、为君绿。"]'),
('song-ci-695','贺新郎','魏了翁','宋','宋词','song-ci','贺新郎','[]','风定波纹细。',142,'宋词/ci.song.13000.json','["风定波纹细。", "夜无尘、云迷地轴，月流天位。", "摇裔飞来江山鹤，犹作故乡嘹唳。", "清境里、伴人无睡。", "应叹余生舟似泛，浪涛中、几度身尝试。", "书有恨，剑无气。", "从渠俗耳追繁吹。", "抚空明、一窗寒簟，对人如砥。", "梦倚银河天外立，云露惺惺满袂。", "看多少、人间嬉戏。", "要话斯心无分付，路茫茫、还有亲朋至。", "应为我，倒罍洗。"]'),
('song-ci-696','卜算子','魏了翁','宋','宋词','song-ci','卜算子','[]','携月上南楼，月已穿云去。',52,'宋词/ci.song.13000.json','["携月上南楼，月已穿云去。", "莫照峨眉最上峰，同在峰前住。", "东望极青齐，西顾穷商许。", "酒到忧边总未知，犹认胡床处。"]'),
('song-ci-697','卜算子','魏了翁','宋','宋词','song-ci','卜算子','[]','能得几时留，王事催人去。',52,'宋词/ci.song.13000.json','["能得几时留，王事催人去。", "翠荡涵空酒满船，苦要留人住。", "身世两悠悠，飘泊知何许。", "但得心亲志合时，都是相逢处。"]'),
('song-ci-698','卜算子','魏了翁','宋','宋词','song-ci','卜算子','[]','风雨满空霏，总得江山妙。',52,'宋词/ci.song.13000.json','["风雨满空霏，总得江山妙。", "洗出湖光镜似明，不受纤尘涴。", "心事竟堪凭，天意真难料。", "呼吸丰年倾刻间，也合轩渠笑。"]'),
('song-ci-699','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','昨梦鹤山去，风景逐时新。',114,'宋词/ci.song.13000.json','["昨梦鹤山去，风景逐时新。", "藕花拍满栏槛，松竹被池频。", "尽日兄酥弟酪，触处言鲭义□，相对只翁卿。", "梦觉帝乡远，有酒为谁倾。", "忽飞来，天外句，梦中人。", "自怜何事，强把麋鹿裹朝绅。", "坐看九衢车马，鞭策长安日月，檐阁太玄经。", "只说来时节，金气已高明。"]'),
('song-ci-700','木兰花慢','魏了翁','宋','宋词','song-ci','木兰花慢','[]','恰秋光四十，箕斗外、月初弦。',122,'宋词/ci.song.13000.json','["恰秋光四十，箕斗外、月初弦。", "笑浅濑平芜，寒城小市，掌许山川。", "半生梦魂不到，与君侯、岁岁此周旋。", "鞍马空销髀肉，兜牟未换貂蝉。", "人生天地两仪间。", "须住百馀年。", "数重卦三三，后天八八，来日千千。", "面前路头尽阔，放规模、运量十分宽。", "官职终还分定，儿孙也靠心传。"]'),
('song-ci-701','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','九十九峰下，百二十年州。',114,'宋词/ci.song.13000.json','["九十九峰下，百二十年州。", "西风吹起客梦，月满驿南楼。", "影入天河左界，辰在寿星向上，还是去年秋。", "要和木兰曲，载酒寿君侯。", "天边信，云外步，去难留。", "寿觞庭院依旧，已带别离愁。", "离合锺情未免，行止关人何事，浪白世间头。", "将相时来作，身健百无忧。"]'),
('song-ci-702','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','犹记端门外，鞭袖五更寒。',114,'宋词/ci.song.13000.json','["犹记端门外，鞭袖五更寒。", "一声天上钟柝，金锁挚重关。", "君向紫宸上阁，我侍玉皇香案，都号舍人般。", "梦觉帝乡远，相对两苍颜。", "玉围腰，金系肘，绣笼鞯。", "乡人衮衮严近，五马度荆山。", "收拾五湖气度，卷束蟠胸兵甲，春意满人间。", "天锡公纯嘏，气象自平宽。"]'),
('song-ci-703','鹧鸪天','魏了翁','宋','宋词','song-ci','鹧鸪天','[]','日上午头度岁辰。',64,'宋词/ci.song.13000.json','["日上午头度岁辰。", "黄钟吹龠煦乾坤。", "弦歌堂上三称寿，风月亭前又见君。", "人似旧，景长新。", "明朝六桂侍双椿。", "蛮邦父老惊曾见，得似君家别有春。"]'),
('song-ci-704','满江红','魏了翁','宋','宋词','song-ci','满江红','[]','月上南箕，还认得、去年星历。',115,'宋词/ci.song.13000.json','["月上南箕，还认得、去年星历。", "知谁把、一天星象，荡摩朝昔。", "若使平生浑自弃，如今老大何嗟及。", "更年来、偏得钝工夫，蹉跎力。", "溪瘴碍，蛮烟隔。", "穹壤断，江山窄。", "纵燕巾滥宝，楚山囚玉。", "小小穷通都未问，忍闻同气相煎急。", "诵虞郎、百字短长诗，忧何极。"]'),
('song-ci-705','鹧鸪天','魏了翁','宋','宋词','song-ci','鹧鸪天','[]','谁把璇玑运化工。',64,'宋词/ci.song.13000.json','["谁把璇玑运化工。", "参旗又挂玉梅东。", "三三律琯声馀亥，九九玄经卦起中。", "新岁月，旧游从。", "一觞还似去年冬。", "人间事会无终极，分付翘关老令公。"]'),
('song-ci-706','菩萨蛮','魏了翁','宋','宋词','song-ci','菩萨蛮','[]','东窗五老峰前月。',52,'宋词/ci.song.13000.json','["东窗五老峰前月。", "南窗九叠坡前雪。", "推出侍郎山。", "著君窗户间。", "离骚乡里住。", "恰记庚寅度。", "挹取芷兰芳。", "酌君千岁觞。"]'),
('song-ci-707','念奴娇','魏了翁','宋','宋词','song-ci','念奴娇','[]','被东风吹送，都看尽、蜀三川。',122,'宋词/ci.song.13000.json','["被东风吹送，都看尽、蜀三川。", "向涪水西来，东山右去，剑阁南旋。", "家家露餐风宿，数旬间、浑不见炊烟。", "踏遍王孙草畔，眼明帝子城边。", "万家赤子日高眠。", "丝管夜喧阗。", "自梓遂而东，岷峨向里，汉益从前。", "人人里歌涂咏，愿君侯、长与作蕃宣。", "我愿时清无事，早归相伴华颠。"]'),
('song-ci-708','贺新郎','魏了翁','宋','宋词','song-ci','贺新郎','[]','幸有天遮蔽。',142,'宋词/ci.song.13000.json','["幸有天遮蔽。", "为西南、空虚一面，挺生男子。", "塞下将军支颐卧，夜半揽衣推起。", "扫十万、胡人如洗。", "见说巴山矟马退，也都因、粮运如流水。", "剑以北，一人耳。", "十年梦断斜阳外。", "恰归来、昌蒲蘸酒，祝兄千岁。", "入从出藩谁不是。", "谁是难兄难弟。", "正乐意、融融未已。", "莫趣东方千骑去，愿时平、华皓长相对。", "闲富贵，只如此。"]'),
('song-ci-709','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','高氏八千古，驺哄溢街坊。',114,'宋词/ci.song.13000.json','["高氏八千古，驺哄溢街坊。", "庸夫俗子，夸道锦绣裹家乡。", "谁识书生心事，各要济时行己，肯顾利名场。", "用我吾所欲，不用亦何伤。", "汉嘉守，凡阅历，几麾幢。", "便教入从出节，都是分之常。", "但愿国安人寿，更只专城也好，不用较强梁。", "准拟耆英会，倚杖看人忙。"]'),
('song-ci-710','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','风雪锢迁客，闭户紧蒙头。',114,'宋词/ci.song.13000.json','["风雪锢迁客，闭户紧蒙头。", "一声门外剥啄，客有从予游。", "直自离骚国里，行到林闾屋畔，万里入双眸。", "世态随炎去，此意澹於秋。", "感毕逋，怀秸鞠，咏夫不，寻师学道虽乐，吾母有离忧。", "岁晚巫云峡雨，春日楚烟湘月，诗思满归舟。", "来日重过我，应记火西流。"]'),
('song-ci-711','摸鱼儿','魏了翁','宋','宋词','song-ci','摸鱼儿','[]','记年时、三星明处。',140,'宋词/ci.song.13000.json','["记年时、三星明处。", "尊前携手相语。", "家山幸有瓜和芋。", "何苦投身官府。", "谁知道，尚随逐风华，为蜀分南土。", "依前廉取。", "便卷却旌麾，提将绣斧。", "天口笑应许。", "逢初度。", "从头要为君数。", "怕君惊落前箸。", "天东扶木三千丈，不照关河烟雨。", "谁砥柱。", "想造物生才，肯恁无分付。", "九州风露。", "待公等归来，为清天步。", "容我赋归去。"]'),
('song-ci-712','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','尚记春归日，锦绣裹江城。',114,'宋词/ci.song.13000.json','["尚记春归日，锦绣裹江城。", "谁推日驭西去，水认故乡痕。", "鱼鸟自飞自跃。", "红紫谁开谁落。", "天运渺无声。", "四序镇如此，当富复亭亭。", "是何年，修禊事，畅幽情。", "竞传元已天气，别是一般清。", "便引郑郊溱洧。", "不道孔门沂泗。", "大道掌如平。", "待挽迷津者，都向此中行。"]'),
('song-ci-713','唐多令','魏了翁','宋','宋词','song-ci','唐多令','[]','轻露濯秋风，新楼插太空。',74,'宋词/ci.song.13000.json','["轻露濯秋风，新楼插太空。", "更遭逢、解事天公。", "为唤羲和驱六马，将杲日、挂帘栊。", "日影正沈红。", "须臾月在东。", "百万家、乐意融融。", "民意乐时天亦好，聊与众、一尊同。"]'),
('song-ci-714','唐多令','魏了翁','宋','宋词','song-ci','唐多令','[]','朔雪上征衣。',74,'宋词/ci.song.13000.json','["朔雪上征衣。", "春风送客归。", "万杨华、数点榴枝。", "春事无多天不管，教烂熳、住离披。", "开谢本同机。", "荣枯自一时。", "算天公、不遣春知。", "但得溶溶生意在，随冷暖、镇芳菲。"]'),
('song-ci-715','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','堪怪两外府，使传载朝缨。',114,'宋词/ci.song.13000.json','["堪怪两外府，使传载朝缨。", "虽云身在江表，都号汉公卿。", "莫是才堪世用，莫是有人吹送，中外尔联荣。", "天运自消息，龙蠖不关情。", "更寻思，谁得失，孰亏成。", "潜鱼要向深渺，犹恐太分明。", "且愿时清无事，长把书生阁束，归践对床盟。", "强似抗尘俗，岁岁上陪京。"]'),
('song-ci-716','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','天地一大物，扶植要人才。',114,'宋词/ci.song.13000.json','["天地一大物，扶植要人才。", "人才谁是，不肯随俗强追陪。", "与我言兮我愿。", "莫我知兮谁怨。", "全仗帝为媒。", "此意久寥阔，今见者留台。", "笏围腰，书创屋，骑笼街。", "时贤白尽须发，老子抑名斋。", "更取堂名淇绿。", "要把北山万竹。", "一日倚云栽。", "自处只如此，将相任时来。"]'),
('song-ci-717','唐多令','魏了翁','宋','宋词','song-ci','唐多令','[]','人物盛乾淳。',74,'宋词/ci.song.13000.json','["人物盛乾淳。", "东嘉最得人。", "费江山、几许精神。", "我已后时犹遍识，君子子、又相亲。", "秋入塞垣新。", "风寒上醉痕。", "万百般、倚靠苍旻。", "只愿诸贤长寿健，容老我、看闲身。"]'),
('song-ci-718','木兰花慢','魏了翁','宋','宋词','song-ci','木兰花慢','[]','正秋阴盛处，忽荡起、一冰轮。',122,'宋词/ci.song.13000.json','["正秋阴盛处，忽荡起、一冰轮。", "甚汉魏从前，才人胜士，断简残文。", "都无一词赏玩，更拟将、美色似非伦。", "此意谁能领会，自夸光景长新。", "得阴多处倍精神。", "俗眼转增明。", "向大第高楼，痴儿呆女，脆竹繁裀。", "此心到头未稳，莫古人、真不及今人。", "坐看两仪消长，静观千古浇淳。"]'),
('song-ci-719','八声甘州','魏了翁','宋','宋词','song-ci','八声甘州','[]','被西风吹不断新愁。',118,'宋词/ci.song.13000.json','["被西风吹不断新愁。", "吾归欲安归。", "望秦云苍憺，蜀山渺渀，楚泽平漪。", "鸿雁依人正急，不奈稻粱稀。", "独立苍茫外，数遍群飞。", "多少曹苻气势，只数舟燥苇，一局枯棋。", "更元颜何事，花玉困重围。", "算眼前、未知谁恃，恃苍天、终古限华夷。", "还须念，人谋如旧，天意难知。"]'),
('song-ci-720','玲珑四犯','李从周','宋','宋词','song-ci','玲珑四犯','[]','初拨琵琶，未肯信，知音真个稀少。',123,'宋词/ci.song.13000.json','["初拨琵琶，未肯信，知音真个稀少。", "尽日芳情，萦系玉人怀抱。", "须待化作杨花，特地过、旧家池沼。", "想绮窗、刺绣迟了，半缕茜茸微绕。", "旧时眉妩贪相恼。", "到春来、为谁浓扫。", "新归燕子都曾识，不敢教知道。", "长是倦出绣幕，向梦里、重谋一笑。", "怎得同携手，花阶月地，把愁勾了。"]'),
('song-ci-721','抛球乐','李从周','宋','宋词','song-ci','抛球乐','[]','风罥荐红雨易晴。',46,'宋词/ci.song.13000.json','["风罥荐红雨易晴。", "病花中酒过清明，绮窗幽梦乱於柳。", "罗袖泪痕凝似饧。", "冷地思量著，春色三停早二停。"]'),
('song-ci-722','谒金门','李从周','宋','宋词','song-ci','谒金门','[]','花似匝。',53,'宋词/ci.song.13000.json','["花似匝。", "两点翠蛾愁压。", "人又不来春且恰。", "谁留春一霎。", "消尽水沈金鸭。", "写尽杏笺红蜡。", "可奈薄情如此黠。", "寄书浑不答。"]'),
('song-ci-723','一丛花令・一丛花','李从周','宋','宋词','song-ci','一丛花令・一丛花','[]','梨花随月过中庭。',94,'宋词/ci.song.13000.json','["梨花随月过中庭。", "月色冷如银。", "金闺平帖阳台路，恨酥雨、不扫行云。", "妆褪臂闲，髻慵簪卸，盟海浪花沈。", "洞箫清吹最关情。", "腔拍懒温寻。", "知音一去教谁听，再拈起、指法都生。", "天阔雁稀，帘空莺悄，相傍又春深。"]'),
('song-ci-724','风流子','李从周','宋','宋词','song-ci','风流子','[]','双燕立虹梁。',135,'宋词/ci.song.13000.json','["双燕立虹梁。", "东风外、烟雨湿流光。", "望芳草云连，怕经南浦，葡萄波涨，怎博西凉。", "空记省，浅妆眉晕敛，罥袖唾痕香。", "春满绮罗，小莺捎蝶，夜留弦索，么凤求凰。", "江湖飘零久，频回首、无奈触绪难忘。", "谁信温柔牢落，翻坠愁乡。", "仗玉笺铜爵，花间陶写，宝钗金镜，月底平章。", "十二主家楼苑，应念萧郎。"]'),
('song-ci-725','清平乐','李从周','宋','宋词','song-ci','清平乐','[]','美人娇小。',54,'宋词/ci.song.13000.json','["美人娇小。", "镜里容颜好。", "秀色侵人春帐晓。", "郎去几时重到。", "叮咛记取儿家。", "碧云隐映红霞。", "直下小桥流水，门前一树桃花。"]'),
('song-ci-726','风入松','李从周','宋','宋词','song-ci','风入松','[]','霜风连夜做冬晴。',88,'宋词/ci.song.13000.json','["霜风连夜做冬晴。", "晓日千门。", "香葭暖透黄钟管，正玉台、彩笔书云。", "竹外南枝意早，数花开对清樽。", "香闺女伴笑轻盈。", "倦绣停针。", "花砖一线添红景，看从今、迤逦新春。", "寒食相逢何处，百单五个黄昏。"]'),
('song-ci-727','乌夜啼','李从周','宋','宋词','song-ci','乌夜啼','[]','径藓痕沿碧甃，檐花影压红阑。',56,'宋词/ci.song.13000.json','["径藓痕沿碧甃，檐花影压红阑。", "今年春事浑无几，游冶懒情悭。", "旧梦莺莺沁水，新愁燕燕长干。", "重门十二帘休卷，三月尚春寒。"]'),
('song-ci-728','清平乐','李从周','宋','宋词','song-ci','清平乐','[]','东风无用。',54,'宋词/ci.song.13000.json','["东风无用。", "吹得愁眉重。", "有意迎春无意送。", "门外湿云如梦。", "韶光九十悭悭。", "俊游回首关山。", "燕子可怜人去，海棠不分春寒。"]'),
('song-ci-729','鹧鸪天','李从周','宋','宋词','song-ci','鹧鸪天','[]','绿色吴笺覆古苔。',64,'宋词/ci.song.13000.json','["绿色吴笺覆古苔。", "濡毫重拟赋幽怀。", "杏花帘外莺将老，杨柳楼前燕不来。", "倚玉枕，坠瑶钗。", "午窗轻梦绕秦淮。", "玉鞭何处贪游冶，寻遍春风十二街。"]'),
('song-ci-730','宴清都','卢祖皋','宋','宋词','song-ci','宴清都','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','春讯飞琼管。',125,'宋词/ci.song.13000.json','["春讯飞琼管。", "风日薄、度墙啼鸟声乱。", "江城次第，笙歌翠合，绮罗香暖。", "溶溶涧渌冰泮。", "醉梦里、年华暗换。", "料黛眉重锁隋堤，芳心还动梁苑。", "新来雁阔云音，鸾分槛影，无计重见。", "啼春细雨，笼愁澹月，恁时庭院。", "离肠未语先断。", "算犹有、凭高望眼。", "更那堪、芳草连天，飞梅弄晚。"]'),
('song-ci-731','鱼游春水','卢祖皋','宋','宋词','song-ci','鱼游春水','[]','离愁禁不去。',105,'宋词/ci.song.13000.json','["离愁禁不去。", "好梦别来无觅处。", "风翻征袂，触目年芳如许。", "软红尘里鸣鞭镫，拾翠丛中句伴侣。", "都负岁时，暗关情绪。", "昨夜山阴杜宇。", "似把归期惊倦旅。", "遥知楼倚东风，凝颦暗数。", "宝香拂拂遗鸳锦，心事悠悠寻燕语。", "芳草暮寒，乱花微雨。"]'),
('song-ci-732','倦寻芳','卢祖皋','宋','宋词','song-ci','倦寻芳','[]','香泥垒燕，密叶巢莺，春晦寒浅。',118,'宋词/ci.song.13000.json','["香泥垒燕，密叶巢莺，春晦寒浅。", "花径风柔，著地舞裀红软。", "斗草烟欺罗袂薄，秋千影落春游倦。", "醉归来，记宝帐歌慵，锦屏香暖。", "别来怅、光阴容易，还又酴醿，牡丹开遍。", "妒恨疏狂，那更柳花迎面。", "鸿羽难凭芳信短，长安犹近归期远。", "倚危楼，但镇日、绣帘高卷。"]'),
('song-ci-733','江城子','卢祖皋','宋','宋词','song-ci','江城子','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','画楼帘幕卷新晴。',86,'宋词/ci.song.13000.json','["画楼帘幕卷新晴。", "掩银屏。", "晓寒轻。", "坠粉飘香，日日唤愁生。", "暗数十年湖上路，能几度，著娉婷。", "年华空自感飘零。", "拥春酲。", "对谁醒。", "天阔云闲，无处觅箫声。", "载酒买花年少事，浑不似，旧心情。"]'),
('song-ci-734','江城子','卢祖皋','宋','宋词','song-ci','江城子','[]','护霜云日霭晴空。',86,'宋词/ci.song.13000.json','["护霜云日霭晴空。", "锦围中。", "卷香风。", "弄玉乘鸾，人自蕊珠宫。", "天遣岁寒为伴侣，还待得，谪仙翁。", "等闲随处是春功。", "笑相从。", "寸心同。", "不羡鱼轩，蝉冕共荣封。", "只爱阶庭兰玉秀，梅不老，对乔松。"]'),
('song-ci-735','江城子','卢祖皋','宋','宋词','song-ci','江城子','[]','小山初筑自天成。',86,'宋词/ci.song.13000.json','["小山初筑自天成。", "架危亭。", "与云平。", "面面梅花，阑槛十分清。", "唤得长淮春意满，香暗度，月微明。", "数枝长忆傍岩扃。", "杖履轻。", "醉中行。", "笑问东风，何日是归程。", "只怕和羹消息近，天未许，遂幽情。"]'),
('song-ci-736','西江月','卢祖皋','宋','宋词','song-ci','西江月','[]','燕掠晴丝袅袅，鱼吹水叶粼粼。',58,'宋词/ci.song.13000.json','["燕掠晴丝袅袅，鱼吹水叶粼粼。", "禁街微雨洒香尘。", "寒食清明相近。", "漫著宫罗试暖，闲呼社酒酬春。", "晚风帘幕悄无人。", "二十四番花讯。"]'),
('song-ci-737','画堂春','卢祖皋','宋','宋词','song-ci','画堂春','[]','玉屏回梦月平谰。',55,'宋词/ci.song.13000.json','["玉屏回梦月平谰。", "元来香冷衣单。", "柳风特地更将寒。", "吹上眉端。", "云羽未回征雁，镜花空舞双鸾。", "去年芳径又斓斑。", "门掩春闲。"]'),
('song-ci-738','画堂春','卢祖皋','宋','宋词','song-ci','画堂春','[]','柳黄移上袂罗单。',55,'宋词/ci.song.13000.json','["柳黄移上袂罗单。", "酒醒娇亸风鬟。", "茗瓯才试鹧鸪斑。", "沈炷熏残。", "夜雨可无归梦，晓风何处征鞍。", "海棠开了尚凭阑。", "划地春寒。"]'),
('song-ci-739','画堂春','卢祖皋','宋','宋词','song-ci','画堂春','[]','柳塘风紧絮交飞。',55,'宋词/ci.song.13000.json','["柳塘风紧絮交飞。", "漾花一水平池。", "暖香飘径日迟迟。", "何处酴醿。", "胡蝶梦中寒浅，杜鹃声里春归。", "镜容不似旧家时。", "羞对清溪。"]'),
('song-ci-740','清平乐','卢祖皋','宋','宋词','song-ci','清平乐','[]','镜屏开晓。',54,'宋词/ci.song.13000.json','["镜屏开晓。", "寒入宫罗峭。", "脉脉不知春又老。", "帘外舞红多少。", "旧时驻马香阶。", "如今细雨苍苔。", "残梦不堪重理，一双胡蝶飞来。"]'),
('song-ci-741','清平乐','卢祖皋','宋','宋词','song-ci','清平乐','[]','柳边深院。',54,'宋词/ci.song.13000.json','["柳边深院。", "燕语明如翦。", "消息无凭听又懒。", "隔断画屏双扇。", "宝杯金缕红牙。", "醉魂几度儿家。", "何处一春游荡，梦中犹恨杨花。"]'),
('song-ci-742','清平乐','卢祖皋','宋','宋词','song-ci','清平乐','[]','玉肌春瘦。',54,'宋词/ci.song.13000.json','["玉肌春瘦。", "别凤离鸾后。", "柳外画船看翠袖。", "眼艳风流依旧。", "杏梁语燕绸缪。", "可堪前梦悠悠。", "几度欲成花雨，断云还过南楼。"]'),
('song-ci-743','清平乐','卢祖皋','宋','宋词','song-ci','清平乐','[]','朔风凝冱。',54,'宋词/ci.song.13000.json','["朔风凝冱。", "不放云来去。", "稚柳回春能几许。", "一夜满城飞絮。", "羊羔酒面频倾。", "护寒香缓娇屏。", "唤取雪儿对舞，看他若个轻盈。"]'),
('song-ci-744','乌夜啼','卢祖皋','宋','宋词','song-ci','乌夜啼','[]','几曲微风按柳，生香暖日蒸花。',56,'宋词/ci.song.13000.json','["几曲微风按柳，生香暖日蒸花。", "鸳鸯睡足芳塘晚，新绿小窗纱。", "尺素难将情绪，嫩罗还试年华。", "凭高无处寻残梦，春思入琵琶。"]'),
('song-ci-745','乌夜啼','卢祖皋','宋','宋词','song-ci','乌夜啼','[]','照水飞禽斗影，舞风小径低花。',56,'宋词/ci.song.13000.json','["照水飞禽斗影，舞风小径低花。", "征鸿排尽相思字，音信落谁家。", "系恨腰围顿减，禁愁酒力难加。", "楼高日暮休帘卷，芳草满天涯。"]'),
('song-ci-746','乌夜啼','卢祖皋','宋','宋词','song-ci','乌夜啼','["\u897f\u6e56"]','柳色津头泫绿，桃花渡口啼红。',56,'宋词/ci.song.13000.json','["柳色津头泫绿，桃花渡口啼红。", "一春又负西湖醉，离恨雨声中。", "客袂迢迢西塞，馀寒翦翦东风。", "谁家拂水飞来燕，惆怅小楼东。"]'),
('song-ci-747','乌夜啼','卢祖皋','宋','宋词','song-ci','乌夜啼','["\u897f\u6e56"]','漾暖纹波飐飐，吹晴丝雨濛濛。',56,'宋词/ci.song.13000.json','["漾暖纹波飐飐，吹晴丝雨濛濛。", "轻衫短帽西湖路，花气扑春骢。", "斗草褰衣湿翠，秋千瞥眼飞红。", "日长不放春醪困，立尽海棠风。"]'),
('song-ci-748','乌夜啼','卢祖皋','宋','宋词','song-ci','乌夜啼','[]','段段寒沙浅水，萧萧暮雨孤篷。',56,'宋词/ci.song.13000.json','["段段寒沙浅水，萧萧暮雨孤篷。", "香罗不共征衫远，砧杵客愁中。", "别恨慵看杨柳，归期暗数芙蓉。", "碧梧声到纱窗晓，昨夜几秋风。"]'),
('song-ci-749','谒金门','卢祖皋','宋','宋词','song-ci','谒金门','[]','风不定。',53,'宋词/ci.song.13000.json','["风不定。", "移去移来帘影。", "一雨林塘新绿净。", "杏梁归燕并。", "翠袖玉屏金镜。", "日薄绮疏人静。", "心事一春疑酒病。", "鸟啼花满径。"]'),
('song-ci-750','谒金门','卢祖皋','宋','宋词','song-ci','谒金门','[]','兰棹举。',53,'宋词/ci.song.13000.json','["兰棹举。", "相趁落红飞去。", "一隙轻帘凝睇处。", "柳丝牵不住。", "昨日翠蛾金缕。", "今夜碧波烟渚。", "好梦无凭窗又雨。", "天涯知几许。"]'),
('song-ci-751','谒金门','卢祖皋','宋','宋词','song-ci','谒金门','[]','间院宇。',53,'宋词/ci.song.13000.json','["间院宇。", "独自行来行去。", "花片无声帘外雨。", "峭寒生碧树。", "做弄清明时序。", "料理春酲情绪。", "忆得归时停棹处。", "画桥看落絮。"]'),
('song-ci-752','谒金门','卢祖皋','宋','宋词','song-ci','谒金门','[]','深院静。',53,'宋词/ci.song.13000.json','["深院静。", "隔叶鸣禽相应。", "金鸭云寒闲梦醒。", "转帘花月影。", "闲步碧阶香径。", "亸翠残红慵整。", "明日阴晴犹未定。", "试教移小艇。"]'),
('song-ci-753','谒金门','卢祖皋','宋','宋词','song-ci','谒金门','[]','寒半退。',53,'宋词/ci.song.13000.json','["寒半退。", "斜掩小屏珠翠。", "柳眼才醒桃欲醉。", "日高帘影碎。", "暗解鸳鸯罗带。", "独立晚风谁会。", "心事悠悠人好在。", "画桥流水外。"]'),
('song-ci-754','谒金门','卢祖皋','宋','宋词','song-ci','谒金门','[]','人寂寞。',53,'宋词/ci.song.13000.json','["人寂寞。", "帘外翠阴如幄。", "团扇藤床花间错。", "雨边残梦觉。", "翠浅粉销香薄。", "临镜不忺梳掠。", "新恨悠悠无处托。", "棋声闲院落。"]'),
('song-ci-755','谒金门','卢祖皋','宋','宋词','song-ci','谒金门','[]','闲睡足。',53,'宋词/ci.song.13000.json','["闲睡足。", "冰柱乱敲寒玉。", "簇簇庭阴嘉树绿。", "晚蝉声断续。", "一雨藕花新浴。", "香破小窗幽独。", "重理焦桐寻旧曲。", "隔墙风动竹。"]'),
('song-ci-756','谒金门','卢祖皋','宋','宋词','song-ci','谒金门','[]','香漠漠。',53,'宋词/ci.song.13000.json','["香漠漠。", "低卷水风池阁。", "玉腕笼纱金半约。", "睡浓团扇落。", "雨后凉生云薄。", "女伴棹歌声乐。", "采得双莲迎笑剥。", "柳阴多处泊。"]'),
('song-ci-757','谒金门','卢祖皋','宋','宋词','song-ci','谒金门','[]','秋几许。',53,'宋词/ci.song.13000.json','["秋几许。", "荒蓼败荷烟渚。", "贴水飞鸥江欲暮。", "风帆追急羽。", "蝶梦转头无据。", "愁到曲屏深处。", "寒入双城扃绣户。", "也应闻细雨。"]'),
('song-ci-758','谒金门','卢祖皋','宋','宋词','song-ci','谒金门','[]','罗袖褪。',53,'宋词/ci.song.13000.json','["罗袖褪。", "短鬓独搔谁恨。", "叶叶秋声风衮衮。", "万端心一寸。", "钗凤镜鸾谁问。", "想见粉香啼损。", "倩尽飞鸿终未稳。", "夜来寒陡顿。"]'),
('song-ci-759','鹧鸪天','卢祖皋','宋','宋词','song-ci','鹧鸪天','[]','纤指轻拈小砑红。',64,'宋词/ci.song.13000.json','["纤指轻拈小砑红。", "自调宫羽按歌童。", "寒馀芍药阑边雨，香落酴醿架底风。", "闲意态，小房栊。", "丁宁须满玉西东。", "一春醉得莺花老，不似年时怨玉容。"]'),
('song-ci-760','鹧鸪天','卢祖皋','宋','宋词','song-ci','鹧鸪天','[]','庭绿初圆结荫浓。',64,'宋词/ci.song.13000.json','["庭绿初圆结荫浓。", "香沟收拾旧梢红。", "池塘少歇鸣蛙雨，帘幕轻回舞燕风。", "春又老，笑谁同。", "澹烟斜日小楼东。", "相思一曲临风笛，吹过云山第几重。"]'),
('song-ci-761','鹧鸪天','卢祖皋','宋','宋词','song-ci','鹧鸪天','[]','岸柳黄深绿已垂。',64,'宋词/ci.song.13000.json','["岸柳黄深绿已垂。", "庭院红遍白还飞。", "几回画蜡银台梦，双字香罗金缕衣。", "山浅澹，水茫弥。", "顿无消息许多时。", "杏梁知有新来燕，下却重帘不放归。"]'),
('song-ci-762','踏莎行','卢祖皋','宋','宋词','song-ci','踏莎行','[]','夜雨灯深，春风寒浅。',68,'宋词/ci.song.13000.json','["夜雨灯深，春风寒浅。", "梅姿雪态怜娇软。", "锦笺闲轴旧缄情，酒边一顾清歌遍。", "玉局弹愁，冰弦写怨。", "几时纤手教重见。", "小楼低隔一街尘，为谁长恁巫山远。"]'),
('song-ci-763','相思引','卢祖皋','宋','宋词','song-ci','相思引','[]','陆续鸣鸠呼晓晴。',54,'宋词/ci.song.13000.json','["陆续鸣鸠呼晓晴。", "霏微残雾湿春城。", "未成梅雨，先做麦寒轻。", "长日愔愔花又落，短屏曲曲酒初醒。", "小舟无绪，闲带牡丹行。"]'),
('song-ci-764','相思引','卢祖皋','宋','宋词','song-ci','相思引','[]','夹岸垂杨步障深。',54,'宋词/ci.song.13000.json','["夹岸垂杨步障深。", "露桥横截影沈沈。", "数家篱落，一晌晚凉侵。", "闲倚短篙停夜月，静看双翅落栖禽。", "久无羁思，前事忽惊心。"]'),
('song-ci-765','眼儿媚','卢祖皋','宋','宋词','song-ci','眼儿媚','[]','玉钩清晓上帘衣。',58,'宋词/ci.song.13000.json','["玉钩清晓上帘衣。", "香雾湿春枝。", "馀寒逗雨，罗裙无赖，重暖金猊。", "柳边谁寄东风缆，流水只年时。", "无人为记，天涯归思，梁燕空飞。"]'),
('song-ci-766','更漏子','卢祖皋','宋','宋词','song-ci','更漏子','[]','玉钩裁，罗袜浅。',58,'宋词/ci.song.13000.json','["玉钩裁，罗袜浅。", "心事漫拈针线。", "钗半亸，鬓慵梳。", "新来消瘦无。", "江南路。", "花无数。", "春梦不知何处。", "帘影转，瞑禽西。", "看看眉黛低。"]'),
('song-ci-767','更漏子','卢祖皋','宋','宋词','song-ci','更漏子','[]','蓼花繁，桐叶下。',58,'宋词/ci.song.13000.json','["蓼花繁，桐叶下。", "寂寂梦回凉夜。", "城角断，砌蛩悲。", "月高风起时。", "衣上泪。", "谁堪寄。", "一寸妾心千里。", "人北去，雁南征。", "满庭秋草生。"]'),
('song-ci-768','锦园春三犯・锦园春','卢祖皋','宋','宋词','song-ci','锦园春三犯・锦园春','[]','昼长人倦。',114,'宋词/ci.song.13000.json','["昼长人倦。", "正凋红涨绿，懒莺忙燕。", "丝雨濛晴，放珠帘高卷。", "神仙笑宴。", "半醒醉、彩鸾飞遍。", "碧玉阑干，青油幢幕，沈香庭院。", "洛阳图画旧见。", "向天香深处，犹认娇面。", "雾縠霞绡，闻绮罗裁翦。", "情高意远。", "怕容易、晓风吹散。", "一笑何妨，银台换蜡，铜壶催箭。"]'),
('song-ci-769','锦园春三犯・锦园春','卢祖皋','宋','宋词','song-ci','锦园春三犯・锦园春','[]','醉痕潮玉。',114,'宋词/ci.song.13000.json','["醉痕潮玉。", "爱柔英未吐，露丛如簇。", "绝艳矜春，分流芳金谷。", "风梳雨沐。", "耿空抱、夜阑清淑。", "杜老情疏，黄州赋冷，谁怜幽独。", "玉环睡醒未足。", "记传榆试火，高照宫烛。", "锦幄风翻，渺春容难续。", "迷红怨绿。", "漫惟有、旧愁相触。", "一舸东游，何时更约，西飞鸿鹄。"]'),
('song-ci-770','水龙吟','卢祖皋','宋','宋词','song-ci','水龙吟','[]','杜鹃啼老春红，翠阴满眼愁无奈。',126,'宋词/ci.song.13000.json','["杜鹃啼老春红，翠阴满眼愁无奈。", "飞来何处，凤軿鸾驭，霞裾云佩。", "风槛娇凭，露梢慵亸，酒浓微退。", "念洛阳人去，香魂又返，依然是，风流在。", "银烛光摇彩翠。", "画堂深、莫辞沈醉。", "十年一觉，扬州春梦，离愁似海。", "浩态难留，粉香吹散，几时重会。", "向尊前笑折，一枝红玉，帽檐斜戴。"]'),
('song-ci-771','水龙吟','卢祖皋','宋','宋词','song-ci','水龙吟','[]','荡红流水无声，暮烟细草黏天远。',126,'宋词/ci.song.13000.json','["荡红流水无声，暮烟细草黏天远。", "低回倦蝶，往来忙燕，芳期顿懒。", "绿雾迷墙，翠虬腾架，雪明香暖。", "笑依依欲挽，春风教住，还疑是，相逢晚。", "不似梅妆瘦减。", "占人间、丰神萧散。", "攀条弄蕊，天涯犹记，曲阑小院。", "老去情怀，酒边风味，有时重见。", "对枕帏空想，东床旧梦，带将离恨。"]');
